-- Poems batch 268
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('d3ee599a-d72b-47ee-b7ed-0faebeb00916','贈余月心五首  其五','文天祥','宋','宋诗','song-poetry','','[]','子心月其明，子術星之數。',24,'全唐诗/poet.song.239000.json','["子心月其明，子術星之數。", "爲月詰衆星，不知何以故。"]'),
('7be9d107-2d74-4e4c-97b0-b1c02fde11d4','贈涂內明','文天祥','宋','宋诗','song-poetry','','[]','老云五色令人盲，面壁不視佛慧生。',64,'全唐诗/poet.song.239000.json','["老云五色令人盲，面壁不視佛慧生。", "彼皆去眼絕人僞，孰知涂者出天成。", "有口能談貴人命，有耳能聽貴人聲。", "此中一片光明藏，嗜欲淺處天機深。"]'),
('b476f12c-1978-4fc4-a666-134757818b59','贈一壺天李日者','文天祥','宋','宋诗','song-poetry','','[]','汝南市人眼，壺小天地大。',96,'全唐诗/poet.song.239000.json','["汝南市人眼，壺小天地大。", "誰知賣藥翁，壺寬天地隘。", "李君血肉身，大化中一芥。", "天度三百餘，滿腔粲蓍蔡。", "仙翁以過謫，長房以術敗。", "造化多漏泄，鬼神爭訝怪。", "君歸視斯壺，口匏深覆蓋。", "得錢且沽酒，日晚便罷賣。"]'),
('4c32fcd9-9f59-4a61-a164-6f0b3176588b','贈蕭巽齋','文天祥','宋','宋诗','song-poetry','','[]','未有大撓書，先有伏羲易。',144,'全唐诗/poet.song.239000.json','["未有大撓書，先有伏羲易。", "古人尚卜筮，今人信命術。", "八卦與五行，皆自河圖出。", "易中元有命，道一萬事畢。", "卦義六十四，蕭君得其一。", "江湖旅瑣瑣，談命以巽入。", "人情愛委曲，喉舌嫌棘棘。", "言言依忠孝，君平意未失。", "我生獨骯髒，動取無妄疾。", "是有命流行，誰隕復誰詘。", "安能從兒女，朝夕談昵昵。", "若卦有人買，不妨君賣直。"]'),
('001460a0-4a32-469f-964e-6b8679b2e6ac','贈曾一軒','文天祥','宋','宋诗','song-poetry','','[]','磨蝎之宮星見斗，簸之揚之箕有口。',128,'全唐诗/poet.song.239000.json','["磨蝎之宮星見斗，簸之揚之箕有口。", "昌黎安身坡立命，謗毀平生無不有。", "我有斗度限所經，適然天尾來臨丑。", "雖非終身事干涉，一年貝錦紛雜糅。", "吾家祿書成巨編，往往日者迷幾先。", "惟有一軒曾正德，其說已在前五年。", "陰陽造化蕩晝夜，世間利鈍非偶然。", "未來不必更臆度，我自存我謂之天。"]'),
('187c148b-f233-4e41-9e3f-a5ad6adf7295','贈龔豫軒數術','文天祥','宋','宋诗','song-poetry','','[]','挾策考休微，巫甘邁何追。',48,'全唐诗/poet.song.239000.json','["挾策考休微，巫甘邁何追。", "君亦布靈草，乃復探其微。", "載觀河洛書，今也休明時。", "天高鳳鳥翔，擊拊遨以嬉。"]'),
('1b7874c5-3f2f-451f-88ed-66a6fd6f0138','贈尅擇徐吉甫','文天祥','宋','宋诗','song-poetry','','[]','東望會稽山，穆陵鬰岧嶢。',96,'全唐诗/poet.song.239000.json','["東望會稽山，穆陵鬰岧嶢。", "卜壤藏劍履，伯也昭其勞。", "昔者遊仙人，龍耳致君王。", "君家世其傳，芳踵疇可量。", "青囊落君手，辯語如流河。", "尋雲履高阜，湯湯俯長波。", "朔風渺天垂，萬里草離離。", "安得結方軌，爲君起遐思。"]'),
('3ce736be-db76-4632-9bd9-5cf7490753c2','贈魏山人','文天祥','宋','宋诗','song-poetry','','[]','君不見而家直臣犯天怒，身死未寒碑已仆。',70,'全唐诗/poet.song.239000.json','["君不見而家直臣犯天怒，身死未寒碑已仆。", "又不見而家處士承天渥，閉門水竹以自樂。", "雲仍妙參曾楊訣，謂余地宅誰優劣。", "小煩穩作子午針，靈於己則靈於人。"]'),
('768b48e1-dd1c-419c-ae55-2afc23f5b8ad','贈老庵廖希說','文天祥','宋','宋诗','song-poetry','','[]','短屐平生幾兩穿，錦囊真得當家傳。',64,'全唐诗/poet.song.239000.json','["短屐平生幾兩穿，錦囊真得當家傳。", "山中老去稱庵主，天上將來說地仙。", "面皺不妨筋骨健，舌存何必齒牙全。", "金精深處苓堪飯，更住人間八百年。"]'),
('1f7295bd-540f-4111-a13f-ce23faaee984','彭通伯衛和堂','文天祥','宋','宋诗','song-poetry','','[]','理身如理國，用藥如用兵。',144,'全唐诗/poet.song.239000.json','["理身如理國，用藥如用兵。", "人能保天和，於身爲太平。", "外邪奸其間，甚於寇搶攘。", "守護一不謹，乘間敵益勍。", "古有黄帝書，猶今六韜經。", "悍夫命雄喙，仁將資參苓。", "羽衣爲其徒，識破陰陽爭。", "指授別生死，錚然震能名。", "道家攝鉛汞，膚腠如重扃。", "到頭關鍵密，六氣無敢嬰。", "君方建旗鼓，不敢走且驚。", "他時櫜吾弓，閉門讀黄庭。"]'),
('97c192df-d9cf-4c35-be66-12bebf871f02','贈適庵冊士','文天祥','宋','宋诗','song-poetry','','[]','本是儒家子，學爲方外事。',48,'全唐诗/poet.song.239000.json','["本是儒家子，學爲方外事。", "此身恨鳬短，有意求蟬蛻。", "猶留鼎餘藥，還授人間世。", "從君卧山中，共談弘景祕。"]'),
('ae725739-75a0-4ff9-b181-1c1debdba59b','贈劉可軒寫真','文天祥','宋','宋诗','song-poetry','','[]','燕頷鳶肩都易寫，從前只道點睛難。',32,'全唐诗/poet.song.239000.json','["燕頷鳶肩都易寫，從前只道點睛難。", "近來阿堵君休問，燈下時將頰影看。"]'),
('b336aee2-daa7-44dd-a84f-af65645e166a','慧和尚三絕  其一','文天祥','宋','宋诗','song-poetry','','[]','畫我郎潜先帝時，而今白髮漸參差。',32,'全唐诗/poet.song.239000.json','["畫我郎潜先帝時，而今白髮漸參差。", "若交傳入都人眼，疑汝前身妙善師。"]'),
('262a3e92-32a0-4d75-bb54-07d2ab9a430b','慧和尚三絕  其二','文天祥','宋','宋诗','song-poetry','','["\u8861\u5c71"]','風雪衡山涕滿膺，懶殘不管自家身。',32,'全唐诗/poet.song.239000.json','["風雪衡山涕滿膺，懶殘不管自家身。", "殷勤撥火分煨芋，却有工夫到別人。"]'),
('3cf06ce9-f885-42a2-a956-e3730c705773','慧和尚三絕  其三','文天祥','宋','宋诗','song-poetry','','[]','花光老矣墨婆娑，無頼梅花一白何。',32,'全唐诗/poet.song.239000.json','["花光老矣墨婆娑，無頼梅花一白何。", "爲問西來宗旨道，世間色相是空麽。"]'),
('a8197f28-fdea-472d-b5cf-0ca1aa855412','象弈各有等級四絕品四人高下  其一','文天祥','宋','宋诗','song-poetry','','[]','螳臂初來攫晚蟬，那知黄雀沫饞涎。',32,'全唐诗/poet.song.239000.json','["螳臂初來攫晚蟬，那知黄雀沫饞涎。", "王孫挾彈無人處，一夜琱盤薦玳筵。"]'),
('89c44241-4bcd-4231-8ab2-90970035cc38','象弈各有等級四絕品四人高下  其二','文天祥','宋','宋诗','song-poetry','','[]','射虎將軍髮欲枯，茫茫沙草正迷途。',32,'全唐诗/poet.song.239000.json','["射虎將軍髮欲枯，茫茫沙草正迷途。", "小兒謾取封侯去，還是平陽公主奴。"]'),
('55c621b6-6123-4b4e-a6fa-73fdb6fd69cd','象弈各有等級四絕品四人高下  其三','文天祥','宋','宋诗','song-poetry','','[]','坐踞河南百戰雄，少年飛槊健如龍。',32,'全唐诗/poet.song.239000.json','["坐踞河南百戰雄，少年飛槊健如龍。", "世間只畏兩人在，上有高公下慕容。"]'),
('977de27b-08d5-4c5b-a321-1af77a66033b','象弈各有等級四絕品四人高下  其四','文天祥','宋','宋诗','song-poetry','','[]','擊柱論功不忍看，築壇刑馬誓河山。',32,'全唐诗/poet.song.239000.json','["擊柱論功不忍看，築壇刑馬誓河山。", "當年絳灌知何似，只在春秋魯衛間。"]'),
('16ee0849-eecd-4780-8d8f-9ae0e7d281a3','贈樂軒彭善之','文天祥','宋','宋诗','song-poetry','','[]','吾家小黄溪，其間石甚巨。',48,'全唐诗/poet.song.239000.json','["吾家小黄溪，其間石甚巨。", "可寫歸來辭，可刻盤谷序。", "晉唐文章手，誰敢以自負。", "異時此重來，煩君作玉筯。"]'),
('8da1621c-c4db-4551-a9c8-b0ffa7bb5a87','贈墨林曹大崧','文天祥','宋','宋诗','song-poetry','','[]','巍峨幼婦碑，伶俜七步詩。',28,'全唐诗/poet.song.239000.json','["巍峨幼婦碑，伶俜七步詩。", "又得墨林墨淋漓，湊作曹家三絕奇。"]'),
('4a63017a-b835-4a2f-834f-c877641bf98b','贈刊圖書蕭文彬','文天祥','宋','宋诗','song-poetry','','[]','蒼籀書法祖，斯冰篆家豪。',48,'全唐诗/poet.song.239000.json','["蒼籀書法祖，斯冰篆家豪。", "昔人鋒在筆，今子鋒在刀。", "收功棠谿金，不禮中山毛。", "囊錐脫穎出，鎸崖齊天高。"]'),
('e453e83f-01ee-472c-8ca5-865f93cd5952','題周山甫錦綉段','文天祥','宋','宋诗','song-poetry','','[]','客從西北來，遺我錦綉段。',72,'全唐诗/poet.song.239000.json','["客從西北來，遺我錦綉段。", "上有雙鳳凰，文彩何燦燦。", "置之篋笥中，歲月亦已晏。", "天孫顧七襄，雷電下河漢。", "鳳凰忽飛去，遽然失把玩。", "貧家機杼寒，秋蟲助予嘆。"]'),
('68ba23b9-2ddc-4dbe-b0b2-1bd2fa8a1dce','題梅尉詩軸','文天祥','宋','宋诗','song-poetry','','[]','乃翁聖俞君，瑰辭燦琳琅。',96,'全唐诗/poet.song.239000.json','["乃翁聖俞君，瑰辭燦琳琅。", "吾鄉歐陽子，逸韻諧宮商。", "人物雄中原，園囿盛洛陽。", "醲郁追皇風，詭怪抑晚唐。", "雲仍四方志，生長百戰場。", "憂國杜少陵，感興陳子昂。", "我亦青原人，君遺明月光。", "掩卷不能和，握手談肝腸。"]'),
('8756c160-cc5c-4ecf-bc55-c1d24ad518cd','贈羅雪崖樵青','文天祥','宋','宋诗','song-poetry','','[]','蕭蕭山下人，閉門衣裘單。',24,'全唐诗/poet.song.239000.json','["蕭蕭山下人，閉門衣裘單。", "春心動溪谷，曉起捫松看。"]'),
('6839ceb0-7fe8-40ef-9c60-253921c74a80','題得魚集史評','文天祥','宋','宋诗','song-poetry','','[]','男兒生作事，豪傑死留名。',48,'全唐诗/poet.song.239000.json','["男兒生作事，豪傑死留名。", "天運常相禪，江流自不平。", "百年多險夢，千古有閑評。", "諸父淵源在，吾猶及老成。"]'),
('e4d2553d-ab96-4a02-8801-2c133014db51','題彭小林詩稿','文天祥','宋','宋诗','song-poetry','','[]','晚識宗文憶浣花，刪餘今見雅名家。',32,'全唐诗/poet.song.239000.json','["晚識宗文憶浣花，刪餘今見雅名家。", "牙籤料理西風讀，共笑鍾山說老鴉。"]'),
('a73ce0e2-63ab-42bb-bbcb-ff138f64d1e2','題王聲甫松坡樵苦唱後','文天祥','宋','宋诗','song-poetry','','[]','倚柯睨蒼髯，短簑挾風雨。',60,'全唐诗/poet.song.239000.json','["倚柯睨蒼髯，短簑挾風雨。", "談道誰我知，對弈者其侶。", "狂吟發悲調，谷鳴相律呂。", "扊扅豈不怨，寧售大夫股。", "長鑱斸仙苓，穫薪爲吾煮。"]'),
('ba69181d-31b6-421c-b968-b8cdf2800fc4','題毛霆甫詩集  其一','文天祥','宋','宋诗','song-poetry','','[]','英英白雲，在澗之濆。',20,'全唐诗/poet.song.239000.json','["英英白雲，在澗之濆。", "彼美人兮，其德孔純。"]'),
('44efbbec-7d06-4c9e-a15f-aa791d709bf6','題毛霆甫詩集  其二','文天祥','宋','宋诗','song-poetry','','[]','英英白雲，在澗之阿。',20,'全唐诗/poet.song.239000.json','["英英白雲，在澗之阿。", "彼美人兮，其思孔多。"]'),
('ff8ca4c0-7880-4631-a441-b191bc21509d','題毛霆甫詩集  其三','文天祥','宋','宋诗','song-poetry','','[]','白雲英英，澗水泱泱。',20,'全唐诗/poet.song.239000.json','["白雲英英，澗水泱泱。", "彼美人兮，碩大且昌。"]'),
('f24706e8-d869-4df1-b1ab-99432b281f72','送趙王賓三首  其一','文天祥','宋','宋诗','song-poetry','','[]','風流不比賀家狂，瀟灑黄冠意更長。',32,'全唐诗/poet.song.239000.json','["風流不比賀家狂，瀟灑黄冠意更長。", "自有武夷溪九曲，鑑湖何必問君王。"]'),
('96af97b3-c3c4-4324-938c-47377da7c046','送趙王賓三首  其二','文天祥','宋','宋诗','song-poetry','','[]','蕭然被褐不求知，歸倚溪船理釣絲。',32,'全唐诗/poet.song.239000.json','["蕭然被褐不求知，歸倚溪船理釣絲。", "却笑荆山空自售，未應有智不如葵。"]'),
('fa2e5187-d711-4f58-a460-25ecf95ab6a3','送趙王賓三首  其三','文天祥','宋','宋诗','song-poetry','','[]','懶從原上訪桃花，又不青門去種瓜。',32,'全唐诗/poet.song.239000.json','["懶從原上訪桃花，又不青門去種瓜。", "傳得神仙蟬蛻法，君如覓我問煙霞。"]'),
('79f17edd-6153-4e98-829b-f3b06d0e039c','又送前人琴棋書畫四首  其一','文天祥','宋','宋诗','song-poetry','','[]','不知甲子定何年，題滿柴桑日醉眠。',32,'全唐诗/poet.song.239000.json','["不知甲子定何年，題滿柴桑日醉眠。", "意不在言君解否，壁間琴本是無弦。"]'),
('ee825edd-3485-4280-87e9-817faa72fffa','又送前人琴棋書畫四首  其二','文天祥','宋','宋诗','song-poetry','','[]','我愛商山茹紫芝，逍遥勝似橘中時。',32,'全唐诗/poet.song.239000.json','["我愛商山茹紫芝，逍遥勝似橘中時。", "紛紛玄白方龍戰，世事從他一局棋。"]'),
('eb5760dd-bd89-4883-804b-077f7af8a97e','又送前人琴棋書畫四首  其三','文天祥','宋','宋诗','song-poetry','','[]','蔡邕去後右軍死，誰是風流入品題。',32,'全唐诗/poet.song.239000.json','["蔡邕去後右軍死，誰是風流入品題。", "只少蛟龍大師字，至今風骨在浯溪。"]'),
('4206332c-41be-46c0-8760-68a390b80b49','又送前人琴棋書畫四首  其四','文天祥','宋','宋诗','song-poetry','','[]','欲覓龍眠舊時事，相傳此本世間無。',32,'全唐诗/poet.song.239000.json','["欲覓龍眠舊時事，相傳此本世間無。", "黄金不買昭君本，只買嚴陵歸釣圖。"]'),
('e6bff9c3-6cb5-4ffb-a51a-7fad7b10193c','題延真羅道士玉澗','文天祥','宋','宋诗','song-poetry','','[]','雙巖夾方流，知有至妙藴。',84,'全唐诗/poet.song.239000.json','["雙巖夾方流，知有至妙藴。", "山石發清暉，草木得餘潤。", "泉源皆寶氣，樵牧駭潜蜃。", "仙翁獨危坐，華池養水性。", "神澤溫而栗，骨峭老益勁。", "苔磯枕泓碧，時有魚出聽。", "糜瓊飯潺湲，沖淡意無朕。"]'),
('9661b86b-1c25-437f-b417-4594af4d3215','聽羅道士琴  其一','文天祥','宋','宋诗','song-poetry','','[]','斷崖千仞碧，下有寒泉落。',48,'全唐诗/poet.song.239000.json','["斷崖千仞碧，下有寒泉落。", "道人揮絲桐，清風轉寥廓。", "飄飄襟袂舉，冰紈不禁薄。", "紫煙護丹霞，雙舞天外鶴。"]'),
('d1780d21-4d62-4e7e-9dad-baaac6e77eb3','聽羅道士琴  其二','文天祥','宋','宋诗','song-poetry','','[]','吾聞泗濱磬，暗含角與徵。',48,'全唐诗/poet.song.239000.json','["吾聞泗濱磬，暗含角與徵。", "又聞天樂泉，凈洗箏笛耳。", "如何碧一泓，乃此并二美。", "藍田滄海意，請問玉溪子。"]'),
('f464f4a5-b8af-4ce4-bd2e-ff70be6ba077','閑居和雲屋道士','文天祥','宋','宋诗','song-poetry','','[]','一樽聊共此時心，文字追隨落醉吟。',64,'全唐诗/poet.song.239000.json','["一樽聊共此時心，文字追隨落醉吟。", "仙子樓臺脩竹外，行人冠蓋畫橋陰。", "一年芳草東風老，五月空江夜雨深。", "且作蘭亭歡喜集，更論誰後又誰今。"]'),
('91a0e250-0edf-4711-b05a-e835ddca069c','遊集靈觀','文天祥','宋','宋诗','song-poetry','','[]','小洞煙霞國，重陽風雨秋。',48,'全唐诗/poet.song.239000.json','["小洞煙霞國，重陽風雨秋。", "歐公嵩嶽步，朱子武夷舟。", "香火真吾職，觥籌且此遊。", "龍山馬臺事，糠粃舊王侯。"]'),
('d51e9732-fe8c-42c8-b022-6351744afbef','題凝祥觀','文天祥','宋','宋诗','song-poetry','','[]','前路風塵走且僵，我來一日此徜徉。',64,'全唐诗/poet.song.239000.json','["前路風塵走且僵，我來一日此徜徉。", "歐公自是遊嵩觀，迂叟原非過太行。", "始信神仙還有國，不知蠻觸是何鄉。", "世間如此紛紛者，贏得山林作道場。"]'),
('a919fa62-e354-4f55-9489-ccd3e5c20ad8','遊青源二首  其一','文天祥','宋','宋诗','song-poetry','','[]','鍾魚閒日月，竹樹老風煙。',48,'全唐诗/poet.song.239000.json','["鍾魚閒日月，竹樹老風煙。", "一徑溪聲滿，四山天影圓。", "無言都是趣，有想便成緣。", "夢破啼猿雨，開元六百年。"]'),
('5b187cee-6cf5-457e-8d28-53251897aa37','遊青源二首  其二','文天祥','宋','宋诗','song-poetry','','[]','空庭橫螮蝀，斷碣偃龍蛇。',48,'全唐诗/poet.song.239000.json','["空庭橫螮蝀，斷碣偃龍蛇。", "活火參禪筍，真泉透佛茶。", "晚鍾何處雨，春水滿城花。", "夜影燈前客，江西七祖家。"]'),
('57fe2f27-3d84-414b-a7a6-f4c127132abd','題碧落堂','文天祥','宋','宋诗','song-poetry','','[]','大厦新成燕雀歡，與君聊此共清閑。',64,'全唐诗/poet.song.239000.json','["大厦新成燕雀歡，與君聊此共清閑。", "地居一郡樓臺上，人在半空煙雨間。", "修復盡還今宇宙，感傷猶記舊江山。", "近來又報秋風緊，頗覺憂時鬢欲斑。"]'),
('2326abfe-94db-4db0-bd0e-8d3d64636e1b','和龔使君韻','文天祥','宋','宋诗','song-poetry','','[]','淡和心事葛天民，回首歸來清渭濱。',64,'全唐诗/poet.song.239000.json','["淡和心事葛天民，回首歸來清渭濱。", "長倩君賓孫子行，道原義仲輩流人。", "一生受用忘非是，萬事升沉等故新。", "近日貞元朝士少，蒲輪有命出楓宸。"]'),
('50c18510-2487-4991-a147-f7e37db25399','餞新班弟','文天祥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','送君天上去，當戶理瑶琴。',48,'全唐诗/poet.song.239000.json','["送君天上去，當戶理瑶琴。", "萬里白鷗遠，千山黄葉深。", "江空行路影，日暮倚門心。", "若見西湖雪，霸橋人正吟。"]'),
('c1d41522-56de-4ab3-9483-82d2d42a5eac','別弟赴新昌','文天祥','宋','宋诗','song-poetry','','[]','十載從遊久，諸公講切精。',48,'全唐诗/poet.song.239000.json','["十載從遊久，諸公講切精。", "天淵分理欲，內外一知行。", "立政須規範，修身是法程。", "對床小疏隔，戀戀弟兄情。"]'),
('4e7b0551-7bdc-4a77-9969-abbd244ddd0a','和韻送逸軒劉民章','文天祥','宋','宋诗','song-poetry','','[]','少日屠龍事已勞，送人千里發江濤。',64,'全唐诗/poet.song.239000.json','["少日屠龍事已勞，送人千里發江濤。", "蓬萊地近風方細，閶闔門開日正高。", "春裏看花須款款，雨中剪韭且陶陶。", "金吾已辦長安月，雙鳳扶雲立海鰲。"]'),
('76ed6848-ccf6-4e3f-96c8-251ca5c3a1a9','題宣州疊嶂樓','文天祥','宋','宋诗','song-poetry','','[]','初日照高樓，輕煙在疏樹。',84,'全唐诗/poet.song.239000.json','["初日照高樓，輕煙在疏樹。", "峨峨遠岫出，泯泯清江去。", "簷隙委殘籀，屋隅連宿莽。", "薈蔚互低昂，熹微分散聚。", "城郭諒非昔，山川儼如故。", "童鬒已零落，姝顔慰遲莫。", "沈沈澹忘歸，欲歸重回顧。"]'),
('e2b23b8e-cd26-49c9-8940-8dee216b48d7','題宣州推官廳覽翠堂','文天祥','宋','宋诗','song-poetry','','[]','都官自楚産，文采光陸離。',144,'全唐诗/poet.song.239000.json','["都官自楚産，文采光陸離。", "當年從事君，如與山川期。", "歲月忽巳遒，天球落塵土。", "豈曰無嘉賓，過者不我顧。", "誰令赤城子，發坎出方珉。", "靈物必復見，其見乃以人。", "回視城南端，飛甍俯蒼蒨。", "物理有屈伸，流峙豈云變。", "寥寥南樓月，至今有遐音。", "千年一邂逅，共調風中琴。", "亦欲結方軌，攬茝事幽尋。", "行行且言邁，踟躕思何深。"]'),
('c0227cf9-1f3b-4929-8bc5-aa9c43a44d25','登雙溪閣','文天祥','宋','宋诗','song-poetry','','[]','碧落神仙宅，當年庾謝來。',48,'全唐诗/poet.song.239000.json','["碧落神仙宅，當年庾謝來。", "煙雲連草樹，山水近樓臺。", "萬雉銀缸舉，千鴉鐵騎回。", "梅花衣上月，把玩爲徘徊。"]'),
('a36f0816-8e4c-4f40-a616-24216174680c','題吳城山','文天祥','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','龍行人鬼外，神在地天間。',48,'全唐诗/poet.song.239000.json','["龍行人鬼外，神在地天間。", "彭蠡石砮出，洞庭商舶還。", "秋風黄鵠闊，春雨白鷗閑。", "雲際青如粟，河流接海山。"]'),
('6f423ced-f64e-4105-be4b-ca08306e0e5d','貧女吟四首  其一','文天祥','宋','宋诗','song-poetry','','[]','柴門寒自閉，不識賞花心。',24,'全唐诗/poet.song.239000.json','["柴門寒自閉，不識賞花心。", "春筍翠如玉，爲人拈繡針。"]'),
('a7e9c987-263c-4736-81b2-ebb2d2ad407b','貧女吟四首  其二','文天祥','宋','宋诗','song-poetry','','[]','竹扇掩紅顔，辛苦紉白苧。',24,'全唐诗/poet.song.239000.json','["竹扇掩紅顔，辛苦紉白苧。", "人間羅雪香，白苧汗如雨。"]'),
('07ebf04d-ec88-47e1-a703-55e1be451954','貧女吟四首  其三','文天祥','宋','宋诗','song-poetry','','[]','西風兩鬢鬆，凉意吹伶俜。',24,'全唐诗/poet.song.239000.json','["西風兩鬢鬆，凉意吹伶俜。", "百巧不救貧，誤拜織女星。"]'),
('e757ef24-8774-47a4-931b-860479e650ec','貧女吟四首  其四','文天祥','宋','宋诗','song-poetry','','[]','巧梳手欲冰，小顰爲寒怯。',24,'全唐诗/poet.song.239000.json','["巧梳手欲冰，小顰爲寒怯。", "有時衿肘露，頗與雪爭潔。"]'),
('6d8b4fd2-6d07-43e8-af80-ffdbd3ad6c24','名姝吟','文天祥','宋','宋诗','song-poetry','','[]','丈夫至白首，鍾鼎垂功名。',120,'全唐诗/poet.song.239000.json','["丈夫至白首，鍾鼎垂功名。", "未有朱門中，而無絲竹聲。", "與主共富貴，不見主苦辛。", "名姝從何來，婉孌出神京。", "京人薄生男，生女即不貧。", "東家從王侯，西家事公卿。", "吾行天下多，朱紫稀晨星。", "大都不一一，甚者曠數城。", "如何世上福，冉冉歸娉婷。", "乃知長安市，家家生貴人。"]'),
('a0ba1f02-423e-4bf9-87d0-3b37e5e9c98a','東方有一士','文天祥','宋','宋诗','song-poetry','','[]','萬金結遊俠，千金買歌舞。',96,'全唐诗/poet.song.239000.json','["萬金結遊俠，千金買歌舞。", "丹青映第宅，從者塞衢路。", "身爲他人役，名聲落塵土。", "他人一何傷，富貴還自苦。", "東方有一士，敗垣半風雨。", "不識絲與竹，飛雀滿庭戶。", "一飯或不飽，夜夢無驚寤。", "此事古來多，難與俗人語。"]'),
('c7e02f52-7586-4c71-8b22-4cff64789554','和故人韻  其一','文天祥','宋','宋诗','song-poetry','','[]','去歲湟中穀，醫瘡咸糶新。',48,'全唐诗/poet.song.239000.json','["去歲湟中穀，醫瘡咸糶新。", "一言堪救藥，三秩敢貪嗔。", "自是仁由己，休論哲保身。", "當時若瘖默，何面見鄉人。"]'),
('2b97db96-5070-45bc-9f44-e364f3174670','和故人韻  其二','文天祥','宋','宋诗','song-poetry','','[]','人情嗟愈變，世法合何如。',48,'全唐诗/poet.song.239000.json','["人情嗟愈變，世法合何如。", "氣以心平定，才因意廣疏。", "時行或時止，無咎亦無譽。", "第一嚴交際，琴紳敢不書。"]'),
('0d6e8c9f-eddd-4d1d-87ed-01b5a9659b3c','賦吉州隆慶寺塔火','文天祥','宋','宋诗','song-poetry','','[]','玉塔穿空不可梯，剨然霹靂暗招提。',64,'全唐诗/poet.song.239000.json','["玉塔穿空不可梯，剨然霹靂暗招提。", "四城决破吳胥眼，一炷然成漢卓臍。", "風雨滿山連地捲，鬼神現世覺天低。", "時人子細回頭看，萬事悠悠落日西。"]'),
('fcd81613-4a06-4d3e-b8bf-d5f3aef1e556','寄故人劉方齋','文天祥','宋','宋诗','song-poetry','','[]','溪頭濁潦擁魚蝦，笑殺漁翁下釣差。',32,'全唐诗/poet.song.239000.json','["溪頭濁潦擁魚蝦，笑殺漁翁下釣差。", "棹取扁舟湖海去，悠悠心事寄蘆花。"]'),
('2c7280ed-4bd4-419d-8d2b-c25e4797ceb1','題高君寶紺泉','文天祥','宋','宋诗','song-poetry','','[]','渟渟巖下泓，澄碧落梧影。',72,'全唐诗/poet.song.239000.json','["渟渟巖下泓，澄碧落梧影。", "寒瑶披清飆，殘月照濎濙。", "俯淵測浮雲，流日蕩苕穎。", "向來滄浪歌，孺子不可詗。", "載霑衣上塵，懷古意深永。", "招招素心人，相期發深省。"]'),
('e422c5cc-43c1-482a-8840-9ecef3e5ae1c','題曾氏連理木','文天祥','宋','宋诗','song-poetry','','[]','皇后嘉樹生僪佹，四衢五衢合一軌。',232,'全唐诗/poet.song.239000.json','["皇后嘉樹生僪佹，四衢五衢合一軌。", "德澤純洽八方一，乘木而王固如此。", "大明香琴橘，貞觀玉華李。", "一時圖傳傳奇觀，榮華過眼轉九易。", "惟有武城宅前樹，不知何年已連理。", "從來縣官不以聞，武城子孫世專美。", "人言協氣薰嘉生，此家孝友陶協氣。", "朱門多少鎖喬木，百年瞬息滋一喟。", "焉得鼎鼎爲輪囷，受命不遷相曾氏。", "傳聞此木更八世，方遇麻陽大夫記。", "麻陽又幾年，却入青螺地輿志。", "比來徹當路，表名連瑞里。", "有日捧圖上，嘉禾靈草共青史。", "物生隠顯殆有時，展如之人亦應爾。", "楩楠杞梓離奇生繼此，廬陵城北不止稱三瑞。"]'),
('ecdd7c7d-fc9c-4f05-ae18-5b146835a0d1','題滕王閣','文天祥','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','五雲窗戶瞰滄浪，猶带唐人翰墨香。',64,'全唐诗/poet.song.239000.json','["五雲窗戶瞰滄浪，猶带唐人翰墨香。", "日月四時黄道闊，江山一片畫圖長。", "迴風何處摶雙雁，凍雨誰人駕獨航。", "回首十年此漂泊，閣前新柳已成行。"]'),
('0e9f3366-1ceb-4c2e-a3f5-605f855979cf','題黄岡寺次吳履齋韻','文天祥','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u957f\u6c5f"]','長江幾千里，萬折必歸東。',48,'全唐诗/poet.song.239000.json','["長江幾千里，萬折必歸東。", "南浦驚新雁，廬山隔晚風。", "人行荒樹外，秋在斷蕪中。", "何日洗兵馬，車書四海同。"]'),
('9dea7a7a-da31-4db6-8a06-dc1d84550ceb','龍霧洲覺海寺次李文溪壁間韻','文天祥','宋','宋诗','song-poetry','','[]','闍黎鍾後訪團蒲，江色漫漫晝欲晡。',64,'全唐诗/poet.song.239000.json','["闍黎鍾後訪團蒲，江色漫漫晝欲晡。", "一笛梅邊何滿子，千簑蘆外筆頭奴。", "急風吹雁還家未，新雨生濤到海無。", "本是白鷗隨浩蕩，野田漂泊不爲孤。"]'),
('501bd923-c560-40f0-9b90-e50bcbc3c16f','題鍾聖舉積學齋','文天祥','宋','宋诗','song-poetry','','[]','東家築黄金，西家列珊瑚。',96,'全唐诗/poet.song.239000.json','["東家築黄金，西家列珊瑚。", "嘆此草露晞，良時聊斯須。", "古人重孜孜，殖學乃菑畬。", "彼美不琢琱，櫝中竟何如。", "空同白雲深，君子式其廬。", "棐几照初陽，垂籤動凉噓。", "方寸起岑樓，一勺生龍魚。", "辰乎曷來遲，競諸復競諸。"]'),
('3fe36730-3a4e-4036-b348-063288047b93','題顔景彝八窗玲瓏  其一','文天祥','宋','宋诗','song-poetry','','[]','我闥無纖埃，風日自清好。',24,'全唐诗/poet.song.239000.json','["我闥無纖埃，風日自清好。", "面面有芙蓉，何如交翠草。"]'),
('f9b5f7f1-6823-498f-87a6-902a7dcc0afb','題顔景彝八窗玲瓏  其二','文天祥','宋','宋诗','song-poetry','','[]','吾聞開十牖，不及一戶明。',24,'全唐诗/poet.song.239000.json','["吾聞開十牖，不及一戶明。", "泰宇有天光，八荒盡夷庚。"]'),
('6878b875-20ab-4831-aec7-8e9b1d55abbb','予鄧峒□巽齋歐陽先生爲淦鄧峒賦詩以孝子慈孫望於人先生之盛心也敢不拜手敬贊鄧君勉之','文天祥','宋','宋诗','song-poetry','','[]','乃翁猶旅殯，霜露幾焄蒿。',48,'全唐诗/poet.song.239000.json','["乃翁猶旅殯，霜露幾焄蒿。", "日與清江遊，雲連桂嶺高。", "時無郭元振，夢有令狐綯。", "目斷方田墓，招魂我欲騷。"]'),
('b2b01887-7d7a-4e81-9481-c2fb2b8671b2','題陳正獻公六梅亭','文天祥','宋','宋诗','song-poetry','','[]','相府亭前梅六株，四圍香影護琴書。',64,'全唐诗/poet.song.239000.json','["相府亭前梅六株，四圍香影護琴書。", "月華猶带玉堂色，風味曾分金鼎餘。", "五柳門前空寂寞，三槐堂上竟蕭疏。", "惟渠不變凌霜操，千古風標只自如。"]'),
('e5c2bc5c-e69c-43ad-aa1f-f6e4b79a9aea','文山即事','文天祥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','宇宙風煙闊，山林日月長。',48,'全唐诗/poet.song.239000.json','["宇宙風煙闊，山林日月長。", "開灘通燕尾，伐石割羊腸。", "盤谷堪居李，廬山偶姓康。", "知名總閑事，一醉棹滄浪。"]'),
('d7fa04f1-8156-4694-a71f-56b37e7f2a96','出山','文天祥','宋','宋诗','song-poetry','','[]','日日騎馬來山中，歸時明月長在地。',32,'全唐诗/poet.song.239000.json','["日日騎馬來山中，歸時明月長在地。", "但願山人一百年，一年三百餘番醉。"]'),
('8f752434-0732-4a71-854e-57dfbddf409a','闢山寄朱約山','文天祥','宋','宋诗','song-poetry','','[]','一笠一簑三釣磯，歸來不費買山貲。',64,'全唐诗/poet.song.239000.json','["一笠一簑三釣磯，歸來不費買山貲。", "洞天福地深數里，石壁湍流清四時。", "樵牧舊蹊今可馬，鬼神天巧不容詩。", "先生曾有空同約，那裏江山未是奇。"]'),
('27406e7b-c949-4dc5-a31f-bbbdf62568e9','山中即事','文天祥','宋','宋诗','song-poetry','','[]','携壺藉草醉斜陽，白鶴飛來月下雙。',64,'全唐诗/poet.song.239000.json','["携壺藉草醉斜陽，白鶴飛來月下雙。", "蘆葉西風驚別浦，芭蕉夜雨隔疏窗。", "千年帝子朱簾夢，一曲仙人鐵笛腔。", "若問山翁還瘦否，手持漁竹下寒江。"]'),
('43360ea7-ebd4-4ea3-a461-8d1392ffa75f','宿山中用前韻','文天祥','宋','宋诗','song-poetry','','[]','南山之隩北山陽，羽扇輕風共影雙。',64,'全唐诗/poet.song.239000.json','["南山之隩北山陽，羽扇輕風共影雙。", "畫槳菰蒲明月笛，青燈蟋蟀白雲窗。", "半生遊子成行債，一夜佳人作別腔。", "倚釣重來此簑笠，梅花十里雪空江。"]'),
('a1fe9575-cff6-4f9a-9c8e-9da0615054d3','山中','文天祥','宋','宋诗','song-poetry','','[]','滄洲棹影荻花凉，欵乃一聲江水長。',64,'全唐诗/poet.song.239000.json','["滄洲棹影荻花凉，欵乃一聲江水長。", "頼有蓴風堪斫膾，便無花月亦飛觴。", "山中世已驚東晉，席上人多賦晚唐。", "何處魚羹不可飯，蚤拚泉石入膏肓。"]'),
('6d2d7e97-0e74-4e4c-b61d-787b4025e8bf','山中謾成柬劉方齋','文天祥','宋','宋诗','song-poetry','','[]','東風解凍出行嬉，一鬨煙塵隔翠微。',64,'全唐诗/poet.song.239000.json','["東風解凍出行嬉，一鬨煙塵隔翠微。", "自有溪山真樂地，從來富貴是危機。", "二三輩行惟須醉，多少公卿未得歸。", "明日主人酬一座，小船旋網鱖魚肥。"]'),
('a4396177-b820-40b7-8e43-6a756512dd51','山中載酒用蕭敬夫韻賦江漲','文天祥','宋','宋诗','song-poetry','','[]','拍拍春風滿面浮，出門一笑大江流。',64,'全唐诗/poet.song.239000.json','["拍拍春風滿面浮，出門一笑大江流。", "坐中狂客有醉白，物外閑人惟弈秋。", "晴抹雨粧總西子，日開雲暝一滁州。", "忽傳十萬軍聲至，如在浙江亭上遊。"]'),
('a0235874-0499-4773-bc45-90d72f1bf355','山中立夏用坐客韻','文天祥','宋','宋诗','song-poetry','','[]','歸來泉石國，日月共溪翁。',48,'全唐诗/poet.song.239000.json','["歸來泉石國，日月共溪翁。", "夏氣重淵底，春光萬象中。", "窮吟到雲黑，淡飲勝裙紅。", "一陣弦聲好，人間解慍風。"]'),
('337acff8-5c1c-43ec-b018-1884ff11a6cb','山中和韻','文天祥','宋','宋诗','song-poetry','','[]','白扇揮殘暑，青鞋踏嫩晴。',48,'全唐诗/poet.song.239000.json','["白扇揮殘暑，青鞋踏嫩晴。", "花床尋小隠，石鼎引長鳴。", "紗帽有時去，酒壺惟意傾。", "山僧癡與坐，閑却瘦彌明。"]'),
('da3384a1-877e-4b21-a9b6-32500a7668eb','山中自賦','文天祥','宋','宋诗','song-poetry','','[]','□□□□□□□，門外蒼松一水修。',64,'全唐诗/poet.song.239000.json','["□□□□□□□，門外蒼松一水修。", "不必清高逼巢許，祇教瀟灑勝由求。", "空花自滿三千界，老樹相看五百秋。", "坐有鷹揚人物在，怕牽昨夢上漁舟。"]'),
('8c7d7fd6-8803-42f5-b353-de7f94859c7e','入山即事','文天祥','宋','宋诗','song-poetry','','[]','江流風㶁㶁，雲薄雨絲絲。',48,'全唐诗/poet.song.239000.json','["江流風㶁㶁，雲薄雨絲絲。", "上馬忙呼繖，巡簷靜看棋。", "露天厨作濘，沙地水生池。", "秉燭留前夕，茲遊更絕奇。"]'),
('c9041611-d609-4bb3-bed7-3376fbf9921d','山中感興三首  其一','文天祥','宋','宋诗','song-poetry','','[]','載酒之東郊，東郊草新綠。',72,'全唐诗/poet.song.239000.json','["載酒之東郊，東郊草新綠。", "一雨生江波，洲渚失其足。", "青春豈不惜，行樂非所欲。", "采芝復采芝，終朝不盈掬。", "大風從何來，奇響振空谷。", "我馬何玄黄，息我西山麓。"]'),
('cc4bda6b-45df-4d9b-83ed-34f4bf8cdcfe','山中感興三首  其二','文天祥','宋','宋诗','song-poetry','','[]','山中有流水，霜降石自出。',72,'全唐诗/poet.song.239000.json','["山中有流水，霜降石自出。", "驟雨東南來，消長不終日。", "故人書問至，爲言北風急。", "山深人不知，塞馬誰得失。", "挑燈看古史，感淚縱橫發。", "幸生聖明時，漁樵以自適。"]'),
('9f08ff82-9afd-4e19-ba92-7d8418b27453','山中感興三首  其三','文天祥','宋','宋诗','song-poetry','','[]','桃花何夭夭，楊柳何依依。',72,'全唐诗/poet.song.239000.json','["桃花何夭夭，楊柳何依依。", "去年白鳥集，今年黄鵠飛。", "昔爲江上潮，今爲山中雲。", "江上潮有聲，山中雲無情。", "一年足自念，况復百年長。", "但存松柏心，天地真茫茫。"]'),
('0f68a284-2978-43cf-8e9d-f4d1b09a5fbb','山中呈聶心遠諸客  其一','文天祥','宋','宋诗','song-poetry','','[]','誰入山來問野舟，一篙花外渡深流。',64,'全唐诗/poet.song.239000.json','["誰入山來問野舟，一篙花外渡深流。", "小顰風樹蹁躚鶴，淺約湍沙浩蕩鷗。", "湖上有時思洛社，人間何處不滁州。", "徘徊才是黄昏候，短笛先催月上樓。"]'),
('dccd3799-4e7c-419f-ac61-7395573733b7','山中呈聶心遠諸客  其二','文天祥','宋','宋诗','song-poetry','','[]','黄葉婆娑上釣舟，喚回舊夢到江流。',64,'全唐诗/poet.song.239000.json','["黄葉婆娑上釣舟，喚回舊夢到江流。", "多情政自憐檣燕，兩鬢終當付野鷗。", "未說離懷向南浦，須知詩意在夔州。", "朔風昨夜吹沙急，早覺寒聲戰玉樓。"]'),
('fd5ef1ef-1b74-4c24-822f-96edd34d7047','山中六言三首  其一','文天祥','宋','宋诗','song-poetry','','[]','兩兩漁舟摇下，雙雙紫燕飛回。',28,'全唐诗/poet.song.239000.json','["兩兩漁舟摇下，雙雙紫燕飛回。", "流水白雲芳草，清風明月蒼苔。"]'),
('b545ce99-13e3-4e17-a35a-fc44646b84ae','山中六言三首  其二','文天祥','宋','宋诗','song-poetry','','[]','鶴外竹聲簌簌，座邊松影疏疏。',28,'全唐诗/poet.song.239000.json','["鶴外竹聲簌簌，座邊松影疏疏。", "夜靜不收棋局，日高猶卧紗厨。"]'),
('c06df24d-3976-425c-aba3-0dafd71f81bf','山中六言三首  其三','文天祥','宋','宋诗','song-poetry','','[]','風煖江鴻海燕，雨晴簷鵲林鳩。',28,'全唐诗/poet.song.239000.json','["風煖江鴻海燕，雨晴簷鵲林鳩。", "一段青山顔色，不隨江水俱流。"]'),
('889741c4-fce9-43d2-9eb8-70321228d968','用蕭敬夫韻','文天祥','宋','宋诗','song-poetry','','[]','庭院芭蕉碎綠陰，高山一曲寄瑶琴。',64,'全唐诗/poet.song.239000.json','["庭院芭蕉碎綠陰，高山一曲寄瑶琴。", "西風遊子萬山影，明月故鄉千里心。", "江上斷鴻隨我老，天涯芳草爲誰深。", "雪中若作梅花夢，約莫孤山人姓林。"]'),
('eaf21f59-5790-4cba-8232-401de72bbe67','山中  其一','文天祥','宋','宋诗','song-poetry','','[]','煙雲開窈緲，荆棘剪離披。',48,'全唐诗/poet.song.239000.json','["煙雲開窈緲，荆棘剪離披。", "蠟屐上下齒，竹枝長短詞。", "半山江色透，獨樹午陰遲。", "世上兒孫老，有人猶看棋。"]'),
('48c78f8f-8db9-49ce-9877-d39ac8edb6b4','山中  其二','文天祥','宋','宋诗','song-poetry','','[]','倏忽當年遇，蒙茸幾度披。',48,'全唐诗/poet.song.239000.json','["倏忽當年遇，蒙茸幾度披。", "水霞明畫卷，草樹幻騷詞。", "鳥過目不瞬，江流意自遲。", "世人空黑白，一色看坡棋。"]'),
('02a6308f-6297-4304-b517-e7afe6777608','竹花','文天祥','宋','宋诗','song-poetry','','[]','黄家紫家鬭魏姚，夷齊玉立青蕭蕭。',32,'全唐诗/poet.song.239000.json','["黄家紫家鬭魏姚，夷齊玉立青蕭蕭。", "便是人間小天地，不特水上作萍漂。"]'),
('c17252c4-7a9c-46d8-9d60-62cc22851faf','夜歸','文天祥','宋','宋诗','song-poetry','','[]','市橋燈火未闌珊，一簇人家樹影間。',32,'全唐诗/poet.song.239000.json','["市橋燈火未闌珊，一簇人家樹影間。", "想把神仙爭羨我，不知我正羨渠閒。"]'),
('2169bc4f-62db-4ff4-b492-d2ee610185f5','八月十六日見梅','文天祥','宋','宋诗','song-poetry','','[]','廣寒殿裏玉樓開，那得孤山處士來。',32,'全唐诗/poet.song.239000.json','["廣寒殿裏玉樓開，那得孤山處士來。", "半夜西風半身影，夢中騎得雪馿回。"]'),
('e204ce4b-f3de-420e-92c6-56194d2cef22','和蕭秋屋韻','文天祥','宋','宋诗','song-poetry','','[]','蘆花作雪照波流，黄葉聲中一半秋。',64,'全唐诗/poet.song.239000.json','["蘆花作雪照波流，黄葉聲中一半秋。", "明月嬋娟千里夢，扁舟汗漫五湖游。", "星辰活動驚歌笑，風露輕寒敵拍浮。", "贏得年年清賞處，山河全影入金甌。"]'),
('b722a1fc-75a7-49c3-9b6e-0391d6b5fa14','月夜','文天祥','宋','宋诗','song-poetry','','[]','月到中天雲劃開，斷橋幻出玉樓臺。',32,'全唐诗/poet.song.239000.json','["月到中天雲劃開，斷橋幻出玉樓臺。", "夜深一鶴掠舟過，疑是坡仙赤壁來。"]'),
('be7c73a6-eb63-4a01-9bbf-a6bbca66b3b4','江行','文天祥','宋','宋诗','song-poetry','','[]','日日看山好，山山山色蒼。',48,'全唐诗/poet.song.239000.json','["日日看山好，山山山色蒼。", "忘機鷗下早，戀廄馬行忙。", "松曉清風濕，荷秋流水香。", "短簑吹鐵笛，年歲大江長。"]'),
('2d3c3e23-9c83-4bc3-bf0c-bef4a117613e','紙帳','文天祥','宋','宋诗','song-poetry','','[]','紙帳白如雪，上有坐客影。',48,'全唐诗/poet.song.239000.json','["紙帳白如雪，上有坐客影。", "一白不自由，黑光蕩無定。", "人倦影已散，依然雪花瑩。", "須臾秉燭眠，相忘心目靜。"]'),
('0305f0b8-ec63-4d81-97d2-28dbc692df24','爲劉定伯索油蕨','文天祥','宋','宋诗','song-poetry','','[]','我欲登山去采薇，江南秋雨正霏霏。',32,'全唐诗/poet.song.239000.json','["我欲登山去采薇，江南秋雨正霏霏。", "仙家解有逡巡手，一筯西風落翠微。"]'),
('cd940aae-2b2d-4812-8ac7-44ad597a85e4','山中小集','文天祥','宋','宋诗','song-poetry','','[]','江山閑勝賞，萬戶不須留。',48,'全唐诗/poet.song.239000.json','["江山閑勝賞，萬戶不須留。", "客醉客多事，吾詩吾自酬。", "夕風吹絳蠟，春色漾黄流。", "賓從歸來夜，滁翁無此遊。"]'),
('78605ae3-e9af-4159-b414-976297691675','新年','文天祥','宋','宋诗','song-poetry','','[]','梅花枕上聽司晨，起綰金章候拜親。',32,'全唐诗/poet.song.239000.json','["梅花枕上聽司晨，起綰金章候拜親。", "喜對慈顔看鋪鬢，髮雖疏脫未如銀。"]'),
('f6e98a2c-93dc-4434-9e6f-50f1ced657ef','生日和聶吉甫','文天祥','宋','宋诗','song-poetry','','[]','青蒲花未老，黄竹筍初生。',48,'全唐诗/poet.song.239000.json','["青蒲花未老，黄竹筍初生。", "細味詩工部，閑評字率更。", "大江流日影，時鳥說春榮。", "共作千年計，身謀政自輕。"]'),
('81003dc5-8e58-4faf-9914-59c4d62f8011','生日和謝愛山長句','文天祥','宋','宋诗','song-poetry','','[]','寓形落落大塊間，噓吸一氣自往還。',128,'全唐诗/poet.song.239000.json','["寓形落落大塊間，噓吸一氣自往還。", "桑弧未了男子事，何能局促甘囚山。", "昔年此日作初度，賓客如雲劇歡舞。", "今年避影却閉門，捧觴自壽白頭母。", "故人憶我能遠來，虹光滿袖生瓊瑰。", "一杯相屬慰岑寂，使我發笑愁顔開。", "簸揚且聽箕張口，丈夫壯氣須衝斗。", "夜闌拂劍碧光寒，握手相期出雲表。"]'),
('527b2fb4-ddb7-4f15-aae3-b6e31af2d797','生日謝朱約山和來韻','文天祥','宋','宋诗','song-poetry','','[]','元豐五年正月日，洛中耆英佳話出。',240,'全唐诗/poet.song.239000.json','["元豐五年正月日，洛中耆英佳話出。", "當時韓公七十九，歡噱賡酬老吟筆。", "偉然冠劍照孔鸞，鮐背鳩杖蒲輪安。", "韓公而下文寬夫，相高以壽不以官。", "洛塵已隨流水急，雲仍相逢松下石。", "顧我行輩真我來，兼謩故事强安排。", "約對青山共長久，醉歌要賽滁州守。", "願隨後社著深衣，闌風伏雨從是非。", "便令携樽西墅去，山花山鳥爲歌舞。", "招招瑶母來庭闈，拍手共笑偷桃兒。", "吾山陂陀白雲滿，猿鶴司我北門管。", "紫霞隔斷雞犬聲，下有琥珀滋長齡。", "向來福地七十二，此亦清高仙地位。", "朝遊崑崙暮崆峒，駕風鞭霆迎我公。", "丹崖翠壁千萬丈，與公上上上上上。"]'),
('64ca5596-5bcd-48bc-b740-e6d106ba9e72','生日山中和蕭敬夫韻','文天祥','宋','宋诗','song-poetry','','[]','山深不用結凉棚，風起江蘋暑氣輕。',64,'全唐诗/poet.song.239000.json','["山深不用結凉棚，風起江蘋暑氣輕。", "處士林泉自今古，男兒弧矢付豪英。", "客來不必籠中羽，我愛無如橘裏枰。", "一任蒼松栽十里，他年猶見茯苓生。"]'),
('a9243947-db44-4999-a498-7ad8c9ba5179','與朱古平飲山中和蕭敬夫韻','文天祥','宋','宋诗','song-poetry','','[]','江山自足引千杯，况有如今此客哉。',64,'全唐诗/poet.song.239000.json','["江山自足引千杯，况有如今此客哉。", "石室只還湖守住，蘆峰曾屈晦翁來。", "酒酣剩有詩酬唱，步倦何妨車馬回。", "遊徧此山方可別，北崖莫遣曉雲開。"]'),
('b66e9524-4b8b-470e-bdf2-c321c9e4255a','所懷','文天祥','宋','宋诗','song-poetry','','[]','英英香蕙瑩朝華，收拾東風作一家。',32,'全唐诗/poet.song.239000.json','["英英香蕙瑩朝華，收拾東風作一家。", "燕語鶑啼春又夏，燈花剔盡暗窗斜。"]'),
('6d6f96f6-fdc7-48aa-86be-862f5ca251c1','山中偶成','文天祥','宋','宋诗','song-poetry','','[]','白鶴飛來牽我衣，東風吹我下漁磯。',32,'全唐诗/poet.song.239000.json','["白鶴飛來牽我衣，東風吹我下漁磯。", "當年祇爲青山誤，直草君王一詔歸。"]'),
('324733da-aabd-4d94-a344-b21bc7e05f08','次約山賦杏花韻','文天祥','宋','宋诗','song-poetry','','[]','名花韻在午晴初，雨沁臙脂臉更敷。',64,'全唐诗/poet.song.239000.json','["名花韻在午晴初，雨沁臙脂臉更敷。", "蒲驛莫妨娛刺史，錦坊豈不勝中書。", "時無艷曲臨軒縱，公莫巍壇韞匱沽。", "春老綠陰青子近，東風來往一吹噓。"]'),
('659405aa-b0ee-49c2-9049-8228da5eddf9','贈南安黄梅峰','文天祥','宋','宋诗','song-poetry','','[]','清淺風流聖得知，黄昏歸鶴月來時。',32,'全唐诗/poet.song.239000.json','["清淺風流聖得知，黄昏歸鶴月來時。", "嶺頭更有高寒處，却是江南第一枝。"]'),
('4efdbb70-ed83-4c56-8836-51da66f6675a','送人往湖南','文天祥','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','雁拖秋月洞庭邊，客路凄凉野菊天。',64,'全唐诗/poet.song.239000.json','["雁拖秋月洞庭邊，客路凄凉野菊天。", "雲隔酒尊橫北海，風吹詩史落西川。", "夜深鬼火千山雪，春後鵑花一樹煙。", "爲我祝融峰上看，朝暾白處禮蓬仙。"]'),
('1720404a-98a2-47fa-a55a-4ba2739e0b5d','題張景召簿尉梅墅并餞入南','文天祥','宋','宋诗','song-poetry','','[]','喚醒三影燕支魂，一枝半樹專黄昏。',64,'全唐诗/poet.song.239000.json','["喚醒三影燕支魂，一枝半樹專黄昏。", "江南暗香鬰不住，霜風吹入羅浮村。", "疏枝不入輞川畫，暗香不到東山棋。", "雲階一枕梨花夢，參橫月落無人知。"]'),
('34732ccc-d708-4e0d-b5a8-7330acff5a8a','和謝愛山晚吟韻日晚與客散步因誦夕陽雖好不多時之句謝愛山欣然賦之余亦率然口占以和亦一時之樂也','文天祥','宋','宋诗','song-poetry','','[]','日落未落天滄凉，懸崖掛壁留餘光。',80,'全唐诗/poet.song.239000.json','["日落未落天滄凉，懸崖掛壁留餘光。", "紫煙翠霧空迷茫，颼颼度壑松風長。", "牛背短笛催歸忙，飄飄逸興空悠揚。", "襟懷灑落萬慮亡，須臾薄暝山色藏。", "長歌浩浩相激昂，淡雲弄月微昏黄。"]'),
('888b466a-5542-4bcd-85e6-d87b8fdec959','別謝愛山  其一','文天祥','宋','宋诗','song-poetry','','[]','綠綺知音早，青燈對語遲。',48,'全唐诗/poet.song.239000.json','["綠綺知音早，青燈對語遲。", "那知今雨別，又重故人思。", "山隔詩情遠，雲含客思悲。", "小樓今夜笛，莫向月中吹。"]'),
('f951f561-9e23-41b9-b557-9e4c294dc2ad','別謝愛山  其二','文天祥','宋','宋诗','song-poetry','','[]','君今拂衣去，我獨枕書眠。',48,'全唐诗/poet.song.239000.json','["君今拂衣去，我獨枕書眠。", "一片過林雨，數聲當戶蟬。", "情長空有恨，吟苦不成篇。", "後會知何日，西風老雁天。"]'),
('68a284b4-b6c7-4642-b665-d327780fce4d','和胡琴窗','文天祥','宋','宋诗','song-poetry','','[]','買得青山貴似金，瘦筇上下費沉吟。',64,'全唐诗/poet.song.239000.json','["買得青山貴似金，瘦筇上下費沉吟。", "花開花落相關意，雲去雲來自在心。", "夜雨一江漁唱小，秋風兩袖客愁深。", "夾堤密與栽楊柳，剩有行人待綠陰。"]'),
('44a59761-abb9-4348-a6c5-57e5cbd5de5a','七月十三夜用燈牌字韻湊成一詩與諸賓一笑','文天祥','宋','宋诗','song-poetry','','[]','赤壁當年賦子虛，西風忽復到菰蒲。',64,'全唐诗/poet.song.239000.json','["赤壁當年賦子虛，西風忽復到菰蒲。", "蟾蜍影裏千秋鑒，蟋蟀聲中七月圖。", "詩思飄飄入雲漢，歌聲隠隠動江湖。", "萬家簫鼓連燈火，見說來年此事無。"]'),
('b8bf36e7-8544-479f-b428-7a5539c54b08','病中作','文天祥','宋','宋诗','song-poetry','','[]','歲月侵尋見二毛，劍花冷落鸊鵜膏。',64,'全唐诗/poet.song.239000.json','["歲月侵尋見二毛，劍花冷落鸊鵜膏。", "睡餘吸海龍身瘦，渴裏奔雲馬骨高。", "百忌不容親酒具，千愁那解減詩豪。", "起來大作屠門嚼，自笑我非兒女曹。"]'),
('c58db1e8-dba5-4d4e-97cc-74b3b7378954','又二絕  其一','文天祥','宋','宋诗','song-poetry','','[]','瞿塘隘處真重險，勾漏坡前又一灘。',32,'全唐诗/poet.song.239000.json','["瞿塘隘處真重險，勾漏坡前又一灘。", "世事不容輕易看，翻雲覆雨等閑間。"]'),
('f6c2b6d6-b0fc-41a2-8d66-235d36d7ee5e','又二絕  其二','文天祥','宋','宋诗','song-poetry','','[]','病中忽悞通真理，靜處專尋入定工。',32,'全唐诗/poet.song.239000.json','["病中忽悞通真理，靜處專尋入定工。", "雨汗淋頭都不管，須臾和氣自沖融。"]'),
('03e641e4-aaea-44c5-80db-2254bd30b956','又賦  其一','文天祥','宋','宋诗','song-poetry','','[]','一病忽兩月，蓬頭夏涉秋。',48,'全唐诗/poet.song.239000.json','["一病忽兩月，蓬頭夏涉秋。", "形羸心自壯，手弱筆仍遒。", "昨夜燈如喜，今宵蝶莫愁。", "問誰驅五瘧，正與五窮謀。"]'),
('608c80b5-0566-40f6-a2d1-9c45c9087453','又賦  其二','文天祥','宋','宋诗','song-poetry','','[]','一病四十日，西風草木凉。',48,'全唐诗/poet.song.239000.json','["一病四十日，西風草木凉。", "倚床腰見骨，覽鏡眼留眶。", "倦策吟詩杖，頻燒讀易香。", "夜深排果餌，乞巧大醫王。"]'),
('40076891-9cfa-4ba0-8ca2-e17f3c1234e8','又賦  其三','文天祥','宋','宋诗','song-poetry','','[]','病裏心如故，閑中事更生。',48,'全唐诗/poet.song.239000.json','["病裏心如故，閑中事更生。", "睡貓隨我懶，黠鼠向人鳴。", "羽扇看棋坐，黄冠扶杖行。", "燈前翻自喜，瘦得此詩清。"]'),
('a65117d0-d52b-4f98-8917-d2e4efe00c32','又賦  其四','文天祥','宋','宋诗','song-poetry','','[]','驟雨知何處，一溪秋水生。',48,'全唐诗/poet.song.239000.json','["驟雨知何處，一溪秋水生。", "苦吟肩鶴瘦，多病耳蟬鳴。", "隠几惟便睡，挑包正倦行。", "山深明月夜，乞我半窗清。"]'),
('7c2cbeb2-bcd9-4ae2-a174-c9bdc2168cff','又賦  其五','文天祥','宋','宋诗','song-poetry','','[]','寄興逃吾病，吟詩老此生。',48,'全唐诗/poet.song.239000.json','["寄興逃吾病，吟詩老此生。", "風高鴻雁起，晴久鵓鳩鳴。", "野樹辭秋落，溪雲带雨行。", "晚凉便懶坐，移傍竹陰清。"]'),
('303aab39-1c82-414e-a6ba-3d288cc32ed6','借道冠有賦','文天祥','宋','宋诗','song-poetry','','[]','病中蕭散服黄冠，笑倒群兒指爲彈。',64,'全唐诗/poet.song.239000.json','["病中蕭散服黄冠，笑倒群兒指爲彈。", "祕監賀君曾道士，翰林蘇子亦祠官。", "酒壺釣具有時樂，茶竈筆床隨處安。", "幸有山陰深密處，他年煉就九還丹。"]'),
('35247c41-ad68-4e23-ac93-31cc84eb976a','又賦','文天祥','宋','宋诗','song-poetry','','[]','一番潮信過，時暫脫熬煎。',48,'全唐诗/poet.song.239000.json','["一番潮信過，時暫脫熬煎。", "心似轆轤轉，身如徽纆纏。", "夜聽饑鼠嘯，晝看伏雌眠。", "急雨千山動，應知爲解弦。"]'),
('1fbf24f6-cb2a-4a07-ba3a-61e1daa18a04','病甚夢召至帝所獲宥覺而頓愈遂賦','文天祥','宋','宋诗','song-poetry','','[]','卧聽風雷叱，天官赦小臣。',48,'全唐诗/poet.song.239000.json','["卧聽風雷叱，天官赦小臣。", "平生無害物，不死復爲人。", "道德門庭遠，君親念慮新。", "自憐螻蟻輩，豈意動蒼旻。"]'),
('9666a996-940a-4318-8831-8d86ba49f831','病愈簡劉小村  其一','文天祥','宋','宋诗','song-poetry','','[]','秋光沁人骨，意氣曉來新。',48,'全唐诗/poet.song.239000.json','["秋光沁人骨，意氣曉來新。", "古鼎龍團雪，虛簷麈尾春。", "商山弈棋老，赤壁洞簫賓。", "風月真倉扁，招呼入屋頻。"]'),
('069e4079-fe4c-4165-8510-33bbb3484aa2','病愈簡劉小村  其二','文天祥','宋','宋诗','song-poetry','','[]','倦餘心似醉，病起首如蓬。',48,'全唐诗/poet.song.239000.json','["倦餘心似醉，病起首如蓬。", "黄竹斷橋雨，白蘋長笛風。", "仙仙鷗屢舞，咄咄雁書空。", "孤負秋來眼，閑挑爨下桐。"]'),
('9dc0b4ef-036a-48ae-8c18-e8b0ebde7993','夜坐偶成','文天祥','宋','宋诗','song-poetry','','[]','蕭蕭秋夜凉，明月入我戶。',48,'全唐诗/poet.song.239000.json','["蕭蕭秋夜凉，明月入我戶。", "攬衣起中庭，仰見牛與女。", "坐久寒露下，悲風動紈素。", "不遇王子喬，此意誰與語。"]'),
('b1656039-9449-456f-842a-77529ec4050b','簡琴窗雲屋竹軒諸友','文天祥','宋','宋诗','song-poetry','','[]','世情千萬變，險甚劍頭炊。',48,'全唐诗/poet.song.239000.json','["世情千萬變，險甚劍頭炊。", "嗜傳姑成癖，登山且作癡。", "煙霞非疾痼，泉石自心馳。", "獨喜精神健，山中剩有詩。"]'),
('9032ccda-3389-4a29-a5ae-ad4a5a240dcf','用前韻留琴窗','文天祥','宋','宋诗','song-poetry','','[]','百年矛上淅，萬事枕中炊。',48,'全唐诗/poet.song.239000.json','["百年矛上淅，萬事枕中炊。", "病苦還思老，貪嗔未若癡。", "雲低天欲動，江長岸如馳。", "明月西風健，山頭賦別詩。"]'),
('7f2735d4-e76a-4543-ac76-25305ccf768f','又用韻簡李深之','文天祥','宋','宋诗','song-poetry','','[]','晚尊和月吸，早飯带星炊。',48,'全唐诗/poet.song.239000.json','["晚尊和月吸，早飯带星炊。", "鵬鷃從高下，螳蟬任黠癡。", "水澄神自止，雲遠意俱馳。", "門外誰車馬，故人來課詩。"]'),
('ee73c544-7cfb-4f9d-94c5-123dde47fe58','早起偶成  其一','文天祥','宋','宋诗','song-poetry','','[]','澹澹池光曙，沉沉野色秋。',48,'全唐诗/poet.song.239000.json','["澹澹池光曙，沉沉野色秋。", "片雲生北舍，隻雁過南樓。", "有見皆成趣，無言總是愁。", "芭蕉夜來水，嚥罷自搔頭。"]'),
('95f4600a-92c7-4653-9f5c-51308b65ce87','早起偶成  其二','文天祥','宋','宋诗','song-poetry','','[]','江山如有意，天地可無秋。',48,'全唐诗/poet.song.239000.json','["江山如有意，天地可無秋。", "夜月馮驩鋏，西風王粲樓。", "露蛩令我喜，煙草爲誰愁。", "且醉杯中物，相看尚黑頭。"]'),
('6f4eff19-059e-4b79-80c2-26c51aed8d00','曉起  其一','文天祥','宋','宋诗','song-poetry','','[]','夢破風煙逈，衾寒不自由。',48,'全唐诗/poet.song.239000.json','["夢破風煙逈，衾寒不自由。", "鍾聲到枕曙，月影入簾秋。", "雁過江山老，蛩吟草樹愁。", "整冠人共笑，兩月不梳頭。"]'),
('0168e1d3-0f62-4a96-9b43-dc7139475541','曉起  其二','文天祥','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u5199\u666f"]','遠寺鳴金鐸，疏窗試寶熏。',48,'全唐诗/poet.song.239000.json','["遠寺鳴金鐸，疏窗試寶熏。", "秋聲江一片，曙影月三分。", "倦鶴行黄葉，癡猿坐白雲。", "道人無一事，抱膝看回文。"]'),
('942e1998-3d97-4edc-93fc-589df2f38703','夜坐','文天祥','宋','宋诗','song-poetry','','[]','淡煙楓葉路，細雨蓼花時。',48,'全唐诗/poet.song.239000.json','["淡煙楓葉路，細雨蓼花時。", "宿雁半江畫，寒蛩四壁詩。", "少年成老大，吾道付逶遲。", "終有劍心在，聞雞坐欲馳。"]'),
('1611cf24-9511-47bb-a40f-63fb82f9ea80','和朱松坡','文天祥','宋','宋诗','song-poetry','','[]','學醫未至大醫王，笑殺年年折臂傷。',64,'全唐诗/poet.song.239000.json','["學醫未至大醫王，笑殺年年折臂傷。", "屏裏江山如出色，亭皋松菊已成行。", "細參不語禪三昧，靜對無弦琴一張。", "多謝嶺頭詩寄我，滿園梅意弄春光。"]'),
('a47842af-2185-4260-8460-bcdc2fbd4a8c','陳貫道摘坡詩如寄以自號達者之流也爲賦浩浩歌一首','文天祥','宋','宋诗','song-poetry','','[]','浩浩歌，人生如寄可奈何。',222,'全唐诗/poet.song.239000.json','["浩浩歌，人生如寄可奈何。", "春秋去來傳鴻燕，朝暮出沒奔羲娥。", "青絲冉冉上霜雪，百年欻若彈指過。", "封侯未必勝瓜圃，青門老子聊婆娑。", "江湖流浪何不可，亦曾力士爲脫靴。", "清風明月不用買，何處不是安樂窩。", "鶴脛豈長鳬豈短，夔足非少蚿非多。", "浩浩歌，人生如寄可奈何。", "不能高飛與遠舉，天荒地老懸網羅。", "到頭北邙一抔土，萬事碌碌空奔波。", "金張許史久寂寞，古來賢聖聞丘軻。", "乃知世間爲長物，惟有真我難滅磨。", "浩浩歌，人生如寄可奈何。", "春夢婆，春夢婆，拍手笑呵呵。", "是亦一東坡，非亦一東坡。"]'),
('ed610b44-fdcc-4b3f-90ff-d4ba720cce41','借朱約山韻就賀挂冠','文天祥','宋','宋诗','song-poetry','','[]','身健尚堪松下飯，眼明正好橘中棋。',64,'全唐诗/poet.song.239000.json','["身健尚堪松下飯，眼明正好橘中棋。", "青山有約當朱戶，白首何心上彩闈。", "栗里田園供雅興，午橋鍾鼓賞清時。", "晚來倦客秋江上，坐看半天黄鵠飛。"]'),
('4551ea4b-6c82-41f7-a574-b03ab2d40868','用前人韻賦招隠','文天祥','宋','宋诗','song-poetry','','[]','釣魚船上聽吹笛，煨芋爐頭看下棋。',64,'全唐诗/poet.song.239000.json','["釣魚船上聽吹笛，煨芋爐頭看下棋。", "賸有晚愁歸別浦，已無春夢到端闈。", "去年尚憶桃紅處，好景重逢橘綠時。", "珍重山人招隠意，猿啼鶴嘯白雲飛。"]'),
('d4432ab0-1a0b-4744-b94a-9c0e0f4c5192','用前人韻招山行以春爲期','文天祥','宋','宋诗','song-poetry','','[]','掃殘竹徑隨人坐，鑿破苔磯到處棋。',64,'全唐诗/poet.song.239000.json','["掃殘竹徑隨人坐，鑿破苔磯到處棋。", "一水樓臺開曉鏡，萬山花木放春闈。", "雪中便有回舟興，林下豈無燒筍時。", "莫待東風吹柳絮，眼穿籠鶴遶湖飛。"]'),
('983f3e62-04b9-45e1-9d49-c252b5a0da08','翰林權直罷歸和朱約山韻','文天祥','宋','宋诗','song-poetry','','[]','閑雲舒卷無聲畫，醉石敲推一色棋。',64,'全唐诗/poet.song.239000.json','["閑雲舒卷無聲畫，醉石敲推一色棋。", "試問挂瓢棲碧洞，何如襆被卧彤闈。", "夢中芳草還成路，別後黄花又是時。", "羞殺今年堂上燕，片心寄與雁南飛。"]'),
('10aaa368-fd2a-4551-be50-7d7ec1eed5b6','慶羅氏祖母百歲','文天祥','宋','宋诗','song-poetry','','[]','麗日萱花照五雲，升堂風采見乾淳。',64,'全唐诗/poet.song.239000.json','["麗日萱花照五雲，升堂風采見乾淳。", "蓬萊會上逢王母，婺女光中見老人。", "雨露一門華髮潤，江山滿座綵衣新。", "只將千載苓爲壽，更住人間九百春。"]'),
('7b900220-0ca7-47ad-abcc-0b5c4ce38ac0','拜羅氏百歲母之明日主人舉酒客張千載心賦詩某喜贊不自已見之趁韻','文天祥','宋','宋诗','song-poetry','','[]','翠微三島近，畫閣五雲橫。',48,'全唐诗/poet.song.239000.json','["翠微三島近，畫閣五雲橫。", "春水鷗聲滑，夕陽鴉背明。", "尊前持一笑，花下卧餘酲。", "曾見瑶池母，不爲虛此生。"]'),
('4b93c369-1e1a-47a9-a982-27f5cd99fc4d','醉清湖上三日存叟獨不在坐即席有懷','文天祥','宋','宋诗','song-poetry','','[]','石鼎吟方透，瑶觴醉未闌。',48,'全唐诗/poet.song.239000.json','["石鼎吟方透，瑶觴醉未闌。", "疏林花密綴，舊壘燕新安。", "春半湖山好，夜深江海寒。", "王孫隔芳草，初月正相看。"]'),
('3b406ad9-1b94-4e3b-81b6-eb9a0eb10912','羅山長存叟兄弟來謝宴山中','文天祥','宋','宋诗','song-poetry','','[]','天開盤谷隠，春到浣溪家。',48,'全唐诗/poet.song.239000.json','["天開盤谷隠，春到浣溪家。", "一水樓臺影，滿山桃李花。", "春風寄橫笛，夜月擬乘槎。", "政好逢佳客，江空北斗斜。"]'),
('849da8e9-fbc4-49bb-afe3-db8decc1b5fa','壽朱約山八十韻','文天祥','宋','宋诗','song-poetry','','[]','翠袖瓊樓八十翁，平安曉宇看孤鴻。',64,'全唐诗/poet.song.239000.json','["翠袖瓊樓八十翁，平安曉宇看孤鴻。", "五湖圖裏添彭祖，南極光中約祝融。", "日日青山醉春色，年年黄菊飽西風。", "鷹揚但願無施處，臣老婆娑一釣蓬。"]'),
('971d87fd-dc3d-4fc6-b908-f9e687b5c0a3','壽朱約山八十三歲','文天祥','宋','宋诗','song-poetry','','[]','八十餘翁雪滿顛，深衣大带耳垂肩。',64,'全唐诗/poet.song.239000.json','["八十餘翁雪滿顛，深衣大带耳垂肩。", "磻溪回首今三載，絳縣論心又十年。", "歸去來兮真富貴，美哉壽也活神仙。", "門前燕雀紛如雨，媿我白雲深處眠。"]'),
('c056ac7a-52fa-469f-9f3d-b34c75d13141','賀祕書歐陽巽齋先生遷居','文天祥','宋','宋诗','song-poetry','','[]','先生挾冊當菑畬，不待辛勤有屋廬。',64,'全唐诗/poet.song.239000.json','["先生挾冊當菑畬，不待辛勤有屋廬。", "宅樣只還齊里舊，鄉風好似潁川居。", "鏡湖今日賀外監，瀛館前年虞祕書。", "天下經綸猶一室，時人尚敢說吾迂。"]'),
('87895d0e-addf-47d8-bf25-604766aa88ee','挽李制帥二首  其一','文天祥','宋','宋诗','song-poetry','','[]','上下荆淮劍氣雄，進擔全蜀凜英風。',64,'全唐诗/poet.song.239000.json','["上下荆淮劍氣雄，進擔全蜀凜英風。", "將壇歃血金湯志，白腹填天竹帛功。", "治法征謀關世道，精忠定力簡皇衷。", "傷哉生出瞿塘險，翻落黄粱一夢中。"]'),
('4a42b1a9-881b-4497-9d7a-be314a4a4df1','挽李制帥二首  其二','文天祥','宋','宋诗','song-poetry','','[]','世變江河渺未涯，如公真是濟時危。',64,'全唐诗/poet.song.239000.json','["世變江河渺未涯，如公真是濟時危。", "幾年荆益龍驤譽，一日瀟湘鵩讖悲。", "天下皆傳清獻節，人心自有武侯碑。", "郎君昔共慈恩約，抆泪西風寄些詞。"]'),
('64586a67-80b5-46eb-8b7c-af678ed8c1b6','挽孫庸齋','文天祥','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','淮水奇人物，樞星偉弟兄。',48,'全唐诗/poet.song.239000.json','["淮水奇人物，樞星偉弟兄。", "泰山開學譜，雲谷發詩源。", "委吏初行志，修文莫返魂。", "功名傳久遠，頼有二郎存。"]'),
('d58a49cf-4241-489d-a3c2-b120fad59bdd','挽龔用和','文天祥','宋','宋诗','song-poetry','','[]','結屋南陵三十秋，田園舊隠隔江流。',64,'全唐诗/poet.song.239000.json','["結屋南陵三十秋，田園舊隠隔江流。", "鄜州避亂杜工部，下澤乘車馬少遊。", "名利無心付隍鹿，詩書有種出煙樓。", "長淮清野難歸玉，魂魄猶應戀故丘。"]'),
('23a99801-d95f-4b2a-8923-ed89786f9b01','挽萬監丞益之','文天祥','宋','宋诗','song-poetry','','[]','文華時輩右，質樸古風餘。',48,'全唐诗/poet.song.239000.json','["文華時輩右，質樸古風餘。", "壁上舂陵記，屏間太極圖。", "雲山居士屋，風雪故人書。", "一夢中觀化，堯夫以後無。"]'),
('267a38be-d712-4add-b070-ed3e6cef4a5d','哭祕書彭止所','文天祥','宋','宋诗','song-poetry','','[]','人物孤中祕，神山返異仙。',48,'全唐诗/poet.song.239000.json','["人物孤中祕，神山返異仙。", "目穿陪紼處，夢斷曝書年。", "玉質應無死，韋編豈不傳。", "奠芻和泪遣，此月向誰圓。"]'),
('c93f4fed-d95b-4251-9edc-08b51928b434','挽湖守吳西林  其一','文天祥','宋','宋诗','song-poetry','','[]','凜凜千軍筆，堂堂一面威。',48,'全唐诗/poet.song.239000.json','["凜凜千軍筆，堂堂一面威。", "荆流春浪湧，峽樹莫雲飛。", "素壁琴猶在，中橋鶴不歸。", "劍亭遺跡古，豐石照山輝。"]'),
('9944f53b-79d9-40d8-a9ac-f564a2130ba9','挽湖守吳西林  其二','文天祥','宋','宋诗','song-poetry','','[]','傾蓋歲年晚，相知江海深。',48,'全唐诗/poet.song.239000.json','["傾蓋歲年晚，相知江海深。", "春天思北樹，夜雨話西林。", "五嶺生前夢，中原地下心。", "英雄凋落盡，慷慨一霑襟。"]'),
('2b076800-fbef-46c4-9bd9-04b13e66ccbe','挽高郵守晏桂山','文天祥','宋','宋诗','song-poetry','','[]','淮南已仙去，桂樹鬰青青。',48,'全唐诗/poet.song.239000.json','["淮南已仙去，桂樹鬰青青。", "五馬賢聲望，三丞舊典刑。", "邦人多感嘆，諸老半凋零。", "何日持雞酒，傷心請葬銘。"]'),
('203fcd75-f7b0-40a7-a5d5-08715f73c7db','挽鄢晉叔主簿','文天祥','宋','宋诗','song-poetry','','[]','此君何坦坦，迴首杏園遊。',48,'全唐诗/poet.song.239000.json','["此君何坦坦，迴首杏園遊。", "魂魄湘潭去，聲名彭澤休。", "百年中道短，千里故鄉愁。", "六子三方幼，遺言可泪流。"]'),
('2273259c-6f65-4818-aaa7-615affa86786','挽王遠叔','文天祥','宋','宋诗','song-poetry','','[]','孟嘗生五日，白首嘆遭逢。',48,'全唐诗/poet.song.239000.json','["孟嘗生五日，白首嘆遭逢。", "燈火殘編雨，虀鹽短褐風。", "八天下鵰鶚，半水偃蛟龍。", "原上諸生哭，黄花衰草中。"]'),
('4a67bba5-d8cf-4ffc-8631-00697529ff67','挽蕭帥機虎溪','文天祥','宋','宋诗','song-poetry','','[]','世以千金重，誰能學隠君。',48,'全唐诗/poet.song.239000.json','["世以千金重，誰能學隠君。", "一門名似雨，滿座客如雲。", "志願生無憾，聲華死有聞。", "韓碑照原草，含笑有斯文。"]'),
('41408715-de9b-483f-9c9d-17b84db45f9b','挽朱尚書貔孫','文天祥','宋','宋诗','song-poetry','','[]','一代文昌貴，千年諫議名。',48,'全唐诗/poet.song.239000.json','["一代文昌貴，千年諫議名。", "天球聲渾厚，玄酒韻和平。", "巖穴思風采，朝廷惜老成。", "東西生死別，江水泪爲傾。"]'),
('4b6d38ca-26ff-4210-b91c-966deab07460','挽太博朱古平  其一','文天祥','宋','宋诗','song-poetry','','[]','白氏賢司馬，昌黎真學官。',48,'全唐诗/poet.song.239000.json','["白氏賢司馬，昌黎真學官。", "江湖驚落筆，朝野望彈冠。", "天馬高風骨，秋鷹折羽翰。", "萊庭人白髮，煙雨萬松寒。"]'),
('a39c6b79-4c22-47ba-ba4f-7426bfd0037e','挽太博朱古平  其二','文天祥','宋','宋诗','song-poetry','','[]','鐵硯傷同志，青燈憶舊游。',48,'全唐诗/poet.song.239000.json','["鐵硯傷同志，青燈憶舊游。", "臨軒朝鳳闕，馳道聽雞籌。", "魏野神仙宅，元龍湖海樓。", "西風一揮泪，世事蓋棺休。"]'),
('a0298c77-31da-4121-8da2-92258c770f99','挽黎致政','文天祥','宋','宋诗','song-poetry','','[]','楚峰天地闊，四世百年家。',48,'全唐诗/poet.song.239000.json','["楚峰天地闊，四世百年家。", "鶴髮垂袍葉，龍孫上榜花。", "詩書新雨露，松柏老煙霞。", "白馬蒼山路，斯人忽已遐。"]'),
('75d1eafd-a17d-42c9-8a35-05e1dfc400ff','古心江先生以舊弼出鎮長沙癸酉十月乙亥是爲七十六歲門人文某以一節趨走部內謹擬古體一首爲壽','文天祥','宋','宋诗','song-poetry','','[]','炎圖啟丕運，皇路熙以平。',156,'全唐诗/poet.song.239000.json','["炎圖啟丕運，皇路熙以平。", "蜿蟺發令姿，有美洵一人。", "鴻藻舒朝華，大音鏘韶鈞。", "黼珽麗三階，火龍昭紞紘。", "桓圭殿南服，熊旂被金城。", "瞻彼鶉爲火，翼軫宣其精。", "祥鸞舞瑶席，鳴鳳翔媧笙。", "孟冬兆陽氣，西北無浮雲。", "駕言酌春酒，可以寫我情。", "揚旍下祝融，躧履朝泰清。", "嘉猷扇九垓，還以邃古淳。", "君子保金石，所以永國成。", "純嘏錫千歲，綿綿贊休明。"]'),
('ba92a37e-032c-4457-9f3e-bf89eddac677','送張宗甫兄弟楚觀登舟赴湖北試','文天祥','宋','宋诗','song-poetry','','["\u8861\u5c71"]','金螺曉氣照人寒，手把天漿領佩環。',64,'全唐诗/poet.song.239000.json','["金螺曉氣照人寒，手把天漿領佩環。", "夜月送魚來赤壁，秋風吹雁發衡山。", "東南折處旗花見，牛女光中槎影還。", "見說青年文賦好，士龍一笑共雲間。"]'),
('5d2832fa-fbc9-493b-bae0-3770fae434c1','衡州送胡端逸赴漕','文天祥','宋','宋诗','song-poetry','','[]','楚觀簷花曉，舟人擊鼓東。',48,'全唐诗/poet.song.239000.json','["楚觀簷花曉，舟人擊鼓東。", "蛟龍噀靈雨，鵰鶚展雄風。", "此客雲霄士，斯文造化工。", "捷來君飲此，我亦凱元戎。"]'),
('6c2e48a3-3461-40b1-adfe-012d96b15d9d','題楚觀樓','文天祥','宋','宋诗','song-poetry','','[]','西風吹感慨，曉氣薄登臨。',48,'全唐诗/poet.song.239000.json','["西風吹感慨，曉氣薄登臨。", "半壁楚雲立，一川湘雨深。", "乾坤橫笛影，江海倚樓心。", "遺恨飛鴻外，南來訪遠音。"]'),
('5d30fcac-1697-4d2c-a375-6096fda7c4d5','安序宋吏部來牧衡陽某將指聯事好也會以便郡歸養獲忝交承臨發賦詩湘水千里','文天祥','宋','宋诗','song-poetry','','[]','傾蓋年華晚，行人早發湘。',48,'全唐诗/poet.song.239000.json','["傾蓋年華晚，行人早發湘。", "白雲虹浪小，明月燕花香。", "明浦春何急，巴山日正長。", "祝君加一飯，我意爲桐鄉。"]'),
('7d5b5ca1-f5e0-48cb-a3b5-910ef48019c2','贈周東卿畫魚','文天祥','宋','宋诗','song-poetry','','[]','觀君瀟湘圖，起我濠上心。',24,'全唐诗/poet.song.239000.json','["觀君瀟湘圖，起我濠上心。", "短褐波濤舊，秋雨菰蒲深。"]'),
('461675cf-2f9a-47f9-833c-fd8e9d761b1d','某叨臬衡湘蒙恩以便郡歸養肯齋大卿實寓衡我十年前邦君也一再見間即分南北五言啟之所以致今舊雨繾綣云','文天祥','宋','宋诗','song-poetry','','[]','瀟湘一夜雨，湖海十年雲。',48,'全唐诗/poet.song.239000.json','["瀟湘一夜雨，湖海十年雲。", "相見皆成老，重逢便作分。", "啼鵑春浩蕩，回雁曉殷勤。", "江闊人方健，月明思對君。"]'),
('17893d44-6aa9-4e48-927f-8b8e8b8d2b31','幕客載酒舟中即席序別','文天祥','宋','宋诗','song-poetry','','[]','故人滿江海，遊子下瀟湘。',48,'全唐诗/poet.song.239000.json','["故人滿江海，遊子下瀟湘。", "夢載月千里，意行雲一方。", "櫓聲人語小，岸影客心長。", "總是浮萍迹，飛花莫近檣。"]'),
('9cd4c25b-090e-4c90-85f7-830cb34b3260','用韻謝諸客和章','文天祥','宋','宋诗','song-poetry','','[]','傳鼓發船去，我秦君向湘。',48,'全唐诗/poet.song.239000.json','["傳鼓發船去，我秦君向湘。", "持螯思太白，占鵲問東方。", "世味秋雲薄，交情江水長。", "相期天路曉，陣馬度風檣。"]'),
('cb0f20a0-f8f4-4cf4-8253-1e6709f247ef','湘潭道中贈丁碧眼相士  其一','文天祥','宋','宋诗','song-poetry','','["\u8861\u5c71"]','自詭衡山道士孫，至今句法有軒轅。',32,'全唐诗/poet.song.239000.json','["自詭衡山道士孫，至今句法有軒轅。", "世人未見題堯廟，盡把昌黎作寓言。"]'),
('be74cd83-41a8-4bf7-a5ff-b0d27bd0a689','湘潭道中贈丁碧眼相士  其二','文天祥','宋','宋诗','song-poetry','','[]','收拾衡雲作羽衣，便如屈子遠遊歸。',32,'全唐诗/poet.song.239000.json','["收拾衡雲作羽衣，便如屈子遠遊歸。", "離騷忘却題天柱，爲立斜陽問翠微。"]'),
('66273936-e5ec-4b1e-acd1-7bd92d300080','咸淳甲戌第二朔予道櫧洲里徐畋方諫自長沙來爲別問客幾何曰半年矣臨別爲賦','文天祥','宋','宋诗','song-poetry','','[]','君爲湘水燕，我作衡陽雁。',24,'全唐诗/poet.song.239000.json','["君爲湘水燕，我作衡陽雁。", "雁去燕方留，白雲草迷岸。"]'),
('51a18199-7fab-44bd-b962-08ed6d3bd02b','和衡守宋安序送行詩  其一','文天祥','宋','宋诗','song-poetry','','[]','玉立湘西第一州，丹梯小爲嶽雲留。',64,'全唐诗/poet.song.239000.json','["玉立湘西第一州，丹梯小爲嶽雲留。", "東風城郭人行樂，春日旌旗公出遊。", "便趁綈香摩碧漢，莫嫌綉影涴清流。", "兩君相見衣冠好，記取兒孫好話頭。"]'),
('f6ad078b-b00e-4033-9189-596680323a7a','和衡守宋安序送行詩  其二','文天祥','宋','宋诗','song-poetry','','[]','方共衡雲把酒杯，春風吹向鬰孤臺。',64,'全唐诗/poet.song.239000.json','["方共衡雲把酒杯，春風吹向鬰孤臺。", "雁將回處驚帆落，花未開時怯笛催。", "別草可堪遊子去，寄梅應爲故人來。", "臨行笑覓凝香譜，十駕那追逸驥材。"]'),
('fb3e4d67-8f61-41ba-aee7-93bb416563c6','贈萍鄉道士','文天祥','宋','宋诗','song-poetry','','[]','道上觀行人，半似重相見。',48,'全唐诗/poet.song.239000.json','["道上觀行人，半似重相見。", "古云性相近，性豈不如面。", "萬形本一性，萬心方一殊。", "世固難絕聖，亦恐難絕愚。"]'),
('b1ef4502-3b3a-4de0-b9db-2a2f4c46a715','白髭行','文天祥','宋','宋诗','song-poetry','','[]','憶昔守宣時，白上一根髮。',120,'全唐诗/poet.song.239000.json','["憶昔守宣時，白上一根髮。", "去之四五年，一化爲七八。", "今年客衡湘，黑髭已多黄。", "衆黄忽一白，驚見如陵陽。", "白髮已爲常，白髭何足怪。", "歲月不可歇，雪霜日長大。", "世人競染緇，厭之固足嗤。", "誰服蘆菔湯，避老亦奚爲。", "少老如春秋，造物以爲儔。", "吾方樂吾天，樂天故不憂。"]'),
('2511bcdd-33b2-4f6f-9105-484c95fe9ca5','將母赴贛道西昌','文天祥','宋','宋诗','song-poetry','','[]','重來鷗閣曉，帆影漲新晴。',48,'全唐诗/poet.song.239000.json','["重來鷗閣曉，帆影漲新晴。", "倚檻雲來去，閉簾花送迎。", "江湖春汗漫，歲月老崢嶸。", "手把忘憂草，夔夔繞太清。"]'),
('ea9e7dc4-4a58-4c2a-8c32-edaa088f52fe','快閣遇雨觀瀾','文天祥','宋','宋诗','song-poetry','','[]','一笑登臨晚，江流接太虛。',48,'全唐诗/poet.song.239000.json','["一笑登臨晚，江流接太虛。", "自慚雲出岫，爭訝雨隨車。", "慷慨十圍柳，周回千里魚。", "故園隄好在，夜夢繞吾廬。"]'),
('74d44516-9bc6-44a3-8898-97dd5c48ceb3','題鬰孤臺','文天祥','宋','宋诗','song-poetry','','[]','城郭春聲闊，樓臺晝影遲。',48,'全唐诗/poet.song.239000.json','["城郭春聲闊，樓臺晝影遲。", "并天浮雪界，蓋海出雲旗。", "風雨十年夢，江湖萬里思。", "倚闌時北顧，空翠濕朝曦。"]'),
('c4d51b92-a4f0-422b-ae6f-5eb66adacbe1','予題鬰孤泉管五湖翁姚濂爲之和翁官滿歸里因韻贄別并謝前辱','文天祥','宋','宋诗','song-poetry','','[]','巢龜君往好，涌翠我來遲。',48,'全唐诗/poet.song.239000.json','["巢龜君往好，涌翠我來遲。", "夜雨呼三韭，春風試一旗。", "飛花行客夢，芳草故人思。", "何日五湖上，同看浴海曦。"]'),
('8b6f64dc-3ca9-4dfc-8a95-b2be4b01cb43','用韻謝前人','文天祥','宋','宋诗','song-poetry','','[]','茲遊良邂逅，吾道未逶遲。',48,'全唐诗/poet.song.239000.json','["茲遊良邂逅，吾道未逶遲。", "斗野橫雙劍，牛津直兩旗。", "此風應小住，明日便相思。", "輸與君家近，扶桑五色曦。"]'),
('670b853a-de0b-4430-9e97-70ed6d6fc5bc','翠玉樓晚雨','文天祥','宋','宋诗','song-poetry','','[]','晚樓一曲轉梅花，官事無多報放衙。',64,'全唐诗/poet.song.239000.json','["晚樓一曲轉梅花，官事無多報放衙。", "林木蔽虧煙斷續，江流曲折雨橫斜。", "年華冉冉風前影，歲莫悠悠客裏家。", "一雁近從沙觜落，更饒片雪入天涯。"]'),
('e8faebce-31d3-4884-99b1-fa112e7c6ab0','翠玉樓觀雪','文天祥','宋','宋诗','song-poetry','','[]','矯矯臨清泚，濛濛認翠微。',48,'全唐诗/poet.song.239000.json','["矯矯臨清泚，濛濛認翠微。", "綈春生客袖，鐵冷上戎衣。", "柳眼驚何老，梅花覺半肥。", "新來有公事，白戰破重圍。"]'),
('fb3f34e9-d55b-4a90-bff9-7bf6fcda322e','翠玉樓和胡端逸韻','文天祥','宋','宋诗','song-poetry','','[]','客影魚千里，年華柳十圍。',48,'全唐诗/poet.song.239000.json','["客影魚千里，年華柳十圍。", "白雲栖石密，黄鵠出煙微。", "江海秋風老，湖山晚日暉。", "鬰孤臺上望，野闊犢初肥。"]'),
('d746022e-3bc5-4b2d-8609-3b0f96181d18','翠玉樓','文天祥','宋','宋诗','song-poetry','','[]','昏鴉何處落，野渡少人行。',48,'全唐诗/poet.song.239000.json','["昏鴉何處落，野渡少人行。", "黄葉聲在地，青山影入城。", "江湖行客夢，風雨故鄉情。", "試問南來信，梅花三兩英。"]'),
('507b1df5-24b0-46d5-91ba-d51965f08ca1','合江樓  其一','文天祥','宋','宋诗','song-poetry','','[]','天上名鶉尾，人間說虎頭。',48,'全唐诗/poet.song.239000.json','["天上名鶉尾，人間說虎頭。", "春風千萬岫，秋水兩三洲。", "客晚驚黄葉，官閑笑白鷗。", "雙江日東下，我欲賦扁舟。"]'),
('1c694920-d91b-4e14-846e-b694f5419c1b','合江樓  其二','文天祥','宋','宋诗','song-poetry','','[]','西楚驚鴻晚，東淮落木秋。',48,'全唐诗/poet.song.239000.json','["西楚驚鴻晚，東淮落木秋。", "蒸湘今石鼓，句宛古宣州。", "白日聊清賞，青山總舊遊。", "不知滄海水，何處接天流。"]'),
('3eb49c9c-f5a7-42d6-81ab-fdbf35cd2939','皂蓋樓','文天祥','宋','宋诗','song-poetry','','[]','一水樓臺繞，半空圖畫開。',48,'全唐诗/poet.song.239000.json','["一水樓臺繞，半空圖畫開。", "蝸涎行薜荔，雀影上莓苔。", "碧落人千載，青山酒一杯。", "晚煙看不盡，待月却歸來。"]'),
('a16de87b-feec-4ac0-b593-f6ae83a5d8f4','石樓','文天祥','宋','宋诗','song-poetry','','[]','曉色重簾捲，春聲疊鼓催。',48,'全唐诗/poet.song.239000.json','["曉色重簾捲，春聲疊鼓催。", "長垣連草樹，遠水照樓臺。", "八境煙濃淡，六街人往來。", "平安消息好，看到嶺頭梅。"]'),
('aff87b3a-be6b-4b84-8952-0a7a9a1b95be','馬祖巖','文天祥','宋','宋诗','song-poetry','','[]','曾將飛錫破苔痕，一片雲根鎖洞門。',32,'全唐诗/poet.song.239000.json','["曾將飛錫破苔痕，一片雲根鎖洞門。", "山外人家山下路，石頭心事付無言。"]'),
('af54dc61-b3be-4fe0-a208-ca417cdf513d','禪關','文天祥','宋','宋诗','song-poetry','','[]','秋風吹日上禪關，路入松花第一彎。',32,'全唐诗/poet.song.239000.json','["秋風吹日上禪關，路入松花第一彎。", "只願四時煙霧少，滿城樓閣見青山。"]'),
('80fdbe5b-d993-4cdb-a285-d40ac21f96af','吸江','文天祥','宋','宋诗','song-poetry','','[]','絕壁千尋俯雪潭，春花秋草有䰐鬖。',32,'全唐诗/poet.song.239000.json','["絕壁千尋俯雪潭，春花秋草有䰐鬖。", "當年誤著蒲團坐，惹得人稱馬祖巖。"]'),
('c03a93ba-c7c2-40be-96cf-02504e5c98ae','塵外','文天祥','宋','宋诗','song-poetry','','[]','半山風雨截江城，未脫人間總是塵。',32,'全唐诗/poet.song.239000.json','["半山風雨截江城，未脫人間總是塵。", "中夜起看衣上月，青天如水露華新。"]'),
('f3188ec2-5c48-4e24-ad65-eb1a57bce9c6','雲端','文天祥','宋','宋诗','song-poetry','','[]','半空夭矯起層臺，傳道劉安車馬來。',32,'全唐诗/poet.song.239000.json','["半空夭矯起層臺，傳道劉安車馬來。", "山上自晴山下雨，倚闌平立看風雷。"]'),
('5ed35aac-1579-4a67-a61b-12732e2d9bff','清江何漢英再見於空同讀歐陽先生詩感慨爲賦','文天祥','宋','宋诗','song-poetry','','[]','采芝雲滿山，采檗瀑垂澗。',108,'全唐诗/poet.song.239000.json','["采芝雲滿山，采檗瀑垂澗。", "當年有清徽，爲寄南來雁。", "雁去人已逝，歲月剨云晏。", "流水失聲音，西河老憂患。", "往日志士悲，窮途行子慣。", "君爲梁宋遊，我復江漢宦。", "十年耿相逢，千里欠一盼。", "玄機寄糟粕，美疢墮芻豢。", "贈子歸東方，聊薦吳興莧。"]'),
('8b71b29f-2e29-4af9-be8d-f1566a6d3071','送曹倅巖山官滿歸里','文天祥','宋','宋诗','song-poetry','','[]','春陵光霽落蒼苔，葛水神仙立翠槐。',64,'全唐诗/poet.song.239000.json','["春陵光霽落蒼苔，葛水神仙立翠槐。", "萬里雲霞麒驥路，三年風月鳳凰臺。", "興同老子復不淺，歌曰先生歸去來。", "庾嶺梅花開漸徧，一枝就與寄蓬萊。"]'),
('a8437597-34d5-408e-9522-8289fc08cfac','和前人賦別  其一','文天祥','宋','宋诗','song-poetry','','[]','翠松三萬頃，松雪著神仙。',48,'全唐诗/poet.song.239000.json','["翠松三萬頃，松雪著神仙。", "柳院催金鑰，江花送玉鞭。", "曉巖雲壁立，晚棹浪規圓。", "未了醉翁事，重尋潁上田。"]'),
('17aae07d-5cad-4ba1-92d3-1f70c399017e','和前人賦別  其二','文天祥','宋','宋诗','song-poetry','','[]','當年童子見，今見二毛翁。',48,'全唐诗/poet.song.239000.json','["當年童子見，今見二毛翁。", "海月三秋別，江雲一日同。", "鷗心馳舍北，龍尾曳天東。", "定有延和奏，南來寄一通。"]'),
('3dabd86d-ff39-429b-957d-1e5fe88307e4','贈明脈蕭信叔','文天祥','宋','宋诗','song-poetry','','[]','枚乘擅七發，郭玉明四難。',72,'全唐诗/poet.song.239000.json','["枚乘擅七發，郭玉明四難。", "微言起沈痼，此道今漫漫。", "云何東海生，而乃緒真要。", "砉然以神遇，契彼鏡經妙。", "我欲炊彫胡，俯鑿菊水泉。", "壽彼方輿人，六氣何由諐。"]'),
('c53d0021-dd71-4872-8b36-5a5609eb8d00','贈林碧鑒相士','文天祥','宋','宋诗','song-poetry','','[]','咸陽宮中四尺鏡，照人五臟何烱烱。',140,'全唐诗/poet.song.239000.json','["咸陽宮中四尺鏡，照人五臟何烱烱。", "桑田滄海千餘年，百鍊依然化爲礦。", "君從何處得此物，鑄就雙瞳敵秋月。", "向來照心今照形，不事瀾翻三寸舌。", "遠衝風雪肯我過，看來猶未深知我。", "我方簑笠立釣磯，萬事浮雲都勘破。", "噫嘻吁，只今神目鬼眼紛道途，暗中許負應盧胡。", "試問何如林家老碧鑒，不知天津橋上復有龍鍾無。"]'),
('23e3bd2c-dba3-40cb-b725-8ab5b9759687','送吉州陳守解任','文天祥','宋','宋诗','song-poetry','','[]','美人策良馬，弭節螺江湄。',108,'全唐诗/poet.song.239000.json','["美人策良馬，弭節螺江湄。", "歲年忽晼晚，桃李已成蹊。", "遥遥一水間，復復東與西。", "晴川夾修楊，行舟何能維。", "朱鳳翔海山，層漢揚音徽。", "高岡有梧桐，駕言覽朝暉。", "贈君以白雲，白雲不我持。", "贈君以明月，明月不我携。", "白雲與明月，遠道相追隨。"]'),
('db33b487-60da-455b-ac47-92872ccf23be','贈蜀醫鍾正甫','文天祥','宋','宋诗','song-poetry','','[]','炎皇覽衆草，異種多西州。',72,'全唐诗/poet.song.239000.json','["炎皇覽衆草，異種多西州。", "爲君望岷峨，使我雙泪流。", "向來秦越人，朝洛夕邯鄲。", "子持鵲經來，自西亦徂南。", "江南有羈羽，豈不懷故營。", "何當同皇風，六氣和且平。"]'),
('31b237be-b939-48ab-bcfa-d8208c018b3e','改題萬安縣凝祥觀','文天祥','宋','宋诗','song-poetry','','[]','古道松花空翠香，風前鬢影照滄浪。',64,'全唐诗/poet.song.239000.json','["古道松花空翠香，風前鬢影照滄浪。", "飛泉半壁朝雲濕，啼鳥滿山春日長。", "須信神仙元有國，不知蠻觸是何鄉。", "道人橫笛招歸鶴，坐到斜暉上壁璫。"]'),
('74325c17-ae7e-4b2a-a40f-5bbf617fc9b1','西昌倪氏有山谷書杜陵山水圖障歌作江山堂堂廢其後人以黄書求題跋感慨一絕','文天祥','宋','宋诗','song-poetry','','[]','杜二已無黄九去，長歌大字落江山。',32,'全唐诗/poet.song.239000.json','["杜二已無黄九去，長歌大字落江山。", "百年風物今何似，春水晚煙飛白鷳。"]'),
('1b15ba3c-e30e-45d9-98ab-2d44bfc1f6e4','山中再次胡德昭韻  其一','文天祥','宋','宋诗','song-poetry','','[]','不將顔色汗黄金，落得灞橋馿上吟。',64,'全唐诗/poet.song.239000.json','["不將顔色汗黄金，落得灞橋馿上吟。", "是處江山生酒興，滿天風雪得梅心。", "觥籌堂裏春聲沸，燈火林臯夜色深。", "人世可能行樂耳，重游不用卜晴陰。"]'),
('ed1e8c1a-28ff-41a7-9c5c-30887f9668c9','山中再次胡德昭韻  其二','文天祥','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','人生柳絮鬭堅牢，過眼春光歎伯勞。',64,'全唐诗/poet.song.239000.json','["人生柳絮鬭堅牢，過眼春光歎伯勞。", "蜀道謾傳千古險，廬山方許一人高。", "眼前見赤徒妨道，耳後生風未當豪。", "明月蘆花隨處有，扁舟自在不須篙。"]'),
('824f6d7f-b635-41ae-8203-72a8f4842298','山中再次胡德昭韻  其三','文天祥','宋','宋诗','song-poetry','','[]','曾見尊前此客哉，笑携麈尾拂莓苔。',64,'全唐诗/poet.song.239000.json','["曾見尊前此客哉，笑携麈尾拂莓苔。", "水邊飛雁年年見，湖上新亭日日來。", "酹菊醉餘披草坐，探梅吟罷带花回。", "北崖尚被剛風隔，笑按匆匆上馬杯。"]'),
('6cf7df7e-1cd3-490a-8cc4-dcb3b2fedccd','山中泛舟觴客','文天祥','宋','宋诗','song-poetry','','[]','便作乘槎客，蕭蕭骨髮清。',48,'全唐诗/poet.song.239000.json','["便作乘槎客，蕭蕭骨髮清。", "尊前山月過，笛裏水風生。", "半夜魚龍沸，三秋河漢明。", "雪堂眠二客，夢與白鷗盟。"]'),
('3fcc16c3-fe4b-4b2a-850b-3bdbd26d140f','病中作','文天祥','宋','宋诗','song-poetry','','[]','六月廿四夜，人間熱欲炊。',48,'全唐诗/poet.song.239000.json','["六月廿四夜，人間熱欲炊。", "病懷如酒困，倦睫似書癡。", "夢與千年接，心隨萬里馳。", "客來相問訊，寄語有新詩。"]'),
('c5749425-64ff-4fea-b354-cf55c1b782ef','山中即事','文天祥','宋','宋诗','song-poetry','','[]','山中方雨笠，天外忽晴絲。',48,'全唐诗/poet.song.239000.json','["山中方雨笠，天外忽晴絲。", "夕釣江澄練，春行路布棋。", "乾坤供俯仰，歲月任差池。", "有酒如澠在，何妨日問奇。"]'),
('29f0f38d-eec3-463c-9a2b-6942b611c67c','挽巽齋先生歐陽大著','文天祥','宋','宋诗','song-poetry','','[]','徘徊西河上，月落衆星稀。',144,'全唐诗/poet.song.239000.json','["徘徊西河上，月落衆星稀。", "哲人萎中道，雨絕將安之。", "昔者麗鴻藻，玉振含清暉。", "名理軼晉魏，雅言襲軻思。", "連駕覲馳道，并坐侍端闈。", "及門懷燕婉，升堂接逶迤。", "方期黄鵠翔，忽作朝露晞。", "黔婁不蓋體，延陵有遺悲。", "層阿翳寒樹，平楚曖希微。", "帷㡛衣廣柳，縞冠涕如縻。", "水從章江去，雲遶楚山飛。", "已矣如有聞，斯文不在茲。"]'),
('5233cfcd-6713-478e-bffa-daf960c5cdc6','送劉其發入蜀','文天祥','宋','宋诗','song-poetry','','[]','秋風凄已寒，蜀道阻且長。',96,'全唐诗/poet.song.239000.json','["秋風凄已寒，蜀道阻且長。", "虎狼伏原野，欲濟川無梁。", "客從何處來，云我之西方。", "蕭蕭驌驦鳴，熠熠湛盧光。", "昔時榮華地，今爲爭戰場。", "將軍揚天戈，壯士發戎行。", "江南有羈鳥，悠悠懷故鄉。", "駕言與子遊，雲天何茫茫。"]'),
('93074c02-528d-41de-ae61-298b525f9ad7','周蒼崖入吾山作圖詩贈之','文天祥','宋','宋诗','song-poetry','','[]','三生石上結因緣，袍笏橫斜學米顛。',64,'全唐诗/poet.song.239000.json','["三生石上結因緣，袍笏橫斜學米顛。", "漁父幾忘山下路，仙人時訪嶺頭船。", "烏猨白鶴無根樹，淡月疏星一線天。", "爲我醉呼添濛澒，倦來平卧看雲煙。"]'),
('eed1f4ea-3cc0-4e76-b93a-49af8a12dd43','題羅次說竹巖摘藁','文天祥','宋','宋诗','song-poetry','','[]','游子西南來，出門道何悠。',48,'全唐诗/poet.song.239000.json','["游子西南來，出門道何悠。", "文章會有用，意氣輕身謀。", "紛紛食粱肉，藜藿當其憂。", "君看百川水，何處不東流。"]'),
('f9334f57-cda1-4dc5-97ff-f106492aa76e','挽劉知縣','文天祥','宋','宋诗','song-poetry','','[]','玉海淵源懿，金閨步武高。',48,'全唐诗/poet.song.239000.json','["玉海淵源懿，金閨步武高。", "功名千載意，翰墨一時豪。", "天馬含風骨，秋鷹折羽毛。", "相逢俱白髮，流涕濕征袍。"]'),
('27ef6971-df2d-4ce5-9291-da0b5ab2ad3a','古樂府','文天祥','宋','宋诗','song-poetry','','[]','珊瑚香點胭脂雪，芙蓉帳壓春雲熱。',144,'全唐诗/poet.song.239000.json','["珊瑚香點胭脂雪，芙蓉帳壓春雲熱。", "明朝早弄燈前月，瀲灧九霞碧藕折。", "璇杓高聳婺女明，金波漾曉輝郎星。", "赤瓊曲裏長眉青，頭上更有瑶池君。", "六九五十四東風，西蟠桃花花未紅。", "鳴鸞鼓玉聲玲瓏，綠毛蒙茸蓮水龜。", "媥斕五色人間稀，春多瑞葉不敢飛。", "冰壺光滿魚龍轉，笑中低舞玉釵燕。", "明年今日長秋殿，安輿入侍金桃宴。"]'),
('596082a5-a388-42f2-9ae8-843246f087ab','赴闕','文天祥','宋','宋诗','song-poetry','','[]','楚月穿春袖，吳霜透曉韉。',48,'全唐诗/poet.song.239000.json','["楚月穿春袖，吳霜透曉韉。", "壯心欲填海，苦膽爲憂天。", "役役慙金注，悠悠歎瓦全。", "丈夫竟何事，一日定千年。"]'),
('16db2a4f-a23c-4381-9269-68419874fbfd','所懷','文天祥','宋','宋诗','song-poetry','','[]','只把初心看，休將近事論。',48,'全唐诗/poet.song.239000.json','["只把初心看，休將近事論。", "誓爲天出力，疑有鬼迷魂。", "明月夜推枕，春風晝閉門。", "故人萬山外，俯仰向誰言。"]'),
('0389663a-7ca0-4e32-8f3d-ad52bf4b416e','自嘆','文天祥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','長安不可詣，何故會臯亭。',48,'全唐诗/poet.song.239000.json','["長安不可詣，何故會臯亭。", "倦鳥非無翼，神龜弗自靈。", "乾坤增感慨，身世付飄零。", "回首西湖曉，雨餘山更青。"]'),
('c3f27d62-1065-40d2-88d6-103ac61e6f13','鐵錯','文天祥','宋','宋诗','song-poetry','','[]','貔貅十萬衆，日夜望南轅。',48,'全唐诗/poet.song.239000.json','["貔貅十萬衆，日夜望南轅。", "老馬翻迷路，羝羊竟觸藩。", "武夫傷鐵錯，達士笑金昏。", "單騎見回紇，汾陽豈易言。"]'),
('ce24719e-b555-4d0a-a814-f15f4d26eae1','和言字韻','文天祥','宋','宋诗','song-poetry','','[]','悠悠天地闊，世事與誰論。',48,'全唐诗/poet.song.239000.json','["悠悠天地闊，世事與誰論。", "清夜爲揮涕，白雲空斷魂。", "死生蘇子節，貴賤翟公門。", "前輩如瓶戒，無言勝有言。"]'),
('95b44cab-2ad2-4adb-8425-404964e20df5','愧故人','文天祥','宋','宋诗','song-poetry','','[]','九門一夜漲風塵，何事癡兒竟誤身。',64,'全唐诗/poet.song.239000.json','["九門一夜漲風塵，何事癡兒竟誤身。", "子産片言圖救鄭，仲連本志爲排秦。", "但知慷慨稱男子，不料蹉跎愧故人。", "玉勒雕鞍南上去，天高月冷泣孤臣。"]'),
('eaa8249f-ca6f-4aa9-a05f-085a71e63c86','求客','文天祥','宋','宋诗','song-poetry','','[]','眼看銅駝燕雀羞，東風花柳自皇州。',64,'全唐诗/poet.song.239000.json','["眼看銅駝燕雀羞，東風花柳自皇州。", "白雲萬里易成夢，明月一間都是愁。", "男子鐵心無地著，故人血淚向天流。", "鷄鳴曾脫函關厄，還有當年此客不。"]'),
('ab15ef95-6b55-4a2c-83e5-d920205f8e54','紀事  其一','文天祥','宋','宋诗','song-poetry','','[]','三宮九廟事方危，狼子心腸未可知。',32,'全唐诗/poet.song.239000.json','["三宮九廟事方危，狼子心腸未可知。", "若使無人折狂虜，東南那箇是男兒。"]'),
('4affbae0-bdd2-45a0-9352-8c2e315d56f9','紀事  其二','文天祥','宋','宋诗','song-poetry','','[]','春秋人物類能言，宗國常因口舌存。',32,'全唐诗/poet.song.239000.json','["春秋人物類能言，宗國常因口舌存。", "我亦瀕危專對出，北風滿野負乾坤。"]'),
('18f7ee45-a315-4c19-a43e-169ce57eb81d','紀事  其三','文天祥','宋','宋诗','song-poetry','','[]','單騎堂堂詣虜營，古今禍福了如陳。',32,'全唐诗/poet.song.239000.json','["單騎堂堂詣虜營，古今禍福了如陳。", "北方相顧稱男子，似謂江南尚有人。"]'),
('ee77abff-d595-4ad1-a2f0-6e3706e6065b','紀事  其四','文天祥','宋','宋诗','song-poetry','','[]','百色無厭不可支，甘心賣國問爲誰。',32,'全唐诗/poet.song.239000.json','["百色無厭不可支，甘心賣國問爲誰。", "豺狼尚畏忠臣在，相戒勿令丞相知。"]'),
('01e606d3-d48e-449a-81c5-595b18658557','紀事  其五','文天祥','宋','宋诗','song-poetry','','[]','慷慨輕身墮蒺藜，羝羊生乳是歸期。',32,'全唐诗/poet.song.239000.json','["慷慨輕身墮蒺藜，羝羊生乳是歸期。", "豈無從史私袁盎，恨我從前少侍兒。"]'),
('a5d74c21-d9e0-4315-8985-bc7dab7cdd01','紀事  其六','文天祥','宋','宋诗','song-poetry','','[]','英雄未肯死前休，風起雲飛不自由。',32,'全唐诗/poet.song.239000.json','["英雄未肯死前休，風起雲飛不自由。", "殺我混同江外去，豈無曹翰守幽州。"]'),
('20d3f209-aca9-4a64-a4f5-f35317ea1463','紀事','文天祥','宋','宋诗','song-poetry','','[]','狼心那顧歃銅盤，舌在縱橫擊可汗。',32,'全唐诗/poet.song.239000.json','["狼心那顧歃銅盤，舌在縱橫擊可汗。", "自分身爲虀粉碎，虜中方作丈夫看。"]'),
('5913e399-9754-43dd-b022-4590384aefd7','紀事  其一','文天祥','宋','宋诗','song-poetry','','[]','不拚一死報封疆，忍使湖山牧虎狼。',32,'全唐诗/poet.song.239000.json','["不拚一死報封疆，忍使湖山牧虎狼。", "當日本爲妻子計，而今何面見三光。"]'),
('fbe7fb71-9c81-4c4e-86dc-3a241cef682a','紀事  其二','文天祥','宋','宋诗','song-poetry','','[]','虎頭牌子織金裳，北面三年蟻夢長。',32,'全唐诗/poet.song.239000.json','["虎頭牌子織金裳，北面三年蟻夢長。", "借問一門朱與紫，江南幾世謝君王。"]'),
('d2efcb19-feb4-47dc-bf31-42dc602c1b8b','紀事  其三','文天祥','宋','宋诗','song-poetry','','[]','梟獍何堪共勸酬，衣冠塗炭可勝羞。',32,'全唐诗/poet.song.239000.json','["梟獍何堪共勸酬，衣冠塗炭可勝羞。", "袖中若有擊賊笏，便使兇渠面血流。"]'),
('970d39b1-f846-4938-976f-6cf9b27e7cc9','紀事  其四','文天祥','宋','宋诗','song-poetry','','[]','麟筆嚴於首惡書，我將口舌擊奸諛。',32,'全唐诗/poet.song.239000.json','["麟筆嚴於首惡書，我將口舌擊奸諛。", "雖非周勃安劉手，不愧當年産祿誅。"]'),
('f18bb401-14b6-4575-9524-d374e5c46f87','信雲父  其一','文天祥','宋','宋诗','song-poetry','','[]','東魯遺黎老子孫，南方心事北方身。',32,'全唐诗/poet.song.239000.json','["東魯遺黎老子孫，南方心事北方身。", "幾多江左腰金客，便把君王作路人。"]'),
('58430755-dd1e-4f7e-b4da-7e1cc7c55300','信雲父  其二','文天祥','宋','宋诗','song-poetry','','[]','肯從悟室課兒書，嚙雪風流却減渠。',32,'全唐诗/poet.song.239000.json','["肯從悟室課兒書，嚙雪風流却減渠。", "我愛信陵冠带意，任教句法問何如。"]'),
('13577484-8a22-42ac-ab63-76dda8371e10','則堂  其一','文天祥','宋','宋诗','song-poetry','','[]','山河四塞舊甌金，藝祖高宗實鑒臨。',32,'全唐诗/poet.song.239000.json','["山河四塞舊甌金，藝祖高宗實鑒臨。", "一日盡將輸敵手，何人賣國獨甘心。"]'),
('234c05da-c2c8-47bf-a2d5-60426a1e67f5','則堂  其二','文天祥','宋','宋诗','song-poetry','','[]','中書堂帖下諸城，摇首庭中號獨清。',32,'全唐诗/poet.song.239000.json','["中書堂帖下諸城，摇首庭中號獨清。", "此後方知樞密事，從今北地轉相驚。"]'),
('dacb6e3e-f7f7-401f-b9c7-412e9e735283','思蒲塘','文天祥','宋','宋诗','song-poetry','','[]','揚旌來冉冉，捲旆去堂堂。',48,'全唐诗/poet.song.239000.json','["揚旌來冉冉，捲旆去堂堂。", "恨我飛無翼，思君濟有航。", "麒麟還共處，熊虎已何鄉。", "南國應無恙，中興事會長。"]'),
('71b24987-d519-43ee-beb0-013244af1aa3','思方將軍','文天祥','宋','宋诗','song-poetry','','[]','始興溪子下江淮，曾爲東南再造來。',32,'全唐诗/poet.song.239000.json','["始興溪子下江淮，曾爲東南再造來。", "如虎如熊今固在，將軍何處上金臺。"]'),
('0535b2e1-aa17-4aaa-bf4d-dfa4ea722197','唆都','文天祥','宋','宋诗','song-poetry','','[]','虎牌氈笠號公卿，不直人間一唾輕。',32,'全唐诗/poet.song.239000.json','["虎牌氈笠號公卿，不直人間一唾輕。", "但願扶桑紅日上，江南匹士死猶榮。"]'),
('70e8ae93-543e-4045-b53a-9515de9b7b3d','二王','文天祥','宋','宋诗','song-poetry','','[]','一馬渡江開晉土，五龍夾日復唐天。',32,'全唐诗/poet.song.239000.json','["一馬渡江開晉土，五龍夾日復唐天。", "內家苗裔真隆準，虜運從來無百年。"]'),
('5719bf5b-14b4-4ff0-ba08-3eabe2a683d5','氣概','文天祥','宋','宋诗','song-poetry','','[]','氣概如虹俺得知，留吳那肯豎降旗。',32,'全唐诗/poet.song.239000.json','["氣概如虹俺得知，留吳那肯豎降旗。", "北人不解欺心語，正恐南人作淺窺。"]'),
('970dd0cb-1644-463c-906d-5d93a5dd7cd0','使北  其一','文天祥','宋','宋诗','song-poetry','','[]','自說家鄉古相州，白麻風旨出狂酋。',32,'全唐诗/poet.song.239000.json','["自說家鄉古相州，白麻風旨出狂酋。", "中書盡出降元表，北渡黄河衣錦游。"]'),
('48443d5e-0086-4c49-82c8-f3b2fdcd9be3','使北  其二','文天祥','宋','宋诗','song-poetry','','[]','至尊馳表獻燕城，肉食那知以死爭。',32,'全唐诗/poet.song.239000.json','["至尊馳表獻燕城，肉食那知以死爭。", "當代老儒居首揆，殿前陪拜率公卿。"]'),
('81cf4e5b-baeb-4cfd-bf42-c2db283ccb6c','使北  其三','文天祥','宋','宋诗','song-poetry','','[]','江南浪子是何官，只當空廬雜劇看。',32,'全唐诗/poet.song.239000.json','["江南浪子是何官，只當空廬雜劇看。", "撥取公卿如糞土，沐猴徒自辱衣冠。"]'),
('c23f561c-0d03-48c6-91b9-f0d0a39b0259','使北  其四','文天祥','宋','宋诗','song-poetry','','[]','公子方張奉使旗，行行且尼復何爲。',32,'全唐诗/poet.song.239000.json','["公子方張奉使旗，行行且尼復何爲。", "似聞傾盡黄金塢，辛苦平生只爲誰。"]'),
('e0836829-0cf2-4f95-90ff-b1543314dabf','使北  其五','文天祥','宋','宋诗','song-poetry','','[]','廷爭堂堂負直聲，飄零沙漠若爲情。',32,'全唐诗/poet.song.239000.json','["廷爭堂堂負直聲，飄零沙漠若爲情。", "程嬰存趙真公志，頼有忠良壯此行。"]'),
('b6359757-bdf4-45cb-af94-e1302005f1bc','使北  其六','文天祥','宋','宋诗','song-poetry','','[]','初修降表我無名，不是隨班拜舞人。',32,'全唐诗/poet.song.239000.json','["初修降表我無名，不是隨班拜舞人。", "誰遣附庸祈請使，要教索虜識忠臣。"]'),
('c25c73b9-0016-4799-bd5c-c5a28a972023','使北  其七','文天祥','宋','宋诗','song-poetry','','[]','客子漂摇萬里程，北征情味似南征。',32,'全唐诗/poet.song.239000.json','["客子漂摇萬里程，北征情味似南征。", "小臣事主寧無罪，只作幽州謫吏行。"]'),
('0f7b36a1-4698-492a-ab58-30a4d056fa3a','使北  其八','文天祥','宋','宋诗','song-poetry','','[]','使旃盡道有回期，獨陷羈臣去牧羝。',32,'全唐诗/poet.song.239000.json','["使旃盡道有回期，獨陷羈臣去牧羝。", "中爾含沙渾小事，白雲飛處楚天低。"]'),
('62818e8e-c754-4a89-8140-5c423cb5f3c1','杜架閣  其一','文天祥','宋','宋诗','song-poetry','','[]','仗節辭王室，悠悠萬里轅。',48,'全唐诗/poet.song.239000.json','["仗節辭王室，悠悠萬里轅。", "諸君皆雨別，一士獨星言。", "啼鳥亂人意，落花銷客魂。", "東坡愛巢谷，頗恨晚登門。"]'),
('71d90d08-e07c-4bda-90e7-ac5b277d09f2','杜架閣  其二','文天祥','宋','宋诗','song-poetry','','[]','昔趨魏公子，今事霍將軍。',48,'全唐诗/poet.song.239000.json','["昔趨魏公子，今事霍將軍。", "世態炎凉甚，交情貴賤分。", "黄沙揚暮靄，黑海起朝氛。", "獨與君携手，行吟看白雲。"]'),
('3d27d90d-b54e-48f6-84e1-bc0e5fe27d51','聞鷄','文天祥','宋','宋诗','song-poetry','','[]','軍中二十日，此夕始聞鷄。',48,'全唐诗/poet.song.239000.json','["軍中二十日，此夕始聞鷄。", "塵暗天街靜，沙長海路迷。", "銅駝隨雨落，鐵騎向風嘶。", "曉起呼詹尹，何時脫蒺藜。"]'),
('e7c5fe28-bd73-42a8-833e-012c382a3358','命裏','文天祥','宋','宋诗','song-poetry','','[]','熊羆十萬建行臺，單騎誰教免胄來。',32,'全唐诗/poet.song.239000.json','["熊羆十萬建行臺，單騎誰教免胄來。", "一日捉將沙漠去，遭逢碧眼老回回。"]'),
('83dad0be-8e8f-48cb-b537-589970e08b56','留遠亭  其一','文天祥','宋','宋诗','song-poetry','','[]','甘心賣國罪滔天，酒後猖狂詐作顛。',32,'全唐诗/poet.song.239000.json','["甘心賣國罪滔天，酒後猖狂詐作顛。", "把酒逢迎酋虜笑，從頭駡坐數時賢。"]'),
('9464ffef-cd6c-403b-87ac-80c738dc30fc','留遠亭  其二','文天祥','宋','宋诗','song-poetry','','[]','落得稱呼浪子劉，樽前百媚佞旃裘。',32,'全唐诗/poet.song.239000.json','["落得稱呼浪子劉，樽前百媚佞旃裘。", "當年鮑老不如此，留遠亭前犬也羞。"]'),
('e3d7ba12-0591-4ec7-9586-6550d4f64613','平江府','文天祥','宋','宋诗','song-poetry','','[]','樓臺俯舟楫，城郭滿干戈。',48,'全唐诗/poet.song.239000.json','["樓臺俯舟楫，城郭滿干戈。", "故吏歸心少，遺民出涕多。", "鳩居無鵲在，魚網有鴻過。", "使遂睢陽志，安危今若何。"]'),
('b50d5d2f-f4c4-4c98-a084-67a90b3eb5da','無錫','文天祥','宋','宋诗','song-poetry','','[]','金山冉冉波濤雨，錫水泯泯草木春。',64,'全唐诗/poet.song.239000.json','["金山冉冉波濤雨，錫水泯泯草木春。", "二十年前曾去路，三千里外作行人。", "英雄未死心爲碎，父老相逢鼻欲辛。", "夜讀程嬰存趙事，一回惆悵一沾巾。"]'),
('592d4aa1-7bb9-433a-a9d5-89239a307d81','吊五木','文天祥','宋','宋诗','song-poetry','','[]','首赴勤王役，成功事則天。',48,'全唐诗/poet.song.239000.json','["首赴勤王役，成功事則天。", "富平名委地，好水淚成川。", "我作招魂想，誰爲掩骼緣。", "中興須再舉，寄語慰重泉。"]'),
('b5d71d51-19e3-4616-ad3a-b2a6980a7d08','哭尹玉','文天祥','宋','宋诗','song-poetry','','[]','團練濠州廟贛川，官其二子賜良田。',32,'全唐诗/poet.song.239000.json','["團練濠州廟贛川，官其二子賜良田。", "西臺捕逐多亡將，還有焚黄到墓前。"]'),
('c0d3d0ff-b078-4321-a6b3-997b01bf2931','常州','文天祥','宋','宋诗','song-poetry','','[]','山河千里在，煙火一家無。',48,'全唐诗/poet.song.239000.json','["山河千里在，煙火一家無。", "壯甚睢陽守，冤哉馬邑屠。", "蒼天如可問，赤子果何辜。", "唇齒提封舊，撫膺三嘆吁。"]'),
('e9f14b62-e7cd-483b-81f7-ac9104ff6b44','鎮江','文天祥','宋','宋诗','song-poetry','','[]','鐵甕山河舊，金甌宇宙非。',48,'全唐诗/poet.song.239000.json','["鐵甕山河舊，金甌宇宙非。", "昔隨西日上，今見北軍飛。", "豪傑非無志，功名自有機。", "中流懷士稚，風雨濕雙扉。"]'),
('788a7479-7b08-4804-8453-87cd13ba556f','渡瓜洲  其一','文天祥','宋','宋诗','song-poetry','','[]','跨江半壁閲千帆，虎在深山龍在潭。',32,'全唐诗/poet.song.239000.json','["跨江半壁閲千帆，虎在深山龍在潭。", "當日本爲南制北，如今翻被北持南。"]'),
('3dce35d1-e5b2-4158-9175-871cc9b57ba6','渡瓜洲  其二','文天祥','宋','宋诗','song-poetry','','[]','眼前風景異山河，無柰諸君笑語何。',32,'全唐诗/poet.song.239000.json','["眼前風景異山河，無柰諸君笑語何。", "坐上有人正愁絕，胡兒便道是僂儸。"]'),
('12ce5943-f2ed-4bd8-a7bd-cb589ecb6ab2','吊戰場','文天祥','宋','宋诗','song-poetry','','[]','連年淮水上，死者亂如麻。',48,'全唐诗/poet.song.239000.json','["連年淮水上，死者亂如麻。", "魂魄丘中土，英雄糞上花。", "士知忠厥主，人亦念其家。", "夷德無厭甚，皇天定福華。"]'),
('58d48a3d-b0ee-456b-94d1-df414c464acb','回京口','文天祥','宋','宋诗','song-poetry','','[]','早作田文去，終無蘇武留。',48,'全唐诗/poet.song.239000.json','["早作田文去，終無蘇武留。", "偷生寧伏劍，忍死欲焚舟。", "逸驥思超乘，飛鷹志脫鞲。", "登樓望江上，日日數行艘。"]'),
('33817d52-8ac0-4a42-b0f4-d53978b4e9a6','思小村','文天祥','宋','宋诗','song-poetry','','[]','春雲慘慘兮春水漫漫，思我故人兮行路難。',215,'全唐诗/poet.song.239000.json','["春雲慘慘兮春水漫漫，思我故人兮行路難。", "君轅以南兮我轅以北，去日以遠兮憂不可以終極。", "蹇予馬兮江臯，式燕兮以遊遨。", "念我平生兮思君鬰陶。", "在師中兮豈造次之可離，忠言不聞兮思君忸怩。", "毫釐之差兮天壤易位，駟不及舌兮臍不可噬。", "思我故人兮懷我親，懷我親兮思故人。", "懷哉懷哉，不可忍兮不如速死。", "慨百年之未半兮，胡中道而遄止。", "魯連子兮義不帝秦，負玄德兮羽不名爲人。", "委骨草莽兮時廼天命，自古孰無死兮首丘爲正。", "我行我行兮夢寐所思，故人望我兮胡不歸，胡不歸。"]'),
('ade517d3-fed5-4285-a47c-8e7300051fa7','沈頤家','文天祥','宋','宋诗','song-poetry','','[]','孤舟霜月逈，曉起入柴門。',48,'全唐诗/poet.song.239000.json','["孤舟霜月逈，曉起入柴門。", "斷岸行簪影，荒畦落履痕。", "江山渾在眼，宇宙付無言。", "昨夜三更夢，春風滿故園。"]'),
('e26d1537-0fa3-4dc1-8136-fd982c266184','脫京口 定計難','文天祥','宋','宋诗','song-poetry','','[]','南北人人苦泣岐，壯心萬折誓東歸。',32,'全唐诗/poet.song.239000.json','["南北人人苦泣岐，壯心萬折誓東歸。", "若非斫案判生死，夜半何人敢突圍。"]'),
('1bfcab8a-8da3-410f-addf-b67463644750','脫京口 謀人難','文天祥','宋','宋诗','song-poetry','','[]','一片歸心似亂雲，逢人時漏話三分。',32,'全唐诗/poet.song.239000.json','["一片歸心似亂雲，逢人時漏話三分。", "當時若也私謀泄，春夢悠悠郭璞墳。"]'),
('31d2d550-b820-4416-8573-294f7cc35a32','脫京口 踏路難','文天祥','宋','宋诗','song-poetry','','[]','煙火連甍鐵甕關，要尋間道走江干。',32,'全唐诗/poet.song.239000.json','["煙火連甍鐵甕關，要尋間道走江干。", "何人肯爲將軍地，北府老兵思漢官。"]'),
('0233b396-27d7-4605-b429-43b936940d53','脫京口 得船難','文天祥','宋','宋诗','song-poetry','','[]','經營十日苦無舟，慘慘椎心淚血流。',32,'全唐诗/poet.song.239000.json','["經營十日苦無舟，慘慘椎心淚血流。", "漁父疑爲神物遣，相逢揚子大江頭。"]'),
('d454cb83-c0f9-4ba3-89a2-79b9b94cb4c6','脫京口 紿北難','文天祥','宋','宋诗','song-poetry','','[]','百計經營夜負舟，倉皇誰趣渡瓜洲。',32,'全唐诗/poet.song.239000.json','["百計經營夜負舟，倉皇誰趣渡瓜洲。", "若非紿虜成宵遁，哭死界河天地愁。"]'),
('d7a0393a-7ab1-483f-aa0a-7ba314132955','脫京口 定變難','文天祥','宋','宋诗','song-poetry','','[]','老兵中變意差池，倉卒呼來朽索危。',32,'全唐诗/poet.song.239000.json','["老兵中變意差池，倉卒呼來朽索危。", "若使阿婆真一吼，目生隨後悔何追。"]'),
('3fa7d20b-3ccc-4669-b2c5-081b73950a36','脫京口 出門難','文天祥','宋','宋诗','song-poetry','','[]','羅剎盈庭夜色寒，人家燈火半闌珊。',32,'全唐诗/poet.song.239000.json','["羅剎盈庭夜色寒，人家燈火半闌珊。", "夢回跳出鐵門限，世上一重人鬼關。"]'),
('9845486f-4566-4955-bddc-ff81e7252a23','脫京口 出巷難','文天祥','宋','宋诗','song-poetry','','[]','不時徇鋪路縱橫，小隊戎衣自出城。',32,'全唐诗/poet.song.239000.json','["不時徇鋪路縱橫，小隊戎衣自出城。", "天假漢兒燈一炬，旁人只道是官行。"]'),
('7ff8772c-6e30-4c43-8e2b-f17ace264a5a','脫京口 出隘難','文天祥','宋','宋诗','song-poetry','','[]','袖携匕首學啣枚，橫渡城關馬欲猜。',32,'全唐诗/poet.song.239000.json','["袖携匕首學啣枚，橫渡城關馬欲猜。", "夜靜天昏人影散，北軍鼾睡正如雷。"]'),
('4fb82dce-3e53-4658-8e68-f1e1e71d89ae','脫京口 候船難','文天祥','宋','宋诗','song-poetry','','[]','待船三五立江干，眼欲穿時夜漸闌。',32,'全唐诗/poet.song.239000.json','["待船三五立江干，眼欲穿時夜漸闌。", "若使長年期不至，江流便作汨羅看。"]'),
