('f6bbadea-225f-472b-a57f-c623784f7964','至揚州  其一五','文天祥','宋','宋诗','song-poetry','','[]','晝闌萬騎忽東行，鼠伏荒村命羽輕。',32,'全唐诗/poet.song.239000.json','["晝闌萬騎忽東行，鼠伏荒村命羽輕。", "隔壁但聞風雨過，人人顧影賀更生。"]'),
('00f74182-f3a4-47e1-878d-e66e7c280f02','至揚州  其一六','文天祥','宋','宋诗','song-poetry','','[]','青衣山下汲荒泉，道遇腥風走不前。',32,'全唐诗/poet.song.239000.json','["青衣山下汲荒泉，道遇腥風走不前。", "向晚歸來號且哭，胡兒只爲解腰纏。"]'),
('29bef81f-ada0-43af-9ec2-39f7bd2c20c7','至揚州  其一七','文天祥','宋','宋诗','song-poetry','','[]','眼穿只候賣柴回，今日堡城門不開。',32,'全唐诗/poet.song.239000.json','["眼穿只候賣柴回，今日堡城門不開。", "糴米已無消息至，黄昏惆悵下山來。"]'),
('d073e472-d8aa-4996-8f0f-478e9ae208ce','至揚州  其一八','文天祥','宋','宋诗','song-poetry','','[]','既投古廟覓藜羹，三五樵夫不識名。',32,'全唐诗/poet.song.239000.json','["既投古廟覓藜羹，三五樵夫不識名。", "僮子似知予夢惡，生柴燒火到天明。"]'),
('af6812de-2079-44f9-bf8b-c95523fd801f','至揚州  其一九','文天祥','宋','宋诗','song-poetry','','[]','苦作江頭乞食翁，一層破廟五更風。',32,'全唐诗/poet.song.239000.json','["苦作江頭乞食翁，一層破廟五更風。", "眼前境界身何許，始悟人間萬法空。"]'),
('afb825fc-0851-4ff4-be7a-44f2883a6625','至揚州  其二○','文天祥','宋','宋诗','song-poetry','','[]','樵夫偏念客途長，肯向城中爲裹糧。',32,'全唐诗/poet.song.239000.json','["樵夫偏念客途長，肯向城中爲裹糧。", "曉指高沙移處泊，司徒廟下賈家莊。"]'),
('43f4d68f-9009-4127-934a-3cbce38309bd','賈家莊','文天祥','宋','宋诗','song-poetry','','[]','行邊無鳥雀，卧處有腥臊。',48,'全唐诗/poet.song.239000.json','["行邊無鳥雀，卧處有腥臊。", "露打鬚眉硬，風搜顴頰高。", "流離外顛沛，饑渴內煎熬。", "多少偷生者，孤臣嘆所遭。"]'),
('9a1dd979-4209-4a3f-bd9f-52e99c8f553c','揚州地分官  其一','文天祥','宋','宋诗','song-poetry','','[]','五騎馳來號徼巡，咆哮按劍一何嗔。',32,'全唐诗/poet.song.239000.json','["五騎馳來號徼巡，咆哮按劍一何嗔。", "金錢買命方無語，何必豺狼駡北人。"]'),
('4740cd16-aabf-4a26-b43b-645b129b2ecb','揚州地分官  其二','文天祥','宋','宋诗','song-poetry','','[]','便當縞素駕戎車，畏賊何當畏虎如。',32,'全唐诗/poet.song.239000.json','["便當縞素駕戎車，畏賊何當畏虎如。", "看取摘星樓咫尺，可憐城下哭包胥。"]'),
('6abbc392-09e2-415e-8a69-ccd6a29be70a','思則堂先生','文天祥','宋','宋诗','song-poetry','','[]','白鬚老子宿招提，香積厨邊供晚炊。',32,'全唐诗/poet.song.239000.json','["白鬚老子宿招提，香積厨邊供晚炊。", "借問魚羹何處少，北風安得似南枝。"]'),
('6a14a0e2-a6a8-4794-8284-45250243e639','高沙道中','文天祥','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','三月初五日，索馬平山邊。',288,'全唐诗/poet.song.239000.json','["三月初五日，索馬平山邊。", "疾馳趨高沙，如走阪上圓。", "夜行二百里，望望無人煙。", "迷途呼不應，如在盤中旋。", "昏霧腥且濕，怒飆狂欲顛。", "流澌在鬚髮，塵沫滿櫜鞬。", "紅日高十丈，方辨山與川。", "胡行疾如鬼，忽在林之巔。", "誰家苦竹園，其葉青戔戔。", "倉皇伏幽篠，生死信天緣。", "鐵騎俄四合，鳥落無虛弦。", "遶林勢奔軼，動地聲喧闐。", "霜蹄破叢翳，出入相貫穿。", "既無遁形術，又非縮地僊。", "猛虎驅群羊，兔魚落蹄筌。", "一吏射中目，頸血僅可濺。", "一隸縛上馬，無路脫糾纏。", "一廝躪其足，吞聲以自全。", "一賓與一從，買命得金錢。", "一伻與一校，幸不逢戈鋋。", "嗟予何薄命，寄身空且懸。", "蕭蕭數竹側，往來度飛韉。", "遊鋒幾及膚，怒興空握拳。", "跬步偶不見，殘息忽復延。"]'),
('5d7a5800-b7a3-42bb-8cdc-547525a9552c','至高沙','文天祥','宋','宋诗','song-poetry','','[]','江南自好築金臺，何事風花墮向淮。',32,'全唐诗/poet.song.239000.json','["江南自好築金臺，何事風花墮向淮。", "若使兩遭豺虎手，而今玉也有誰埋。"]'),
('1346e04f-179a-4a13-92a2-691bb82ca32b','發高沙  其一','文天祥','宋','宋诗','song-poetry','','[]','曉發高沙卧一航，平沙漠漠水茫茫。',32,'全唐诗/poet.song.239000.json','["曉發高沙卧一航，平沙漠漠水茫茫。", "舟人爲指荒烟岸，南北今年幾戰場。"]'),
('5468f334-ba88-4a84-a139-3b7d60c17751','發高沙  其二','文天祥','宋','宋诗','song-poetry','','[]','城子河邊委亂尸，河陰血肉更稀微。',32,'全唐诗/poet.song.239000.json','["城子河邊委亂尸，河陰血肉更稀微。", "太行南北燕山外，多少遊魂逐馬蹄。"]'),
('d43da3a2-ed54-494c-a14e-0fed8245f9c8','發高沙  其三','文天祥','宋','宋诗','song-poetry','','[]','一日經行白骨堆，中流失柁爲心摧。',32,'全唐诗/poet.song.239000.json','["一日經行白骨堆，中流失柁爲心摧。", "海陵棹子長狼顧，水有船來步馬來。"]'),
('40d337f2-15be-4485-9749-a07b35162f52','發高沙  其四','文天祥','宋','宋诗','song-poetry','','[]','小泊稽莊月正弦，莊官驚問是何船。',32,'全唐诗/poet.song.239000.json','["小泊稽莊月正弦，莊官驚問是何船。", "今朝哨馬灣頭出，正在青山大路邊。"]'),
('1c4e91b8-cab8-4e2d-83ce-67df8003662f','稽莊即事','文天祥','宋','宋诗','song-poetry','','[]','乃心王室故，日夜奔南征。',48,'全唐诗/poet.song.239000.json','["乃心王室故，日夜奔南征。", "蹈險寧追悔，懷忠莫見明。", "雁聲連水遠，山色與天平。", "枉作窮途哭，男兒付死生。"]'),
('f4c5b2ea-6cc3-4b02-8914-8f03579284f5','泰州','文天祥','宋','宋诗','song-poetry','','[]','羈臣家萬里，天目鑒孤忠。',48,'全唐诗/poet.song.239000.json','["羈臣家萬里，天目鑒孤忠。", "心在坤維外，身游坎窞中。", "長淮行不斷，苦海望無窮。", "晚鵲傳佳好，通州路已通。"]'),
('8296421d-7c64-4eee-bd77-58c704842f03','卜神','文天祥','宋','宋诗','song-poetry','','[]','通州三百里，茅葦也還無。',48,'全唐诗/poet.song.239000.json','["通州三百里，茅葦也還無。", "胡騎虎出沒，山鼯鬼嘯呼。", "王陽懷畏道，阮籍淚窮途。", "人物中興骨，神明爲國扶。"]'),
('38d7834d-584d-4ce4-b137-274d6fc319ad','旅懷  其一','文天祥','宋','宋诗','song-poetry','','[]','北去通州號畏途，固應孝子爲回車。',32,'全唐诗/poet.song.239000.json','["北去通州號畏途，固應孝子爲回車。", "海陵若也容羈客，賸買菰蒲且寄居。"]'),
('797d6133-f990-4dd0-8ac8-e6cd75e7fcd5','旅懷  其二','文天祥','宋','宋诗','song-poetry','','[]','天地雖寬靡所容，長淮誰是主人翁。',32,'全唐诗/poet.song.239000.json','["天地雖寬靡所容，長淮誰是主人翁。", "江南父老還相念，只欠一帆東海風。"]'),
('a6743a93-7b87-406c-a0ab-73958920f234','旅懷  其三','文天祥','宋','宋诗','song-poetry','','[]','昨夜分明夢到家，飄颻依舊客天涯。',32,'全唐诗/poet.song.239000.json','["昨夜分明夢到家，飄颻依舊客天涯。", "故園門掩東風老，無限杜鵑啼落花。"]'),
('d89eb290-d26a-4407-9a97-5d6a3cb6deb0','懷則堂實堂','文天祥','宋','宋诗','song-poetry','','[]','白頭北使駕雙韉，沙闊天長淚曉煙。',32,'全唐诗/poet.song.239000.json','["白頭北使駕雙韉，沙闊天長淚曉煙。", "中夜想應發深省，故人南北地行僊。"]'),
('fcb818f8-ef3d-434d-a9d3-1f350fbeeaca','貴卿','文天祥','宋','宋诗','song-poetry','','[]','天高併地逈，與子獨牢愁。',48,'全唐诗/poet.song.239000.json','["天高併地逈，與子獨牢愁。", "初作燕齊客，今爲淮海游。", "半生誰俯仰，一死共沉浮。", "我視君年長，相看比惠州。"]'),
('ad18324b-1d0b-415b-aca2-09198559b382','憶太夫人','文天祥','宋','宋诗','song-poetry','','[]','三生命孤苦，萬里路酸辛。',48,'全唐诗/poet.song.239000.json','["三生命孤苦，萬里路酸辛。", "屢險不一險，無身復有身。", "不忘聖天子，幾負太夫人。", "定省今何處，新來夢寐頻。"]'),
('c2339a47-2a8a-4a2e-9952-1f1b6852e798','即事','文天祥','宋','宋诗','song-poetry','','[]','痛哭辭京闕，微行訪海門。',48,'全唐诗/poet.song.239000.json','["痛哭辭京闕，微行訪海門。", "久無鷄可聽，新有虱堪捫。", "白髮應多長，蒼頭少有存。", "但令身未死，隨力報乾坤。"]'),
('96a8679e-544f-4558-b147-7c2d46545248','紀閑','文天祥','宋','宋诗','song-poetry','','[]','九十春光好，周流人鬼關。',48,'全唐诗/poet.song.239000.json','["九十春光好，周流人鬼關。", "人情輕似土，世路險於山。", "俯仰經行處，死生談笑間。", "近時最難得，旬日海陵閑。"]'),
('1160202b-541e-4704-8509-bf4e8c93bfaf','聲苦','文天祥','宋','宋诗','song-poetry','','[]','萬死奔波落一生，飄零淮海命何輕。',32,'全唐诗/poet.song.239000.json','["萬死奔波落一生，飄零淮海命何輕。", "近來學得趙清獻，叫苦時時數十聲。"]'),
('12e2ae71-ba07-4674-a30e-dce744da31cc','即事','文天祥','宋','宋诗','song-poetry','','[]','船隻時閒鎖，城孤日閉關。',48,'全唐诗/poet.song.239000.json','["船隻時閒鎖，城孤日閉關。", "驚心常有馬，極目柰無山。", "出路相傳險，行囊愈覺慳。", "歸心風絮亂，無柰一身閑。"]'),
('7e539aa1-91e8-40c9-8abe-9d85bbd761a2','發海陵','文天祥','宋','宋诗','song-poetry','','[]','自海陵來向海安，分明如渡鬼門關。',32,'全唐诗/poet.song.239000.json','["自海陵來向海安，分明如渡鬼門關。", "若將九折回車看，倦鳥何年可得還。"]'),
('336f51f4-05a3-4271-a25d-98493a55c4f7','聞馬','文天祥','宋','宋诗','song-poetry','','[]','過海安來柰若何，舟人去後馬臨河。',32,'全唐诗/poet.song.239000.json','["過海安來柰若何，舟人去後馬臨河。", "若非神物扶忠直，世上未應僥倖多。"]'),
('1fcf9011-ce9f-4747-9ce9-c802807b6953','如臯','文天祥','宋','宋诗','song-poetry','','[]','雄狐假虎之林臯，河水腥風接海濤。',32,'全唐诗/poet.song.239000.json','["雄狐假虎之林臯，河水腥風接海濤。", "行客不知身世險，一窗春夢送輕舠。"]'),
('5d99907a-70e5-4958-9fd0-95c166bdeee2','聞諜','文天祥','宋','宋诗','song-poetry','','[]','北來追騎滿江濱，那更元戎按劍嗔。',32,'全唐诗/poet.song.239000.json','["北來追騎滿江濱，那更元戎按劍嗔。", "不是神明扶正直，淮頭何處可安身。"]'),
('73062b84-f8a9-4ae8-aa34-f5fa2359cf74','哭金路分應  其一','文天祥','宋','宋诗','song-poetry','','[]','我爲吾君役，而從乃主行。',48,'全唐诗/poet.song.239000.json','["我爲吾君役，而從乃主行。", "險夷寧異趣，休戚與同情。", "遇賊能無死，尋醫劇不生。", "通州一丘土，相望淚如傾。"]'),
('d9ae27c7-832b-497a-ae07-6b4ec3ab9502','哭金路分應  其二','文天祥','宋','宋诗','song-poetry','','[]','明朝吾渡海，汝魄在它鄉。',48,'全唐诗/poet.song.239000.json','["明朝吾渡海，汝魄在它鄉。", "六七年華短，三千客路長。", "招魂情黯黯，歸骨事茫茫。", "有子應年長，平生不汝忘。"]'),
('ac6c5db8-dd98-4e1e-8865-829d9a07caa5','懷揚通州  其一','文天祥','宋','宋诗','song-poetry','','[]','江波無柰暮雲陰，一片朝宗只此心。',32,'全唐诗/poet.song.239000.json','["江波無柰暮雲陰，一片朝宗只此心。", "今日海頭覓船去，始知百煉是精金。"]'),
('7f061e24-f518-484f-8a36-fef80e7d5253','懷揚通州  其二','文天祥','宋','宋诗','song-poetry','','[]','喚渡江沙眼欲枯，羈臣中道落崎嶇。',32,'全唐诗/poet.song.239000.json','["喚渡江沙眼欲枯，羈臣中道落崎嶇。", "乘船不管千金購，漁父真成大丈夫。"]'),
('8bea0551-96b4-4728-8aa8-d8d7a9e82495','懷揚通州  其三','文天祥','宋','宋诗','song-poetry','','[]','範叔西來變姓名，綈袍曾感故人情。',32,'全唐诗/poet.song.239000.json','["範叔西來變姓名，綈袍曾感故人情。", "而今未識春風面，傾蓋江湖話一生。"]'),
('7734fe6c-58a9-4536-809b-aed5aff274fe','懷揚通州  其四','文天祥','宋','宋诗','song-poetry','','[]','仲連義不帝西秦，拔宅逃來住海濱。',32,'全唐诗/poet.song.239000.json','["仲連義不帝西秦，拔宅逃來住海濱。", "我亦東尋煙霧去，扶桑影裏看金輪。"]'),
('16e7ee00-3a42-453e-8f7a-cc1e24ba6367','海船','文天祥','宋','宋诗','song-poetry','','[]','海上多時斷去舟，公來容易渡南州。',32,'全唐诗/poet.song.239000.json','["海上多時斷去舟，公來容易渡南州。", "子胥江上逢漁父，莫是神明遣汝否。"]'),
('afbf0933-d768-45ab-819c-432c40184dd9','發通州  其一','文天祥','宋','宋诗','song-poetry','','[]','孤舟漸漸脫長淮，星斗當空月照懷。',32,'全唐诗/poet.song.239000.json','["孤舟漸漸脫長淮，星斗當空月照懷。", "今夜分明棲海角，未應便道是天涯。"]'),
('a280a3aa-3743-41fa-80c2-bd24734b4c0d','發通州  其二','文天祥','宋','宋诗','song-poetry','','[]','白骨叢中過一春，東將入海避風塵。',32,'全唐诗/poet.song.239000.json','["白骨叢中過一春，東將入海避風塵。", "姓名變盡形容改，猶有天涯相識人。"]'),
('8d652404-e1d3-40e9-ac74-781988737551','發通州  其三','文天祥','宋','宋诗','song-poetry','','[]','淮水淮山阻且長，孤臣性命寄何鄉。',32,'全唐诗/poet.song.239000.json','["淮水淮山阻且長，孤臣性命寄何鄉。", "只從海上尋歸路，便是當年不死方。"]'),
('ef5cf115-7482-4489-86ce-fed57bf0b030','石港','文天祥','宋','宋诗','song-poetry','','[]','王陽真畏道，季路漸知津。',48,'全唐诗/poet.song.239000.json','["王陽真畏道，季路漸知津。", "山鳥喚醒客，海風吹黑人。", "乾坤萬里夢，烟雨一年春。", "起看扶桑曉，紅黄六六鱗。"]'),
('c33edb61-40eb-457c-a8dd-a8ba5562b572','賣魚灣','文天祥','宋','宋诗','song-poetry','','[]','風起千灣浪，潮生萬頃沙。',48,'全唐诗/poet.song.239000.json','["風起千灣浪，潮生萬頃沙。", "春紅堆蟹子，晚白結鹽花。", "故國何時訊，扁舟到處家。", "狼山青兩點，極目是天涯。"]'),
('deed0c3e-f144-4165-bdc1-fe858abd6cdb','即事','文天祥','宋','宋诗','song-poetry','','[]','飄蓬一葉落天涯，潮濺青紗日未斜。',32,'全唐诗/poet.song.239000.json','["飄蓬一葉落天涯，潮濺青紗日未斜。", "好事官人無勾當，呼童上岸買青蝦。"]'),
('b1871c72-c1e0-4f7f-96dd-35bc8d5fb8c4','北海口','文天祥','宋','宋诗','song-poetry','','[]','滄海人間別一天，只容漁父釣蒼煙。',32,'全唐诗/poet.song.239000.json','["滄海人間別一天，只容漁父釣蒼煙。", "而今蜃起樓臺處，亦有北來蕃漢船。"]'),
('12baa19c-c060-4414-8181-1d0bb6aa6dfd','出海  其一','文天祥','宋','宋诗','song-poetry','','[]','一團蕩漾水晶盤，四畔青天作護闌。',32,'全唐诗/poet.song.239000.json','["一團蕩漾水晶盤，四畔青天作護闌。", "著我扁舟了無礙，分明便作混淪看。"]'),
('b3642e6d-7175-4824-a948-4004713ee66e','出海  其二','文天祥','宋','宋诗','song-poetry','','[]','水天一色玉空明，便似乘槎上太清。',32,'全唐诗/poet.song.239000.json','["水天一色玉空明，便似乘槎上太清。", "我愛東坡南海句，茲游奇絕冠平生。"]'),
('222ad484-db21-4eb1-9a89-fd9f33f7cec6','漁舟','文天祥','宋','宋诗','song-poetry','','[]','一陣飛帆破碧烟，兒郎驚餌理弓弦。',64,'全唐诗/poet.song.239000.json','["一陣飛帆破碧烟，兒郎驚餌理弓弦。", "舟中自信婁師德，海上誰知魯仲連。", "初謂悠揚真賊艦，後聞欵乃是漁船。", "人生漂泊多磨折，何日山林清晝眠。"]'),
('d849b80e-8f6d-452c-b532-97c75a150286','揚子江','文天祥','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u52b1\u5fd7"]','幾日隨風北海游，回從揚子大江頭。',32,'全唐诗/poet.song.239000.json','["幾日隨風北海游，回從揚子大江頭。", "臣心一片磁針石，不指南方不肯休。"]'),
('b3a25bb2-d862-42aa-acf5-7cdcaddf9237','使風','文天祥','宋','宋诗','song-poetry','','[]','渺渺茫茫遠愈微，乘風日夜趁東歸。',32,'全唐诗/poet.song.239000.json','["渺渺茫茫遠愈微，乘風日夜趁東歸。", "半醒半困模糊處，一似醉中騎馬飛。"]'),
('c2cd046c-1992-4eee-a58d-3c6b5e96f938','蘇州洋','文天祥','宋','宋诗','song-poetry','','[]','一葉漂摇揚子江，白雲盡處是蘇洋。',32,'全唐诗/poet.song.239000.json','["一葉漂摇揚子江，白雲盡處是蘇洋。", "便如伍子當年苦，只少行頭寶劍裝。"]'),
('3fb5161d-e504-4a1e-8c3c-0f846cab379c','過揚子江心','文天祥','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','渺渺乘風出海門，一行淡水带潮渾。',32,'全唐诗/poet.song.239000.json','["渺渺乘風出海門，一行淡水带潮渾。", "長江盡處還如此，何日岷山看發源。"]'),
('8c636978-ef69-4650-82e1-1fcb854050c7','入浙東','文天祥','宋','宋诗','song-poetry','','[]','厄運一百日，危機九十遭。',48,'全唐诗/poet.song.239000.json','["厄運一百日，危機九十遭。", "孤蹤落虎口，薄命付鴻毛。", "漠漠長淮路，茫茫巨海濤。", "驚魂猶未定，消息問金鰲。"]'),
('2f01e863-1630-4d09-8432-788d2bc7fe57','夜潮','文天祥','宋','宋诗','song-poetry','','[]','雨惡風獰夜色濃，潮頭如屋打孤蓬。',32,'全唐诗/poet.song.239000.json','["雨惡風獰夜色濃，潮頭如屋打孤蓬。", "漂零行路丹心苦，夢裏一聲何處鴻。"]'),
('4bbe49ea-3298-4a50-82e6-7eee19d79dd2','亂礁洋','文天祥','宋','宋诗','song-poetry','','[]','海山僊子國，邂逅寄孤蓬。',48,'全唐诗/poet.song.239000.json','["海山僊子國，邂逅寄孤蓬。", "萬象畫圖裏，千崖玉界中。", "風摇春浪軟，礁激暮潮雄。", "雲氣東南密，龍騰上碧空。"]'),
('6e21eaf0-a72c-4a1b-92e7-23e84cfe3795','夜走','文天祥','宋','宋诗','song-poetry','','[]','鯨波萬里送歸舟，倏忽驚心欲白頭。',64,'全唐诗/poet.song.239000.json','["鯨波萬里送歸舟，倏忽驚心欲白頭。", "何處赭衣操劍戟，同時黄帽理兜鍪。", "人間風雨真成夢，夜半江山總是愁。", "雁蕩雙峰片雲隔，明朝躡屩作清游。"]'),
('4af1987a-188a-4017-9a15-1babd5535d09','綠漪堂','文天祥','宋','宋诗','song-poetry','','[]','義方堂上看，窗戶翠玲瓏。',48,'全唐诗/poet.song.239000.json','["義方堂上看，窗戶翠玲瓏。", "硯裏雲壇月，席間淇水風。", "清聲隨地到，直節與天通。", "庭玉森如笋，干霄雨露功。"]'),
('fb5fbcb2-8fca-4483-88d5-a474dca0a87c','過黄巖','文天祥','宋','宋诗','song-poetry','','[]','魏雎變張祿，越蠡改陶朱。',24,'全唐诗/poet.song.239000.json','["魏雎變張祿，越蠡改陶朱。", "誰料文山氏，姓劉名是洙。"]'),
('9aa65044-6d80-462b-a880-cd78b9be0c38','至溫州','文天祥','宋','宋诗','song-poetry','','[]','萬里風霜鬢已絲，飄零回首壯心悲。',64,'全唐诗/poet.song.239000.json','["萬里風霜鬢已絲，飄零回首壯心悲。", "羅浮山下雪來未，揚子江心月照誰。", "祇謂虎頭非貴相，不圖羝乳有歸期。", "乘潮一到中川寺，暗讀中興第二碑。"]'),
('0c260fd7-2543-4395-8937-949f34278c9c','長溪道中和張自山韻  其一','文天祥','宋','宋诗','song-poetry','','[]','潮風連地吼，江雨带天流。',48,'全唐诗/poet.song.239000.json','["潮風連地吼，江雨带天流。", "宮殿扃春仗，衣冠鎖月遊。", "傷心今北府，遺恨古東洲。", "王氣如川至，龍興海上州。"]'),
('e1732ae2-3399-4e3b-912c-e6c3925588c5','長溪道中和張自山韻  其二','文天祥','宋','宋诗','song-poetry','','[]','夜靜吳歌咽，春深蜀血流。',48,'全唐诗/poet.song.239000.json','["夜靜吳歌咽，春深蜀血流。", "向來蘇武節，今日子長游。", "海角雲爲岸，江心石作洲。", "丈夫竟何事，底用泣神州。"]'),
('b2e3503f-dfc9-4f2a-8f84-f9387789a5c8','和自山','文天祥','宋','宋诗','song-poetry','','[]','春晚傷爲客，月明思見君。',48,'全唐诗/poet.song.239000.json','["春晚傷爲客，月明思見君。", "我方慕蘇武，誰復從田文。", "龍背夾紅日，雁聲連白雲。", "琶琵漢宮曲，馬上不堪聞。"]'),
('d194002e-fe09-4009-a458-c9981a2395a6','林附祖','文天祥','宋','宋诗','song-poetry','','[]','畫影圖形正捕風，書生薄命入罝中。',32,'全唐诗/poet.song.239000.json','["畫影圖形正捕風，書生薄命入罝中。", "胡兒一似冬烘眼，錯認顔標作魯公。"]'),
('510c2120-929a-42d7-95e7-24373549be42','呈小村','文天祥','宋','宋诗','song-poetry','','[]','萬里飄零命羽輕，歸來喜有故人迎。',64,'全唐诗/poet.song.239000.json','["萬里飄零命羽輕，歸來喜有故人迎。", "雷潜九地聲元在，月暗千山魄再明。", "疑是倉公回已死，恍如羊祜說前生。", "夜闌相對真成夢，清酒浩歌雙劍橫。"]'),
('1223540e-0223-4e2e-88d1-09dd2c38cd12','二月晦','文天祥','宋','宋诗','song-poetry','','[]','塞上明妃馬，江頭漁父船。',48,'全唐诗/poet.song.239000.json','["塞上明妃馬，江頭漁父船。", "新讎誰共雪，舊夢不堪圓。", "遺恨常千古，浮生又一年。", "何時暮春者，還我浴沂天。"]'),
('5662892d-4368-4cf3-9000-078bb951c668','有感呈景山校書諸丈','文天祥','宋','宋诗','song-poetry','','[]','北風吹春草，陽烏日已至。',120,'全唐诗/poet.song.239000.json','["北風吹春草，陽烏日已至。", "天時豈云爽，人事胡乃異。", "三月方皇皇，衣冠道如墜。", "棟撓榱桷折，木顛楨幹悴。", "大者懷端憂，燋頭求室燬。", "小者嗟行役，泥塗跋其尾。", "長平與新安，露胔如櫛比。", "賦分本爾殊，適與天時值。", "哲人處明夷，致命以遂志。", "但令守吾貞，死生浩無愧。"]'),
('7abd787c-de9e-43c1-b2a5-b1f596beabc2','即事','文天祥','宋','宋诗','song-poetry','','[]','去年傷北使，今日嘆南馳。',48,'全唐诗/poet.song.239000.json','["去年傷北使，今日嘆南馳。", "雲濕山如動，天低雨欲垂。", "征夫行未已，游子去何之。", "正好王師出，崆峒麥熟時。"]'),
('e29df9a8-73c1-4bbc-a6ba-70c5b403f255','所懷','文天祥','宋','宋诗','song-poetry','','[]','世途嗟孔棘，行役苦期頻。',48,'全唐诗/poet.song.239000.json','["世途嗟孔棘，行役苦期頻。", "良馬比君子，清風來故人。", "相看千里月，空負一年春。", "便有桃源路，吾當少避秦。"]'),
('8c2a23d5-c7a9-4b3d-9d49-5f1bd4c1c261','自嘆','文天祥','宋','宋诗','song-poetry','','[]','草宿披宵露，松餐立晚風。',48,'全唐诗/poet.song.239000.json','["草宿披宵露，松餐立晚風。", "亂離嗟我在，艱苦有誰同。", "祖逖關河志，程嬰社稷功。", "身謀百年事，宇宙浩無窮。"]'),
('1c1cae6d-f941-4be6-bb39-00c5c1b5c78b','題蘇武忠節圖  其一','文天祥','宋','宋诗','song-poetry','','[]','忽報忠圖紀歲華，東風吹淚落天涯。',64,'全唐诗/poet.song.239000.json','["忽報忠圖紀歲華，東風吹淚落天涯。", "蘇卿更有歸時國，老相兼無去後家。", "烈士喪元心不易，達人知命事何嗟。", "生平愛覽忠臣傳，不爲吾身亦陷車。"]'),
('6938212a-a503-4a6b-9a08-9b547eb545e2','題蘇武忠節圖  其二','文天祥','宋','宋诗','song-poetry','','[]','獨伴羝羊海上遊，相逢血淚向天流。',64,'全唐诗/poet.song.239000.json','["獨伴羝羊海上遊，相逢血淚向天流。", "忠貞已向生前定，老節須從死後休。", "不死未論生可喜，雖生何恨死堪憂。", "甘心賣國人何處，曾識蘇公義膽不。"]'),
('1f123469-d199-4509-b75c-5fe9986a61c6','題蘇武忠節圖  其三','文天祥','宋','宋诗','song-poetry','','[]','漠漠愁雲海戍迷，十年何事望京師。',64,'全唐诗/poet.song.239000.json','["漠漠愁雲海戍迷，十年何事望京師。", "李陵罪在偷生日，蘇武功成未死時。", "鐵石心存無鏡變，君臣義重與天期。", "縱饒夜久胡塵黑，百煉丹心涅不緇。"]'),
('fcdddb32-31d0-4fdb-b85f-b2796415e48f','過零丁洋','文天祥','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u52b1\u5fd7", "\u5fe7\u56fd\u5fe7\u6c11", "\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5185)", "\u521d\u4e2d\u53e4\u8bd7", "\u53e4\u8bd7\u4e09\u767e\u9996"]','辛苦遭逢起一經，干戈落落四周星。',64,'全唐诗/poet.song.239000.json','["辛苦遭逢起一經，干戈落落四周星。", "山河破碎風拋絮，身世飄摇雨打萍。", "皇恐灘頭說皇恐，零丁洋裏歎零丁。", "人生自古誰無死，留取丹心照汗青。"]'),
('15abe9e0-0306-46cf-a048-70fb6252156c','元夕','文天祥','宋','宋诗','song-poetry','','[]','南海觀元夕，茲遊古未曾。',48,'全唐诗/poet.song.239000.json','["南海觀元夕，茲遊古未曾。", "人間大競渡，水上小燒燈。", "世事爭强弱，人情尚廢興。", "孤臣腔血滿，死不愧廬陵。"]'),
('51175904-8fd6-4ee7-982c-7eb06dc5ce8c','懷趙清逸','文天祥','宋','宋诗','song-poetry','','[]','崖海真何地，驅來坐戰場。',48,'全唐诗/poet.song.239000.json','["崖海真何地，驅來坐戰場。", "家人半分合，國事决存亡。", "一死不足道，百憂何可當。", "故人髯似戟，起舞爲君傷。"]'),
('31530160-bd05-49f5-b0c8-5a56fd950388','二月六日海上大戰國事不濟孤臣天祥坐北舟中向南慟哭爲之詩曰','文天祥','宋','宋诗','song-poetry','','[]','長平一坑四十萬，秦人歡欣趙人怨。',352,'全唐诗/poet.song.239000.json','["長平一坑四十萬，秦人歡欣趙人怨。", "大風揚沙水不流，爲楚者樂爲漢愁。", "兵家勝負常不一，紛紛干戈何時畢。", "必有天吏將明威，不嗜殺人能一之。", "我生之初尚無疚，我生之後遭陽九。", "厥角稽首併二州，正氣掃地山河羞。", "身爲大臣義當死，城下師盟愧牛耳。", "間關歸國洗日光，白麻重宣不敢當。", "出師三年勞且苦，只尺長安不得覩。", "非無虓虎士如林，一日不戈爲人擒。", "樓船千艘下天角，兩雄相遭爭奮搏。", "古來何代無戰爭，未有鋒蝟交滄溟。", "遊兵日來復日往，相持一月爲鷸蚌。", "南人志欲扶崑崙，北人氣欲黄河吞。", "一朝天昏風雨惡，炮火雷飛箭星落。", "誰雌誰雄頃刻分，流屍漂血洋水渾。", "昨朝南船滿崖海，今朝只有北船在。", "昨夜兩邊桴鼓鳴，今朝船船鼾睡聲。", "北兵去家八千里，椎牛釃酒人人喜。", "惟有孤臣雨淚垂，冥冥不敢向人啼。", "六龍杳靄知何處，大海茫茫隔煙霧。", "我欲借劍斬佞臣，黄金橫带爲何人。"]'),
('004be197-aec5-4998-b6da-f348c92f98e4','又六噫','文天祥','宋','宋诗','song-poetry','','[]','飈風起兮海水飛，噫。',64,'全唐诗/poet.song.239000.json','["飈風起兮海水飛，噫。", "文武盡兮火德微，噫。", "鷹鸇相擊兮靡所施，噫。", "鴻鵠欲舉兮將安歸，噫。", "櫂歌中流兮任所之，噫。", "獨抱春秋兮莫我知，噫。"]'),
('d0f02b71-8d1a-4bfc-a099-653b11989791','言志','文天祥','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','九垠化爲魅，億醜俘爲虜。',303,'全唐诗/poet.song.239000.json','["九垠化爲魅，億醜俘爲虜。", "既不能變姓名卒於吳，又不能髠鉗奴於魯。", "遠引不如四皓翁，高蹈不如仲連父。", "冥鴻墮矰繳，長鯨陷網罟。", "鷃燕上下爭誰何，螻蟻等閑相爾汝。", "狼藉山河歲云杪，飄零海角春重暮。", "百年落落生涯盡，萬里遥遥行役苦。", "我生不辰逢百罹，求仁得仁尚何語。", "一死鴻毛或泰山，之輕之重安所處。", "婦女低頭守巾幗，男兒嚼齒吞刀鋸。", "殺身慷慨猶易免，取義從容未輕許。", "仁人志士所植立，橫絕地維屹天柱。", "以身徇道不苟生，道在光明照千古。", "素王不作春秋廢，獸蹄鳥跡交中土。", "閏位適在三七間，禮樂終當屬真主。", "李陵衛律罪通天，遺臭至今使人吐。", "種瓜東門不可得，暴骨匈奴固其所。", "平生讀書爲誰事，臨難何憂復何懼。", "已矣夫，易簀不必如曾參，結纓猶當效子路。"]'),
('028a517c-4a42-4503-a3a9-07b4b58636c4','南海','文天祥','宋','宋诗','song-poetry','','[]','朅來南海上，人死亂如麻。',48,'全唐诗/poet.song.239000.json','["朅來南海上，人死亂如麻。", "腥浪拍心碎，飆風吹鬢華。", "一山還一水，無國又無家。", "男子千年志，吾生未有涯。"]'),
('1e6aee66-3705-4eaf-a63c-c9f22ab7f765','有感','文天祥','宋','宋诗','song-poetry','','[]','海闊龍深蟄，山空鳥雜鳴。',48,'全唐诗/poet.song.239000.json','["海闊龍深蟄，山空鳥雜鳴。", "花隨春共去，雲與水俱行。", "壯士千年志，征夫萬里程。", "夜凉看星斗，何處是攙槍。"]'),
('38eb219f-aaea-4fbb-b97d-65e07003997d','張元帥謂予國已亡矣殺身以忠誰復書之予謂商非不亡夷齊自不食周粟人臣自盡其心豈論書與不書張爲改容因成一詩','文天祥','宋','宋诗','song-poetry','','[]','高人名若浼，烈士死如歸。',48,'全唐诗/poet.song.239000.json','["高人名若浼，烈士死如歸。", "智滅猶吞炭，商亡正採薇。", "豈因徼後福，其肯蹈危機。", "萬古春秋義，悠悠雙淚揮。"]'),
('54b1a383-e5a9-4981-8bc4-e8f626420b1a','登樓','文天祥','宋','宋诗','song-poetry','','[]','茫茫地老與天荒，如此男兒鐵石腸。',64,'全唐诗/poet.song.239000.json','["茫茫地老與天荒，如此男兒鐵石腸。", "七十日來浮海道，三千里外望江鄉。", "高鴻尚覺心期闊，蹇馬何堪脚跡長。", "獨自登樓時拄頰，山川在眼淚浪浪。"]'),
('51ba4884-0f61-4d8d-9a61-0d7a95a7a448','海上','文天祥','宋','宋诗','song-poetry','','[]','天邊青鳥逝，海上白鷗馴。',48,'全唐诗/poet.song.239000.json','["天邊青鳥逝，海上白鷗馴。", "王濟非癡叔，陶潜豈醉人。", "得官須報國，可隠即逃秦。", "身事蓋棺定，挑燈看劍頻。"]'),
('01699a26-13ed-4496-94b0-b54ebe714960','贛州','文天祥','宋','宋诗','song-poetry','','[]','滿城風雨送凄凉，三四年前此戰場。',64,'全唐诗/poet.song.239000.json','["滿城風雨送凄凉，三四年前此戰場。", "遺老猶應愧蜂蟻，故交已久化豺狼。", "江山不改人心在，宇宙方來事會長。", "翠玉樓前天亦泣，南音半夜落滄浪。"]'),
('5b8d1739-5cef-4fd1-bf23-55bb0f6f5494','出廣州第一宿','文天祥','宋','宋诗','song-poetry','','[]','越王臺下路，搔首歎萍蹤。',48,'全唐诗/poet.song.239000.json','["越王臺下路，搔首歎萍蹤。", "城古都招水，山高易得風。", "鼓聲殘雨後，塔影暮林中。", "一樣連營火，山同河不同。"]'),
('9cbd687a-c9d6-40b2-b969-66eb9de9d6fe','英德道中','文天祥','宋','宋诗','song-poetry','','[]','海近山如沃，杼深屋半蕪。',48,'全唐诗/poet.song.239000.json','["海近山如沃，杼深屋半蕪。", "乾坤正風雨，軒冕總泥途。", "自歎鳶肩薄，誰憐鶴影孤。", "少年狂不醒，夜夜夢伊吾。"]'),
('61ecb448-f9e9-414e-af3c-c9e564cbf0bc','晚渡','文天祥','宋','宋诗','song-poetry','','[]','青山圍萬疊，流落此何邦。',48,'全唐诗/poet.song.239000.json','["青山圍萬疊，流落此何邦。", "雲靜龍歸海，風清馬渡江。", "汲灘供茗椀，編竹當蓬窗。", "一井沙頭月，羈鴻共影雙。"]'),
('0c5d89a9-d7cf-4e3d-ae22-17dec2b73b25','珊瑚吟','文天祥','宋','宋诗','song-poetry','','[]','南方有珍禽，鳴聲天下奇。',96,'全唐诗/poet.song.239000.json','["南方有珍禽，鳴聲天下奇。", "毛羽黑如漆，兩臉凝璚脂。", "燕趙佳公子，籠檻以自隨。", "童子重丁寧，飲食必以時。", "將獻上林苑，來巢萬年枝。", "待之豈少恩，不免加縶維。", "珊瑚真珊瑚，碎琢良自悲。", "中原寒氣深，風土非所宜。"]'),
('dd530048-6b5b-4629-a55f-46de93ac027d','和中甫端午韻不依次','文天祥','宋','宋诗','song-poetry','','[]','黄茅古道外，羸馬發南州。',48,'全唐诗/poet.song.239000.json','["黄茅古道外，羸馬發南州。", "有客嗤齊魯，何人念楚囚。", "歲年付流水，風雨滿滄洲。", "手把菖蒲看，黑頭非所求。"]'),
('a1993372-98f5-43c6-804d-2600fb240b33','又呈中齋  其一','文天祥','宋','宋诗','song-poetry','','[]','風雨羊腸道，飄零萬死身。',48,'全唐诗/poet.song.239000.json','["風雨羊腸道，飄零萬死身。", "牛兒朝共載，木客夜爲鄰。", "庾子江南夢，蘇郎海上貧。", "悠悠看晚渡，誰是濟川人。"]'),
('922a46ee-6e9a-4eab-a659-1d1f22624e1f','又呈中齋  其二','文天祥','宋','宋诗','song-poetry','','[]','萬里論心晚，相看慰亂離。',48,'全唐诗/poet.song.239000.json','["萬里論心晚，相看慰亂離。", "丹成俄已化，璧碎尚無緇。", "禾黍西原夢，川原落日悲。", "斯文今已矣，來世以爲期。"]'),
('c6eb8ce4-b35a-4e21-99dd-9e5504ac238e','竹間','文天祥','宋','宋诗','song-poetry','','[]','倦來聊歇馬，隨分此青山。',48,'全唐诗/poet.song.239000.json','["倦來聊歇馬，隨分此青山。", "流水竹千箇，清風沙一灣。", "乾坤醒醉裏，身世有無間。", "客路真希絕，浮生半日閑。"]'),
('b70bdcc9-8504-4397-8cae-8341bbb7e2a4','越王臺','文天祥','宋','宋诗','song-poetry','','[]','登臨我向亂離來，落落千年一越臺。',64,'全唐诗/poet.song.239000.json','["登臨我向亂離來，落落千年一越臺。", "春事暗隨流水去，潮聲空逐暮天迴。", "煙橫古道人行少，月墮荒村鬼哭哀。", "莫作楚囚愁絕看，舊家歌舞此銜盃。"]'),
('61d79dcb-4cd0-43d8-9e3c-c52f4e43da76','南華山','文天祥','宋','宋诗','song-poetry','','[]','北行近千里，迷復忘西東。',60,'全唐诗/poet.song.239000.json','["北行近千里，迷復忘西東。", "行行至南華，忽忽如夢中。", "佛化知幾塵，患乃與我同。", "有形終歸滅，不滅惟真空。", "笑看曹溪水，門前坐松風。"]'),
('43d4b71e-d75a-41b6-8d3a-b2bff916863a','南安軍','文天祥','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u884c\u519b", "\u58ee\u5fd7"]','梅花南北路，風雨濕征衣。',48,'全唐诗/poet.song.239000.json','["梅花南北路，風雨濕征衣。", "出嶺誰同出，歸鄉如不歸。", "山河千古在，城郭一時非。", "饑死真吾志，夢中行採薇。"]'),
('ecfcf562-0827-4d8f-9806-2f32305de8d4','黄金市','文天祥','宋','宋诗','song-poetry','','[]','閉蓬絕粒始南州，我過青山欲首丘。',64,'全唐诗/poet.song.239000.json','["閉蓬絕粒始南州，我過青山欲首丘。", "巡遠應無兒女態，夷齊肯作稻粱謀。", "人間早見黄金市，天上猶遲白玉樓。", "先子神遊今二紀，夢中揮淚濺松楸。"]'),
('09eb0866-ca01-4c81-8bee-961b08a9c93e','萬安縣','文天祥','宋','宋诗','song-poetry','','[]','青山曲折水天平，不是南征是北征。',64,'全唐诗/poet.song.239000.json','["青山曲折水天平，不是南征是北征。", "舉世更無巡遠死，當年誰道甫申生。", "遥知嶺外相思處，不見灘頭皇恐聲。", "傳語故園猿鶴好，夢回江路月風清。"]'),
('d58991ea-fd7a-4e47-a64c-289143755369','泰和','文天祥','宋','宋诗','song-poetry','','[]','書生曾擁碧油幢，耻與群兒共豎降。',64,'全唐诗/poet.song.239000.json','["書生曾擁碧油幢，耻與群兒共豎降。", "漢節幾回登快閣，楚囚今度過澄江。", "丹心不改君臣誼，清淚難忘父母邦。", "惟有鄉人知我瘦，下帷絕粒坐蓬窗。"]'),
('3a5561f3-7f1a-47a2-8589-8cb51986be6f','蒼然亭','文天祥','宋','宋诗','song-poetry','','[]','風打船頭繫夕陽，亭前老子舊胡床。',64,'全唐诗/poet.song.239000.json','["風打船頭繫夕陽，亭前老子舊胡床。", "青牛過去關山動，白鶴歸來城郭荒。", "忠節風流落塵土，英雄遺恨滿滄浪。", "故園水月應無恙，江上新松幾許長。"]'),
('a2c6f28a-23ed-4a44-b54a-5b19d53c6c43','別里中諸友','文天祥','宋','宋诗','song-poetry','','[]','青山重回首，風雨暗啼猿。',48,'全唐诗/poet.song.239000.json','["青山重回首，風雨暗啼猿。", "楊柳溪頭釣，梅花石上尊。", "故人無復見，烈士尚誰言。", "長有歸來夢，衣冠滿故園。"]'),
('c6c0dc1a-f4b0-4ef9-be17-959a7003cfff','發吉州','文天祥','宋','宋诗','song-poetry','','[]','己卯六月初一日，蒼然亭下楚囚立。',128,'全唐诗/poet.song.239000.json','["己卯六月初一日，蒼然亭下楚囚立。", "山河顛倒紛雨泣，乙亥七夕此何夕。", "煌煌斗牛劍光濕，戈鋋彗雲雷電擊。", "三百餘年火爲德，須臾風雨天地黑。", "皇綱解紐地維折，妾婦偷生自爲賊。", "英雄扼腕怒鬚赤，貫日血忠死窮北。", "首陽風流落南國，正氣未亡人未息。", "青原萬丈光赫赫，大江東去日夜白。"]'),
('53fa2a62-799b-4419-a0c0-d5494d8be250','臨江軍','文天祥','宋','宋诗','song-poetry','','[]','江岸今多嚙，城居昔屢焚。',48,'全唐诗/poet.song.239000.json','["江岸今多嚙，城居昔屢焚。", "市人半傖父，豎子亦將軍。", "蛟哭金洲雨，猿啼玉觀雲。", "周郎墳土上，回首淚成痕。"]'),
('f13b252f-a820-45aa-a209-3bed4bd5b190','隆興府','文天祥','宋','宋诗','song-poetry','','[]','半生幾度此登臨，流落而今雪滿簪。',64,'全唐诗/poet.song.239000.json','["半生幾度此登臨，流落而今雪滿簪。", "南浦不知春已晚，西山但覺日初陰。", "誰憐龜鶴千年語，空負鵬鵾萬里心。", "無限故人簾雨外，夜深如有廣陵音。"]'),
('2ba66a5d-7504-449e-8431-bdd78c901dcc','湖口','文天祥','宋','宋诗','song-poetry','','[]','江湖一都會，宇宙幾興亡。',48,'全唐诗/poet.song.239000.json','["江湖一都會，宇宙幾興亡。", "走馬蘆林外，買魚茅舍傍。", "南人撐快槳，北客坐危檣。", "江水交岷水，東流日夜長。"]'),
('b63899e9-caa0-4c2a-8d91-d2084b76e6e0','安慶府','文天祥','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','風雨宜城路，重來白髮新。',48,'全唐诗/poet.song.239000.json','["風雨宜城路，重來白髮新。", "長江還有險，中國自無人。", "梟獍蕃遺育，鱣鯨蟄怒鱗。", "泊船休上岸，不忍見遺民。"]'),
('8ae10b2a-b0e9-4754-a5ec-2902bfaa14a3','池州','文天祥','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','五老湖光遠，九華山色昏。',48,'全唐诗/poet.song.239000.json','["五老湖光遠，九華山色昏。", "南冠前進士，北部故將軍。", "芳草江頭路，斜陽郭外村。", "匆匆十年夢，故國黯銷魂。"]'),
('bb7a9616-35af-4aaf-b520-eadce55b62ee','魯港','文天祥','宋','宋诗','song-poetry','','[]','方誇金塢築，豈料玉床摇。',48,'全唐诗/poet.song.239000.json','["方誇金塢築，豈料玉床摇。", "國體真三代，江流舊六朝。", "鞭投能幾日，瓦解不崇朝。", "千古燕山恨，西風捲怒潮。"]'),
('70ce792c-5549-4bd3-88db-da1531da22ab','采石','文天祥','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','不上峨眉二十歲，重來爲墮山河淚。',64,'全唐诗/poet.song.239000.json','["不上峨眉二十歲，重來爲墮山河淚。", "今人不見虞允文，古人曾有樊若水。", "長江闊處平如驛，况此介然衣带窄。", "欲從謫仙捉月去，安得然犀照神物。"]'),
('fa86bb61-e594-4952-b577-fce36cea3962','建康','文天祥','宋','宋诗','song-poetry','','[]','金陵古會府，南渡舊陪京。',48,'全唐诗/poet.song.239000.json','["金陵古會府，南渡舊陪京。", "山勢猶盤礴，江流已變更。", "健兒徙幽土，新鬼哭臺城。", "一片清溪月，偏於客有情。"]'),
('65784e92-1441-4539-82d6-09d107d25eb1','金陵驛  其一','文天祥','宋','宋诗','song-poetry','','[]','草合離宮轉夕暉，孤雲飄泊復何依。',64,'全唐诗/poet.song.239000.json','["草合離宮轉夕暉，孤雲飄泊復何依。", "山河風景元無異，城郭人民半已非。", "滿地蘆花和我老，舊家燕子傍誰飛。", "從今別却江南日，化作啼鵑带血歸。"]'),
('761079d2-4ee6-4d4b-bb22-603669d10679','金陵驛  其二','文天祥','宋','宋诗','song-poetry','','[]','萬里金甌失壯圖，衮衣顛倒落泥塗。',64,'全唐诗/poet.song.239000.json','["萬里金甌失壯圖，衮衣顛倒落泥塗。", "空流杜宇聲中血，半脫驪龍頷下鬚。", "老去秋風吹我惡，夢回寒月照人孤。", "千年成敗俱塵土，消得人間說丈夫。"]'),
('3dea2c2a-68e3-47d6-b580-c2f71e61b15e','懷忠襄','文天祥','宋','宋诗','song-poetry','','[]','平生王佐心，世運蹈衰末。',48,'全唐诗/poet.song.239000.json','["平生王佐心，世運蹈衰末。", "齊虜誰復封，楚囚詎當脫。", "金陵雖懷古，尚友在風烈。", "褒忠侈遺廟，夫子我先達。"]'),
('196f5536-0b4e-41e7-8206-c796919c807a','早秋','文天祥','宋','宋诗','song-poetry','','[]','隻影飄零天一涯，千秋摇落欲何之。',64,'全唐诗/poet.song.239000.json','["隻影飄零天一涯，千秋摇落欲何之。", "朝看带緩方嫌瘦，夜怯衾單始覺衰。", "眼裏游從驚死別，夢中兒女慰生離。", "六朝無限江山在，搔首斜陽獨立時。"]'),
('e3ade295-6f98-4558-bc7e-a2d66681db0e','睡起','文天祥','宋','宋诗','song-poetry','','[]','空堂孤影起聞鷄，風起高樓鼓角悲。',64,'全唐诗/poet.song.239000.json','["空堂孤影起聞鷄，風起高樓鼓角悲。", "江海無情遊子倦，歲年如夢美人遲。", "平生管鮑成何事，千古夷齊在一時。", "坐久日斜庭木落，浮雲滅沒漏朝曦。"]'),
('ecbf2824-711d-4056-83c5-33e5a41eea29','中秋','文天祥','宋','宋诗','song-poetry','','[]','不教收骨瘴江邊，驅向胡沙著去鞭。',64,'全唐诗/poet.song.239000.json','["不教收骨瘴江邊，驅向胡沙著去鞭。", "舊奪宮袍空獨步，新食官飯飽孤眠。", "客程恰與秋天半，人影何如月倍圓。", "猶是江南佳麗地，徘徊把酒看蒼天。"]'),
('1e8427d2-f4f5-4cd1-af71-0ac0ce6b7760','和中齋韻  其一','文天祥','宋','宋诗','song-poetry','','[]','功業飄零五丈原，如今局促傍誰轅。',64,'全唐诗/poet.song.239000.json','["功業飄零五丈原，如今局促傍誰轅。", "俛首北去明妃淚，啼血南飛望帝魂。", "骨肉凋殘唯我在，形容變盡只聲存。", "洪流千古英雄恨，蘭作行舟柳作樊。"]'),
('42c14058-99aa-4939-b705-df1f04ceb4a3','和中齋韻  其二','文天祥','宋','宋诗','song-poetry','','[]','見說黄沙接五原，飄零隻影向南轅。',64,'全唐诗/poet.song.239000.json','["見說黄沙接五原，飄零隻影向南轅。", "江山有恨銷人骨，風雨無情斷客魂。", "淚似空花千點落，鬢如碩果數根存。", "肉飛不起真堪歎，江水爲籠海作樊。"]'),
('6b5b13a4-fc5a-4440-82aa-9d90c6cd1124','和友人','文天祥','宋','宋诗','song-poetry','','[]','落落南冠過故都，近來我意亦忘吾。',64,'全唐诗/poet.song.239000.json','["落落南冠過故都，近來我意亦忘吾。", "騎來驛馬身如寄，遣去家書字亦無。", "景伯未囚先立後，嵇康縱死不爲孤。", "江南只有歸來夢，休問田園蕪不蕪。"]'),
('d3f0a3c0-8b20-449b-b11b-ff8ca3d52cd8','懷中甫','文天祥','宋','宋诗','song-poetry','','[]','久要何落落，末路重依依。',48,'全唐诗/poet.song.239000.json','["久要何落落，末路重依依。", "風雨連兵幕，泥塗滿客衣。", "人間龍虎變，天外燕鴻違。", "死矣煩公傳，北方人是非。"]'),
('f48dd470-ec30-434c-a98d-db10af66e32d','行宮  其一','文天祥','宋','宋诗','song-poetry','','[]','十里宮牆一聚塵，天津晚過客愁新。',64,'全唐诗/poet.song.239000.json','["十里宮牆一聚塵，天津晚過客愁新。", "花啼杜宇歸來血，樹掛蒼龍脫去鱗。", "福德儻存終有晉，秣陵未改已無秦。", "秋風禾黍空南北，見說銅駝會笑人。"]'),
('c8810b71-9693-4641-8e03-098ef3f4bb6c','行宮  其二','文天祥','宋','宋诗','song-poetry','','[]','怪底秦淮一水長，幾多客淚洒斜陽。',64,'全唐诗/poet.song.239000.json','["怪底秦淮一水長，幾多客淚洒斜陽。", "江流本是限南北，地氣何曾減帝王。", "臺沼漸荒基歷落，鶑花猶在意凄凉。", "青天畢竟有情否，舊月東來失女牆。"]'),
('2171883d-d81d-41aa-bfe4-db39e3dc74a0','送行中齋三首  其一','文天祥','宋','宋诗','song-poetry','','[]','秋風晚正烈，客衣早知寒。',96,'全唐诗/poet.song.239000.json','["秋風晚正烈，客衣早知寒。", "把衣不能別，更盡此日歡。", "出門一萬里，風沙浩漫漫。", "豈無兒女情，爲君思汍瀾。", "百年有時盡，千載無餘觀。", "明明君臣義，公獨爲其難。", "願持丹一寸，寫入青琅玕。", "會有撫卷人，孤燈起長歎。"]'),
('ee2acb78-320e-4980-89d4-3c30ae6bf0eb','送行中齋三首  其二','文天祥','宋','宋诗','song-poetry','','[]','神龍蕩失水，馴擾終未得。',96,'全唐诗/poet.song.239000.json','["神龍蕩失水，馴擾終未得。", "威鳳雖在藪，肯顧鷄鶩食。", "所以古之人，受變心不易。", "亳鼎已遷周，西山竟肌瘠。", "豫子身自漆，長弘血成碧。", "何嘗怨廢興，而或二心跡。", "堅白不在緇，羔裘良自惜。", "此誼公素明，俗見或未識。"]'),
('bcdaeb36-4345-4dd1-bd50-36bbde7d1841','送行中齋三首  其三','文天祥','宋','宋诗','song-poetry','','[]','嗟予抱區區，疇昔同里閈。',132,'全唐诗/poet.song.239000.json','["嗟予抱區區，疇昔同里閈。", "過從三十年，知心不知面。", "零落忽重逢，家亡市朝變。", "惸惸蹈海餘，踽踽南冠殿。", "劇談泥塗際，握手鞍馬倦。", "依依斯文意，苦恨十年晚。", "魯仲偶不逢，隨世本非願。", "靈胥目未抉，端欲詣所見。", "及茲萬里別，一夕腸百轉。", "余生諒須臾，孤感橫九縣。", "庶幾太尉事，萬一中丞傳。"]'),
('0f04c1a3-2aa5-4307-b8db-ef33801c665c','發建康','文天祥','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','賞心亭下路，拍手唱吾歌。',48,'全唐诗/poet.song.239000.json','["賞心亭下路，拍手唱吾歌。", "樓外梁時塔，城中秦氏河。", "江山如夢耳，天地柰愁何。", "回首清溪曲，長江一雁過。"]'),
('5ef2bcdb-7e44-4899-b487-412259a30973','江行有感','文天祥','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','蒲萄肥汗馬，荆棘冷銅駝。',48,'全唐诗/poet.song.239000.json','["蒲萄肥汗馬，荆棘冷銅駝。", "巫峽朝雲濕，洞庭秋水波。", "窮愁空突兀，暗淚自滂沱。", "莫恨吾生悞，江東才俊多。"]'),
('7aa30045-a873-4f91-86e3-28183bafd387','真州驛','文天祥','宋','宋诗','song-poetry','','[]','山川如識我，故舊更無人。',48,'全唐诗/poet.song.239000.json','["山川如識我，故舊更無人。", "俯仰干戈跡，往來車馬塵。", "英雄遺算晚，天地暗愁新。", "北首燕山路，凄凉夜向晨。"]'),
('87b11cbe-6089-4c71-bd25-cc3d03f6730d','望揚州','文天祥','宋','宋诗','song-poetry','','[]','阮籍臨廣武，杜甫登吹臺。',48,'全唐诗/poet.song.239000.json','["阮籍臨廣武，杜甫登吹臺。", "高情發慷慨，前人後人哀。", "江左遘陽運，銅駝化飛灰。", "二十四橋月，楚囚今日來。"]'),
('9be1bcde-c979-437e-9ecb-d7dfce6c1e63','維揚驛','文天祥','宋','宋诗','song-poetry','','[]','三年別淮水，一夕宿揚州。',48,'全唐诗/poet.song.239000.json','["三年別淮水，一夕宿揚州。", "南極山川古，北風江海秋。", "昭君愁出塞，王粲怕登樓。", "千載英雄淚，如今况楚囚。"]'),
('da034df9-d029-44d5-ae26-286cc46ee8d1','過邵伯鎮','文天祥','宋','宋诗','song-poetry','','[]','今朝車馬地，昔日戰爭場。',48,'全唐诗/poet.song.239000.json','["今朝車馬地，昔日戰爭場。", "我有揚州鶴，誰存邵伯棠。", "一灣流水小，數畝故城荒。", "回首江南路，青山斷夕陽。"]'),
('dcdc441f-fdc9-435e-a058-f41ef91bfdb4','高郵懷舊','文天祥','宋','宋诗','song-poetry','','[]','借問曾遊處，高沙第幾山。',48,'全唐诗/poet.song.239000.json','["借問曾遊處，高沙第幾山。", "潜行鷹攫道，直上虎當關。", "一命虛空裏，三年瞬息間。", "自憐今死晚，何復望生還。"]'),
('8fa84151-d103-414a-87e5-b05cdbfdf418','發高郵','文天祥','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','初出高沙門，輕舫遶城樓。',204,'全唐诗/poet.song.239000.json','["初出高沙門，輕舫遶城樓。", "一水何曲折，百年此綢繆。", "北望渺無際，飛鳥翔平疇。", "寒蕪入荒落，日薄行人愁。", "行行行湖曲，萬頃涵清秋。", "大風吹檣倒，如盪彭蠡舟。", "欲寄故鄉淚，使入長江流。", "篙人爲我言，此水通淮頭。", "前與黄河合，同作滄海漚。", "踟躕忽失意，拭淚淚不收。", "吳會日已遠，回首重悠悠。", "馳驅梁趙郊，壯士何離憂。", "吾道久矣東，陸沈古神州。", "我今戴南冠，何異有北投。", "不能裂肝腦，直氣摩斗牛。", "但願光岳合，休明復商周。", "不使殊方魄，終爲異物羞。"]'),
('5d9fb0ad-0b46-4a5f-bf6c-3e67dde40886','寶應道中','文天祥','宋','宋诗','song-poetry','','[]','天闊摶南雁，淮途長北驅。',48,'全唐诗/poet.song.239000.json','["天闊摶南雁，淮途長北驅。", "甘棠成傳舍，細柳作康衢。", "田海隨時變，山河往日殊。", "征袍共衮繡，夜壁一燈孤。"]'),
('1e5aa2a3-ba2b-4d65-b06a-8aacba6475ae','淮安軍','文天祥','宋','宋诗','song-poetry','','[]','楚州城門外，白楊吹悲風。',48,'全唐诗/poet.song.239000.json','["楚州城門外，白楊吹悲風。", "纍纍死人塚，死向鋒鏑中。", "豈無匹婦冤，定無萬夫雄。", "中原在其北，登城望何窮。"]'),
('fff5b17c-2762-4fa5-abe2-0c8228254d85','過淮河宿闞石有感','文天祥','宋','宋诗','song-poetry','','[]','北征垂半年，依依只南土。',120,'全唐诗/poet.song.239000.json','["北征垂半年，依依只南土。", "今晨渡淮河，始覺非故宇。", "江鄉已無家，三年一羈旅。", "龍翔在何方，乃我妻子所。", "昔也無柰何，忽已置念慮。", "今行日已近，使我淚如雨。", "我爲綱常謀，有身不得顧。", "妻兮莫望夫，子兮莫望父。", "天長與地久，此恨極千古。", "來生業緣在，骨肉當如故。"]'),
('b8713790-9952-4414-acf9-17f9846704a4','發淮安','文天祥','宋','宋诗','song-poetry','','[]','九月初二日，車馬發淮安。',96,'全唐诗/poet.song.239000.json','["九月初二日，車馬發淮安。", "行行重行行，天地何不寬。", "烟火無一家，荒草青漫漫。", "恍如泛滄海，身坐玻瓈盤。", "時時逢北人，什伍扶征鞍。", "云我戍江南，當軍身屬官。", "北人適吳楚，所憂地少寒。", "江南有遊子，風雪上燕山。"]'),
('7a484b97-02b7-4650-aa99-04104180c47f','小清口初三日','文天祥','宋','宋诗','song-poetry','','[]','乍見驚胡婦，相嗟遇楚兵。',48,'全唐诗/poet.song.239000.json','["乍見驚胡婦，相嗟遇楚兵。", "北來鴻雁密，南去駱駝輕。", "芳草中原路，斜陽故國情。", "明朝五十里，錯做武陵行。"]'),
('dc350500-77c3-4aca-8597-5de8cde3ee6e','桃源道中','文天祥','宋','宋诗','song-poetry','','[]','漠漠地千里，垂垂天四圍。',48,'全唐诗/poet.song.239000.json','["漠漠地千里，垂垂天四圍。", "隔溪胡騎過，傍草野鷄飛。", "風露吹青笠，塵沙薄素衣。", "吾家白雲下，都伴北人歸。"]'),
('8aea22f4-508d-4463-891e-fa1e95100e94','桃源縣','文天祥','宋','宋诗','song-poetry','','[]','清野百年久，中原千里賒。',48,'全唐诗/poet.song.239000.json','["清野百年久，中原千里賒。", "火煙新聚落，山水舊生涯。", "種麥十數畝，誅茅千百家。", "我來行正倦，何處覓桃花。"]'),
('5ffa6166-4c19-4442-9f89-9f5f5f6388b2','崔鎮驛','文天祥','宋','宋诗','song-poetry','','[]','萬里中原役，北風天正凉。',48,'全唐诗/poet.song.239000.json','["萬里中原役，北風天正凉。", "黄沙漫道路，蒼耳滿衣裳。", "野闊人聲小，日斜駒影長。", "解鞍身似夢，遊子意茫茫。"]'),
('81640ee1-89ef-4867-bb78-37f6f48a3b0d','發崔鎮','文天祥','宋','宋诗','song-poetry','','[]','高雁空秋興，寒螿破曉眠。',48,'全唐诗/poet.song.239000.json','["高雁空秋興，寒螿破曉眠。", "淡烟白似海，野水碧於天。", "興廢嗟何及，行藏信自然。", "南人乍騎馬，北客半乘船。"]'),
('24bf87a3-5b86-4ef5-99cf-980710d95d68','發宿遷縣','文天祥','宋','宋诗','song-poetry','','[]','夜夢入星槎，曉行隨斗柄。',48,'全唐诗/poet.song.239000.json','["夜夢入星槎，曉行隨斗柄。", "衣暖露自乾，鬢寒冰欲凝。", "將軍戴鐵笠，壯士敲金鐙。", "白眼睨青天，我生不有命。"]'),
('c724a0d7-d638-4e5b-bbb0-681cbe5ac5fb','中原','文天祥','宋','宋诗','song-poetry','','[]','中原方萬里，明日是重陽。',48,'全唐诗/poet.song.239000.json','["中原方萬里，明日是重陽。", "桑棗人家近，蓬蒿客路長。", "引弓虛射雁，失馬爲尋羊。", "見說今年旱，青青麥又秧。"]'),
('d8f92db6-a4ac-4df5-ace5-0a6552d322ef','望邳州','文天祥','宋','宋诗','song-poetry','','[]','中原行幾日，今日纔見山。',72,'全唐诗/poet.song.239000.json','["中原行幾日，今日纔見山。", "問山在何處，云在徐邳間。", "邳州山，徐州水，項籍不還韓信死。", "龍爭虎鬭不肯止，煙草漫漫青萬里。", "古來劉季號英雄，樊崇至今已千歲。"]'),
('4f4e3510-3947-4057-859e-3b393af94f02','徐州道中','文天祥','宋','宋诗','song-poetry','','[]','彭城古官道，日中十馬馳。',138,'全唐诗/poet.song.239000.json','["彭城古官道，日中十馬馳。", "咫尺不見人，撲面黄塵飛。", "白頭漢王縞素師，美人燕罷項羽啼。", "一時混戰四十萬，天昏地黑睢水湄。", "乃知大風揚沙失白晝，自是地利非天時。", "漢王倉皇問道西，一兒一女嘻其危。", "太公呂后去不歸，俎上寧有生還時。", "未央稱壽太上皇，巍然女媧帝中闈。", "終然富貴自有命，造物顛倒真小兒。"]'),
('d60eeda3-1578-44a4-bd51-ceb7be980b0b','彭城行','文天祥','宋','宋诗','song-poetry','','[]','連山四圍合，呂梁貫其中。',192,'全唐诗/poet.song.239000.json','["連山四圍合，呂梁貫其中。", "河南大都會，故有項王宮。", "晉牧連楊豫，虎視北方雄。", "唐時燕子樓，風流張建封。", "西望睢陽城，只與汴水通。", "太平黄樓賦，尚能想遺風。", "邇來百餘年，正朔歸江東。", "遺民死欲盡，莽然狐兔叢。", "我從南方來，停驂撫遺蹤。", "故河蓄潢潦，荒城翳秋蓬。", "凄凉戲馬臺，憔悴巨佛峰。", "滄海變桑田，陵谷代不同。", "朝爲朱門貴，暮作行旅窮。", "乘除信物理，感慨繫所逢。", "古來賢達人，一醉萬慮空。", "如此獨醒何，悲風逐征鴻。"]'),
('70d3db6e-61a9-492b-8315-3e4d40287c13','燕子樓','文天祥','宋','宋诗','song-poetry','','[]','自別張公子，嬋娟不下樓。',96,'全唐诗/poet.song.239000.json','["自別張公子，嬋娟不下樓。", "遂令樓上燕，百歲稱風流。", "我遊彭城門，來吊楚王闕。", "問樓在何處，城東草如雪。", "蛾眉代不乏，埋沒安足論。", "因何張家妾，名與山川存。", "自古皆有死，忠義長不沒。", "但傳美人心，不說美人色。"]'),
('6eab1abd-26eb-4154-9e36-bb990e95bf7e','戲馬臺','文天祥','宋','宋诗','song-poetry','','[]','九月初九日，客遊戲馬臺。',48,'全唐诗/poet.song.239000.json','["九月初九日，客遊戲馬臺。", "黄花弄朝露，古人花飛埃。", "今人哀後人，後人復今哀。", "世事那可及，淚落茱萸杯。"]'),
('0882754f-a2df-4e43-a414-602565d27de4','發彭城','文天祥','宋','宋诗','song-poetry','','[]','今朝正重九，行人意遲遲。',72,'全唐诗/poet.song.239000.json','["今朝正重九，行人意遲遲。", "回首戲馬臺，野花發葳蕤。", "草埋范增塚，雲見樊噲旗。", "時節正如此，道路將何之。", "我愛陶淵明，甲子題新詩。", "白衣送酒來，把菊卧東籬。"]'),
('f66adf8a-050b-45a8-820f-ecf134af2c55','沛歌','文天祥','宋','宋诗','song-poetry','','[]','秦世失其鹿，豐沛發龍顔。',108,'全唐诗/poet.song.239000.json','["秦世失其鹿，豐沛發龍顔。", "王侯與將相，不出徐濟間。", "當時數公起，四海王氣閑。", "至今尚想見，虹光照人寰。", "我來千載下，吊古淚如潸。", "白雲落荒草，隠隠芒碭山。", "黄河天下雄，南去不復還。", "乃知盈虛故，天道如循環。", "盧王舊封地，今日殽函關。"]'),
('a9e20959-282e-488c-9476-842e08a648cf','歌風臺','文天祥','宋','宋诗','song-poetry','','[]','長陵有神氣，萬歲光如虹。',180,'全唐诗/poet.song.239000.json','["長陵有神氣，萬歲光如虹。", "有時風雪變，魂魄來沛宮。", "壯哉游子鄉，一覽萬宇空。", "擊筑戒復隍，帝業慎所終。", "重瞳愛梁父，此情豈不同。", "錦衣絢行晝，丈夫何淺中。", "緬懷首丘意，自足分雌雄。", "尚惜霸心存，慷慨懷勇功。", "不見往來事，烹狗與藏弓。", "早知致兩生，禮樂三代隆。", "匹夫事已往，安用責乃翁。", "我來湯沐邑，白楊吹悲風。", "永言三侯章，隠隠聞兒童。", "葉落皆歸根，飄零獨秋蓬。", "登臺共悽惻，目送南飛鴻。"]'),
('07edd0a0-8868-48af-abab-30ba280fcbf1','固陵道中三首  其一','文天祥','宋','宋诗','song-poetry','','[]','九天雲下垂，一雨作秋色。',48,'全唐诗/poet.song.239000.json','["九天雲下垂，一雨作秋色。", "塵埃化泥塗，原野轉蕭瑟。", "十里一雙堠，狐兔卧荆棘。", "見說數年來，中州乍蘇息。"]'),
('0ff71385-5b77-47f3-bdcb-494942b80892','固陵道中三首  其二','文天祥','宋','宋诗','song-poetry','','[]','茅舍荒凉舊固陵，漢王城對楚王城。',32,'全唐诗/poet.song.239000.json','["茅舍荒凉舊固陵，漢王城對楚王城。", "徐州煙火連豐沛，天下還來屋角爭。"]'),
('083240d4-260d-4cbe-9e9b-2d84d381120b','固陵道中三首  其三','文天祥','宋','宋诗','song-poetry','','[]','固陵城下兩龍爭，不見齊王來會兵。',32,'全唐诗/poet.song.239000.json','["固陵城下兩龍爭，不見齊王來會兵。", "勒取河山新分地，項王之後到韓彭。"]'),
('67f724ab-67a5-47ac-acac-bf047f52b3d3','發魚臺','文天祥','宋','宋诗','song-poetry','','[]','晨炊發魚臺，碎雨飛擊面。',72,'全唐诗/poet.song.239000.json','["晨炊發魚臺，碎雨飛擊面。", "團團四野周，冥冥萬象變。", "疑是江南山，煙霧昏不見。", "豈知此中原，今古經百戰。", "英雄化爲土，飛霧洒郊甸。", "天寒日欲短，游子淚如霰。"]'),
('a86061d8-81c7-46a7-a296-9adf4740f0df','自歎','文天祥','宋','宋诗','song-poetry','','[]','瑟瑟秋風悲，烈烈寒氣驕。',72,'全唐诗/poet.song.239000.json','["瑟瑟秋風悲，烈烈寒氣驕。", "蒲柳先已零，松柏何後凋。", "天意重肅殺，造物無不銷。", "强弱有異稟，憂患同一朝。", "惟有南山石，千載一岧嶢。", "人苦不自足，空羨王子喬。"]'),
('c40f1ced-c934-4ca3-b956-752496f9c396','遠遊','文天祥','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','黄河流活活，太行高巍巍。',264,'全唐诗/poet.song.239000.json','["黄河流活活，太行高巍巍。", "王屋山以東，百泉山以西。", "鄒魯盛文獻，燕趙多雄姿。", "右摩泰山碑，左躡函谷泥。", "郟鄏吊周公，曲阜拜宣尼。", "或登廣武歎，或上北邙悲。", "平生幾兩屐，汗漫以爲期。", "絕交天下士，要爲男子奇。", "吳會偏王業，中原隔遺黎。", "安得與黄鶴，比翼天上飛。", "江河異風景，擊楫感且欷。", "陽運遘百六，興否俄推移。", "桑田變滄海，楚囚發孔悲。", "我本檻車客，爲我解縶維。", "青蠅附天驥，萬里相追隨。", "人生尚行樂，矧復新相知。", "周道思下泉，王風懷黍離。", "富貴豈不願，憂患那自持。", "人命危且淺，忽若朝露晞。", "長恐折我軸，中道欲差池。", "去我父母邦，我行且遲遲。", "聽我遠遊曲，寄我長相思。"]'),
('696bcaa3-72aa-4f61-bfcf-142e364743aa','六歌  其一','文天祥','宋','宋诗','song-poetry','','[]','有妻有妻出糟糠，自少結髮不下堂。',89,'全唐诗/poet.song.239000.json','["有妻有妻出糟糠，自少結髮不下堂。", "亂離中道逢虎狼，鳳飛翩翩失其凰。", "將雛一二去何方，豈料國破家亦亡，不忍舍君羅襦裳。", "天長地久終茫茫，牛女夜夜遥相望。", "嗚呼一歌兮歌正長，悲風北來起徬徨。"]'),
('1859cf9e-96d9-4c62-ad9f-8ff6b9a13a11','六歌  其二','文天祥','宋','宋诗','song-poetry','','[]','有妹有妹家流離，良人去後携諸兒。',89,'全唐诗/poet.song.239000.json','["有妹有妹家流離，良人去後携諸兒。", "北風吹沙塞草凄，窮猿慘淡將安歸。", "去年哭母南海湄，三男一女同歔欷，惟汝不在割我肌。", "汝家零落母不知，母知豈有瞑目時。", "嗚呼再歌兮歌孔悲，鶺鴒在原我何爲。"]'),
('41b5fdec-f5db-4f84-afd1-d7bfef358d43','六歌  其三','文天祥','宋','宋诗','song-poetry','','[]','有女有女婉清揚，大者學帖臨鍾王，小者讀字聲琅琅。',73,'全唐诗/poet.song.239000.json','["有女有女婉清揚，大者學帖臨鍾王，小者讀字聲琅琅。", "朔風吹衣白日黄，一雙白璧委道傍。", "雁兒啄啄秋無粱，隨母北首誰人將。", "嗚呼三歌兮歌愈傷，非爲兒女淚淋浪。"]'),
('e6427954-116a-4fed-8635-2f3684ba524c','六歌  其四','文天祥','宋','宋诗','song-poetry','','[]','有子有子風骨殊，釋氏抱送徐卿雛。',81,'全唐诗/poet.song.239000.json','["有子有子風骨殊，釋氏抱送徐卿雛。", "四月八日摩尼珠，榴花犀錢絡繡襦。", "蘭湯百沸香似酥，欻隨飛電飄泥塗。", "汝兄十三騎鯨魚，汝今知在三歲無。", "嗚呼四歌兮歌以吁，燈前老我明月孤。"]'),
('c1b5e9e2-b048-4c1d-b30d-b04341e196af','六歌  其五','文天祥','宋','宋诗','song-poetry','','["\u897f\u6e56"]','有妾有妾今何如，大者手將玉蟾蜍，次者親抱汗血駒。',89,'全唐诗/poet.song.239000.json','["有妾有妾今何如，大者手將玉蟾蜍，次者親抱汗血駒。", "晨粧靚服臨西湖，英英雁落飄璚琚。", "風花飛墜鳥鳴呼，金莖沆瀣浮汙渠。", "天摧地裂龍鳳殂，美人塵土何代無。", "嗚呼五歌兮歌鬰紆，爲爾遡風立斯須。"]'),
('e5001851-e366-4357-bbe4-1e39b7d7e787','六歌  其六','文天祥','宋','宋诗','song-poetry','','[]','我生我生何不辰，孤根不識桃李春。',97,'全唐诗/poet.song.239000.json','["我生我生何不辰，孤根不識桃李春。", "天寒日短重愁人，北風隨我鐵馬塵。", "初憐骨肉鍾奇禍，而今骨肉相憐我。", "汝在北兮嬰我懷，我死誰當收我骸。", "人生百年何醜好，黄粱得喪俱草草。", "嗚呼六歌兮勿復道，出門一笑天地老。"]'),
('378b5af9-7332-48a2-b4ac-e376a9a38f9d','發潭口','文天祥','宋','宋诗','song-poetry','','[]','吹面北風來，拂鬢堅冰至。',60,'全唐诗/poet.song.239000.json','["吹面北風來，拂鬢堅冰至。", "軒冕委道途，衮繡易氈毳。", "百年雜醜好，始酬四方志。", "浩歌激浮雲，亭亭復攬轡。", "羲馭幾曾停，誰當掃幽翳。"]'),
('86727654-3974-47b3-adeb-03f196a181de','新濟州','文天祥','宋','宋诗','song-poetry','','[]','借問新濟州，徐鄆兄弟國。',120,'全唐诗/poet.song.239000.json','["借問新濟州，徐鄆兄弟國。", "昔爲大河南，今爲大河北。", "垂雲陰萬里，平原望不極。", "百草盡枯死，黄花自秋色。", "時時見桑樹，青青雜阡陌。", "路上無人行，煙火渺蕭瑟。", "車轍分縱橫，過者臨岐泣。", "積潦流交衢，霜蹄破叢棘。", "江南寒未深，銅爐獸花赤。", "爲知行路人，鐵冷衣裳濕。"]'),
('a381a1c9-8761-434d-a681-2282202e8df5','汶陽道中','文天祥','宋','宋诗','song-poetry','','[]','積雨不肯霽，行陸如涉川。',108,'全唐诗/poet.song.239000.json','["積雨不肯霽，行陸如涉川。", "青氈纊我後，白氈覆我前。", "我欲正衣冠，兩手如糾纏。", "飛沫流被面，代我泣涕漣。", "鴻雁紛南翔，遊子北入燕。", "平楚渺四極，雪風迷遠天。", "昔聞濟上軍，又說汶陽田。", "我今履其地，吊古愴蒼煙。", "男兒欲了事，長虹射寒泉。"]'),
('4777b2f4-309b-4df1-8c5a-25a6890d27dc','汶陽館','文天祥','宋','宋诗','song-poetry','','[]','去歲營船隩，今朝館汶陽。',48,'全唐诗/poet.song.239000.json','["去歲營船隩，今朝館汶陽。", "海空沙漠漠，河廣草茫茫。", "家國哀千古，男兒慨四方。", "老槐秋雨暗，孤影照淋浪。"]'),
('67f7de55-1017-4651-8649-0a96a5726a82','自汶陽至鄆','文天祥','宋','宋诗','song-poetry','','[]','渺渺中原道，勞生歎百非。',48,'全唐诗/poet.song.239000.json','["渺渺中原道，勞生歎百非。", "風雨吹打人，泥濘飛上衣。", "目力去天短，心事與時違。", "夫子昔相魯，侵疆自齊歸。"]'),
('ae944016-3a2f-4ef4-91d3-0d4eac215225','來平館','文天祥','宋','宋诗','song-poetry','','[]','憔悴江南客，蕭條古鄆州。',48,'全唐诗/poet.song.239000.json','["憔悴江南客，蕭條古鄆州。", "雨聲連五日，月色徹中流。", "萬里山河夢，千年宇宙愁。", "欲鞭劉豫骨，煙草暗荒丘。"]'),
('b1e54f88-993c-4f0d-a02b-f09a68631bd7','發鄆州喜晴','文天祥','宋','宋诗','song-poetry','','[]','烈風西北來，萬竅號高秋。',192,'全唐诗/poet.song.239000.json','["烈風西北來，萬竅號高秋。", "宿雲蔽層空，浮潦迷中州。", "行人苦沮洳，道阻路且修。", "流澌被鞍𩍐，飛沫綴衣裘。", "昏鴉接翅落，原野慘以愁。", "城郭何蕭條，閉戶寒颼颼。", "中宵月色滿，餘光散衾禂。", "余子戒明發，飛霧靄郊丘。", "微見扶桑紅，隠隠如沉浮。", "身遊大荒野，海氣吹蜃樓。", "須臾劃當空，六合開沉幽。", "千年厭顔色，蒼翠光欲流。", "太陽經天行，大化不暫留。", "輝光何曾滅，晻靄終當收。", "嚴霜下豐草，長歌夜悠悠。", "明日東阿道，方軌驟驊騮。"]'),
('0f30bd62-882f-45b2-9daf-1e42497d2208','發東阿','文天祥','宋','宋诗','song-poetry','','[]','東原深處所，時或見人煙。',48,'全唐诗/poet.song.239000.json','["東原深處所，時或見人煙。", "秋雨桑麻地，春風桃李天。", "貪程頻問堠，快馬緩加鞭。", "多少飛檣過，噫吁是北船。"]'),
('51e68ae5-06e6-415f-826e-86a61339c501','宿高唐州','文天祥','宋','宋诗','song-poetry','','[]','早發東阿縣，暮宿高唐州。',48,'全唐诗/poet.song.239000.json','["早發東阿縣，暮宿高唐州。", "哲人達幾微，志士懷隠憂。", "山河已歷歷，天地空悠悠。", "孤館一夜宿，北風吹白頭。"]'),
('ea694154-0bff-4a1d-925e-f741c88217a5','平原','文天祥','宋','宋诗','song-poetry','','[]','平原太守顔真卿，長安天子不知名。',192,'全唐诗/poet.song.239000.json','["平原太守顔真卿，長安天子不知名。", "一朝漁陽動鼙鼓，大河以北無堅城。", "公家兄弟奮戈起，一十七郡連夏盟。", "賊聞失色分兵還，不敢長驅入咸京。", "明皇父子將西狩，由是靈武起義兵。", "唐家再造李郭力，若論牽制公威靈。", "哀哉常山慘鈎舌，心歸朝廷氣不懾。", "崎嶇坎坷不得志，出入四朝老忠節。", "當年幸脫安祿山，白首竟陷李希烈。", "希烈安能遽殺公，宰相盧杞欺日月。", "亂臣賊子歸何處，茫茫煙草中原土。", "公死于今六百年，忠精赫赫雷行天。"]'),
('4d41df85-b7c0-4056-bbdd-f31b7c7db75b','發陵州','文天祥','宋','宋诗','song-poetry','','[]','中原似滄海，萬頃與雲連。',96,'全唐诗/poet.song.239000.json','["中原似滄海，萬頃與雲連。", "大明朝東出，皎月正在天。", "遠樹亂如點，桑麻鬰蒼煙。", "一雁入高空，千鴉落平田。", "我行天地中，如蟻磨上旋。", "雨痕留故衣，霜氣襲重氈。", "健馬嘶北風，潜魚樂深淵。", "噫哉南方人，回首空自憐。"]'),
('7136e98d-eadc-499d-a86a-4012aa673174','獻州道中','文天祥','宋','宋诗','song-poetry','','[]','三年戎服行，五嶺文玉會。',168,'全唐诗/poet.song.239000.json','["三年戎服行，五嶺文玉會。", "躋攀上崖磴，厲揭涉瀟瀨。", "十步九崎嶇，山水何破碎。", "坐令管仲小，自覺伯夷隘。", "乃今來中州，萬里如一概。", "四望登原隰，桑麻蔚旆旆。", "驊騮出清廟，過都真歷塊。", "歷歷古戰場，俯仰生感慨。", "吾常涉重湖，東海際南海。", "茲遊冠平生，天宇更宏大。", "心與太虛際，目空九圍內。", "男兒不出居，婦人坐帷蓋。", "反身以自觀，須彌納一芥。", "以此處死生，超然萬形內。"]'),
('f6e1648c-c226-4fa6-b9bf-97863afd361b','滹沱河二首  其一','文天祥','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','過了長江與大河，橫流數仞絕滹沱。',32,'全唐诗/poet.song.239000.json','["過了長江與大河，橫流數仞絕滹沱。", "蕭王麥飯曾倉卒，回首中天感慨多。"]'),
('ab1b5fc6-1d59-4c7d-95ab-e1ddbf744585','滹沱河二首  其二','文天祥','宋','宋诗','song-poetry','','[]','風沙睢水終亡楚，草木公山竟蹙秦。',32,'全唐诗/poet.song.239000.json','["風沙睢水終亡楚，草木公山竟蹙秦。", "始信滹沱冰合事，世間興廢不由人。"]'),
('47bea823-6263-457c-b7b9-ecd5d2d4a759','河間  其一','文天祥','宋','宋诗','song-poetry','','[]','空有丹心貫碧霄，泮冰亡國不崇朝。',32,'全唐诗/poet.song.239000.json','["空有丹心貫碧霄，泮冰亡國不崇朝。", "小臣萬死無遺慨，曾見天家十八朝。"]'),
('325f2bfb-5b8c-4efe-bf67-92e35e0cef70','河間  其二','文天祥','宋','宋诗','song-poetry','','[]','南歸雁蕩報郎君，老子精神健十分。',32,'全唐诗/poet.song.239000.json','["南歸雁蕩報郎君，老子精神健十分。", "不爲瀛洲復相見，阿戎翻隔萬山雲。"]'),
('dc52a133-ed34-4157-b1f6-c7b63e007df1','河間  其三','文天祥','宋','宋诗','song-poetry','','[]','江南車蓋走燕山，老子旁觀袖手閒。',32,'全唐诗/poet.song.239000.json','["江南車蓋走燕山，老子旁觀袖手閒。", "見說新詩題甲子，桃源元只在人間。"]'),
('eeeabb2d-e9d9-439c-af83-e5ca72968c6f','保州道中','文天祥','宋','宋诗','song-poetry','','[]','昨日渡滹沱，今日望太行。',252,'全唐诗/poet.song.239000.json','["昨日渡滹沱，今日望太行。", "白雲何渺渺，天地何茫茫。", "落葉混西風，黄塵昏夕陽。", "牛車過不住，氈屋行相望。", "小兒騎蹇馿，壯士駕乘黄。", "高低葉萬頃，黑白草千行。", "村落有古風，人間無時粧。", "宋遼舊分界，燕趙古戰場。", "蚩尤亂涿野，共工謫幽邦。", "郭隗致樂毅，荆軻携舞陽。", "臧盧互反覆，安史迭披猖。", "山川一今古，人物幾興亡。", "江南佔畢生，往來習羊腸。", "天馬戴青蠅，電秣馳康莊。", "適從何有來，如此醉夢鄉。", "感時意踟躕，惜往淚淋浪。", "厲階起玉環，左計由石郎。", "天地行日月，萬代乘景光。", "晝夜果可廢，春秋誠荒唐。", "吾生直須臾，俯仰際八荒。", "來者不可見，遠遊賦彷徨。"]'),
('ffebc23a-857a-475b-b6d3-60ff6f3ff40a','保涿州三詩 趙太祖墓','文天祥','宋','宋诗','song-poetry','','[]','我行保州塞，御河直其東。',48,'全唐诗/poet.song.239000.json','["我行保州塞，御河直其東。", "山川猶有靈，佳氣何鬰葱。", "顧我巾車囚，厲氣轉秋蓬。", "瓣香欲往拜，惆悵臨長空。"]'),
('a9db2d31-af04-4f3f-ad1f-d69ec98cc722','保涿州三詩 樓桑','文天祥','宋','宋诗','song-poetry','','[]','我過梁門城，樓桑在其北。',48,'全唐诗/poet.song.239000.json','["我過梁門城，樓桑在其北。", "玄德已千年，青煙遶故宅。", "道傍爲揮淚，徘徊秋風客。", "天下卧龍人，多少空抱膝。"]'),
('8d95eb78-fbd9-4263-b665-5a4b4c402c8a','保涿州三詩 涿鹿','文天祥','宋','宋诗','song-poetry','','[]','我瞻涿鹿野，古來戰蚩尤。',48,'全唐诗/poet.song.239000.json','["我瞻涿鹿野，古來戰蚩尤。", "軒轅此立極，玉帛朝諸侯。", "歷歷關河雁，隨風鳴寒秋。", "邇來三千年，王氣行幽州。"]'),
('ba2e3bdd-0ded-4ce6-b2fa-3368fc396600','過梁門','文天祥','宋','宋诗','song-poetry','','[]','一一金甌在，雙雙鎮璧全。',48,'全唐诗/poet.song.239000.json','["一一金甌在，雙雙鎮璧全。", "土花開舊國，風絮渡江船。", "南北分新統，江淮號極邊。", "更和天塹失，回首慘啼鵑。"]'),
('ab99b8f5-c8a3-405a-ac24-bc44a25b793d','白溝河','文天祥','宋','宋诗','song-poetry','','[]','昔時張叔夜，統兵赴勤王。',288,'全唐诗/poet.song.239000.json','["昔時張叔夜，統兵赴勤王。", "東都一不守，羸馬遷龍荒。", "適過白溝河，裂眥鬚欲張。", "絕粒不遄死，仰天扼其吭。", "群臣總奄奄，一土垂天光。", "讀史識其地，撫卷爲凄凉。", "我生何不辰，異世忽相望。", "皇圖遘陽九，天塹滿飛堭。", "引兵詣闕下，捧土障瀾狂。", "出使義不屈，持節還中郎。", "六飛獨南海，金鉞將煌煌。", "武侯空威心，出狩驚四方。", "吾屬竟爲虜，世事吁彼蒼。", "思公有奇節，一死何慨慷。", "江淮我分地，我欲投滄浪。", "滄浪却不受，中原行路長。", "初登項籍宮，次覽劉季邦。", "涉足河與濟，回首嵩與恒。", "下車撫梁門，上馬指樓桑。", "戴星渡一水，慘淡天微茫。", "行人爲我言，宋遼此分疆。", "懸知公死處，爲公出涕滂。", "恨不持束芻，徘徊官道傍。", "我死還在燕，烈烈同肝腸。"]'),
('f5983a86-4242-4a88-be4a-a9595f38966a','懷孔明','文天祥','宋','宋诗','song-poetry','','[]','斜谷事不濟，將星殞營中。',48,'全唐诗/poet.song.239000.json','["斜谷事不濟，將星殞營中。", "至今出師表，讀之淚沾胸。", "漢賊明大義，赤心貫蒼穹。", "世以成敗論，操懿真英雄。"]'),
('08ea35eb-2663-4dff-9f9d-87613ea0948f','劉琨','文天祥','宋','宋诗','song-poetry','','[]','中原蕩分崩，壯哉劉越石。',48,'全唐诗/poet.song.239000.json','["中原蕩分崩，壯哉劉越石。", "連蹤起幽并，隻手扶晉室。", "福華天意乘，匹磾生鬼蜮。", "公死百世名，天下分南北。"]'),
('04077c75-728e-419d-b94d-76e8c488ec7e','祖逖','文天祥','宋','宋诗','song-poetry','','[]','平生祖豫州，白首起大事。',48,'全唐诗/poet.song.239000.json','["平生祖豫州，白首起大事。", "東門長嘯兒，爲遜一頭地。", "何哉戴若思，中道奮螳臂。", "豪傑事垂成，今古爲短氣。"]'),
('9f814aa2-4a7c-4383-a224-354ad6e7c728','顔杲卿','文天祥','宋','宋诗','song-poetry','','[]','常山義旗奮，范陽哽喉咽。',48,'全唐诗/poet.song.239000.json','["常山義旗奮，范陽哽喉咽。", "胡雛一狼狽，六飛入西川。", "哥舒降且拜，公舌膏戈鋋。", "人世誰不死，公死千萬年。"]'),
('a47cea53-64cb-4a08-882b-265cf750705b','許遠','文天祥','宋','宋诗','song-poetry','','[]','起師哭玄元，義氣震天地。',48,'全唐诗/poet.song.239000.json','["起師哭玄元，義氣震天地。", "百戰奮雄姿，臠妾士揮淚。", "睢陽水東流，雙廟垂百世。", "當時令狐潮，乃爲賊遊說。"]'),
('e22babe7-0f72-4721-814e-770b1fc66b41','過雪橋琉璃橋','文天祥','宋','宋诗','song-poetry','','[]','小橋度雪度琉璃，更有清霜滑馬蹄。',32,'全唐诗/poet.song.239000.json','["小橋度雪度琉璃，更有清霜滑馬蹄。", "遊子衣裳如鐵冷，殘星荒店野鷄啼。"]'),
('8205f411-5110-4f6f-8309-2869cdea6646','五月二日生朝','文天祥','宋','宋诗','song-poetry','','[]','北風吹滿楚冠塵，笑捧蟠桃夢裏春。',64,'全唐诗/poet.song.239000.json','["北風吹滿楚冠塵，笑捧蟠桃夢裏春。", "幾歲已無籠鴿客，去年猶有送半人。", "江山如許非吾土，宇宙柰何多此身。", "不滅不生在何許，靜中聊且養吾真。"]'),
('18044121-3bee-4700-b19a-79e870ff1a01','胡笳曲 一拍','文天祥','宋','宋诗','song-poetry','','[]','風塵澒洞昏王室，天地慘慘無顔色。',64,'全唐诗/poet.song.239000.json','["風塵澒洞昏王室，天地慘慘無顔色。", "而今西北自反胡，西望千山萬山赤。", "歎息人間萬事非，被驅不異犬與鷄。", "不知明月爲誰好，來歲如今歸未歸。"]'),
('0bd7c113-ef6f-4612-8a6d-b3c0ed57c3ac','胡笳曲 二拍','文天祥','宋','宋诗','song-poetry','','[]','獨立縹緲之飛樓，高視乾坤又何愁。',64,'全唐诗/poet.song.239000.json','["獨立縹緲之飛樓，高視乾坤又何愁。", "江風蕭蕭雲拂地，笛聲憤怒哀中流。", "鄰鷄野哭如昨日，昨日晚晴今日黑。", "蒼皇已就長途往，欲往城南忘南北。"]'),
('4b49f7f7-c9ae-4a11-912c-0c7a3e12c178','胡笳曲 三拍','文天祥','宋','宋诗','song-poetry','','[]','三年奔走空皮骨，三年笛裏關山月。',64,'全唐诗/poet.song.239000.json','["三年奔走空皮骨，三年笛裏關山月。", "中天月色好誰看，豺狼塞路人煙絕。", "寒刮肌膚北風利，牛馬毛零縮如蝟。", "塞上風雲接地陰，咫尺但愁雷雨至。"]'),
('50c8a080-8c70-4da3-afab-9b8dfbc28855','胡笳曲 四拍','文天祥','宋','宋诗','song-poetry','','[]','黄河北岸海西軍，翻身向天仰射雲。',64,'全唐诗/poet.song.239000.json','["黄河北岸海西軍，翻身向天仰射雲。", "胡馬長鳴不知數，衣冠南渡多崩奔。", "山木慘慘天欲雨，前有毒蛇後猛虎。", "欲問長安無使來，終日戚戚忍羈旅。"]'),
('ed178f51-da5b-4c4d-a5ca-2f85dec4654b','胡笳曲 五拍','文天祥','宋','宋诗','song-poetry','','[]','北庭數有關中使，飄飄遠自流沙至。',64,'全唐诗/poet.song.239000.json','["北庭數有關中使，飄飄遠自流沙至。", "胡人高鼻動成群，仍唱胡歌飲都市。", "中原無書歸不得，道路只今多擁隔。", "身欲奮飛病在床，時獨看雲淚沾臆。"]'),
('c2cd9178-a271-4833-b570-1ee2f34f0abd','胡笳曲 六拍','文天祥','宋','宋诗','song-poetry','','[]','胡人歸來血洗箭，白馬將軍若雷電。',64,'全唐诗/poet.song.239000.json','["胡人歸來血洗箭，白馬將軍若雷電。", "蠻夷雜種錯相干，洛陽宮殿燒焚盡。", "干戈兵革鬭未已，魑魅魍魎徒爲爾。", "慟哭秋原何處村，千村萬落生荆杞。"]'),
('a49ef4ad-168a-4d6a-94c9-513856607fa9','胡笳曲 七拍','文天祥','宋','宋诗','song-poetry','','[]','憶昔十五心尚孩，莫怪頻頻勸酒杯。',64,'全唐诗/poet.song.239000.json','["憶昔十五心尚孩，莫怪頻頻勸酒杯。", "孤城此日腸堪斷，如何不飲令人哀。", "一去紫臺連朔漠，月出雲通雪山白。", "九度附書歸洛陽，故國三年一消息。"]'),
('a0b99253-411a-4c0d-9875-1f127b53c843','胡笳曲 八拍','文天祥','宋','宋诗','song-poetry','','[]','只今年纔十六七，風塵荏苒音書絕。',64,'全唐诗/poet.song.239000.json','["只今年纔十六七，風塵荏苒音書絕。", "胡騎長驅五六年，弊裘何啻連百結。", "愁對寒雲雪滿山，愁看冀北是長安。", "此身未知歸定處，漂泊西南天地間。"]'),
('fa119c43-5290-4052-ab8d-646cc6f75b02','胡笳曲 九拍','文天祥','宋','宋诗','song-poetry','','[]','午夜漏聲催曉箭，寒盡春生洛陽殿。',80,'全唐诗/poet.song.239000.json','["午夜漏聲催曉箭，寒盡春生洛陽殿。", "漢主山河錦繡中，可惜春光不相見。", "自胡之反持干戈，一生抱恨空咨嗟。", "我已無家尋弟妹，此身那得更無家。", "南極一星朝北斗，每依南斗望京華。"]'),
('7964b317-4795-45cc-b28d-cb8ee617231a','胡笳曲 十拍','文天祥','宋','宋诗','song-poetry','','[]','今年臈月凍全消，天涯涕淚一身遥。',64,'全唐诗/poet.song.239000.json','["今年臈月凍全消，天涯涕淚一身遥。", "諸將亦自軍中至，行人弓箭各在腰。", "白馬嚼嚙黄金勒，三尺角弓兩斛力。", "胡雁翅濕高飛難，一箭正墜雙飛翼。"]'),
('ea0f94b4-1732-4f8f-a3c6-a9d45f107851','胡笳曲 十一拍','文天祥','宋','宋诗','song-poetry','','[]','冬至陽生春又來，口雖吟咏心中哀。',64,'全唐诗/poet.song.239000.json','["冬至陽生春又來，口雖吟咏心中哀。", "長笛誰能亂愁思，呼兒且覆掌中杯。", "雲白山青萬餘里，壁立石城橫塞起。", "元戎小隊出郊坰，天寒日暮山谷裏。"]'),
('bebe2d2e-647c-43ae-97c4-6729941d7874','胡笳曲 十二拍','文天祥','宋','宋诗','song-poetry','','[]','洛陽一別四千里，邊庭流血成海水。',64,'全唐诗/poet.song.239000.json','["洛陽一別四千里，邊庭流血成海水。", "自經喪亂少睡眠，手脚凍皴皮肉死。", "反鏁衡門守環堵，稚子無憂走風雨。", "此時與子空歸來，喜得與子長夜語。"]'),
('f955e758-31e2-4fee-a9c5-4f319a1db5d5','胡笳曲 十三拍','文天祥','宋','宋诗','song-poetry','','[]','大兒九齡色清徹，驊騮作駒已汗血。',80,'全唐诗/poet.song.239000.json','["大兒九齡色清徹，驊騮作駒已汗血。", "小兒五歲氣食牛，冰壺玉衡懸清秋。", "罷琴惆悵月照席，人生有情淚沾臆。", "離別不堪無限意，更爲後會知何地。", "酒肉如山又一時，只今未醉已先悲。"]'),
('07bed681-3a97-458a-8519-c6450632507d','胡笳曲 十四拍','文天祥','宋','宋诗','song-poetry','','[]','北歸秦川多鼓鼙，禾生隴畝無東西。',100,'全唐诗/poet.song.239000.json','["北歸秦川多鼓鼙，禾生隴畝無東西。", "三步回頭五步坐，誰家搗練風凄凄。", "已近苦寒月，慘慘中腸悲。", "自恐二男兒，不得相追隨。", "去留俱失意，徘徊感生離。", "十年蹴踘將雛遠，目極傷神誰爲携。", "此別還須各努力，無使霜露沾人衣。"]'),
('38b38fee-ffa8-4510-8442-340204ab853b','胡笳曲 十五拍','文天祥','宋','宋诗','song-poetry','','[]','寒雨颯颯枯樹濕，坐卧只多少行立。',80,'全唐诗/poet.song.239000.json','["寒雨颯颯枯樹濕，坐卧只多少行立。", "青春欲暮急還鄉，非關使者徵求急。", "欲別上馬身無力，去住彼此無消息。", "關塞蕭條行路難，行路難行澀如棘。", "男兒性命絕可憐，十日不一見顔色。"]'),
('efcdc680-a544-4ed7-ab57-c1133758c27e','胡笳曲 十六拍','文天祥','宋','宋诗','song-poetry','','[]','乃知貧賤別更苦，况我飄轉無定所。',88,'全唐诗/poet.song.239000.json','["乃知貧賤別更苦，况我飄轉無定所。", "心懷百憂復千慮，世人那得知其故。", "嬌兒不離膝，哀哉兩决絕。", "也復可憐人，里巷盡嗚咽。", "斷腸分手各風煙，中間消息兩茫然。", "自斷此生休問天，看射猛虎終殘年。"]'),
('459afa7f-43c7-4707-a9d6-f953445515a1','胡笳曲 十七拍','文天祥','宋','宋诗','song-poetry','','[]','江頭宮殿鎖千門，千家今有百家存。',60,'全唐诗/poet.song.239000.json','["江頭宮殿鎖千門，千家今有百家存。", "面粧首飾雜啼痕，教我歎恨傷精魂。", "自有兩兒郎，忽在天一方。", "胡塵暗天道路長，安得送我置汝傍。"]'),
('de398328-8f8d-4568-b56b-381c5608b236','胡笳曲 十八拍','文天祥','宋','宋诗','song-poetry','','[]','事殊興極憂思集，足繭荒山轉愁疾。',64,'全唐诗/poet.song.239000.json','["事殊興極憂思集，足繭荒山轉愁疾。", "漢家山東二百州，青是烽煙白人骨。", "入門依舊四壁空，一斛舊水藏蛟龍。", "年過半百不稱意，此曲哀怨何時終。"]'),
('03f59283-9279-405b-b290-d7286734cee6','上巳','文天祥','宋','宋诗','song-poetry','','[]','昔自長淮樹去帆，今從燕薊眺東南。',64,'全唐诗/poet.song.239000.json','["昔自長淮樹去帆，今從燕薊眺東南。", "泥沙一命九分九，風雨六年三月三。", "地下故人那可作，天涯遊子竟何堪。", "便從餓死傷遲暮，面對西山已發慚。"]'),
('17a9e8df-9b27-4692-93c0-9fbbb00f4447','寒食','文天祥','宋','宋诗','song-poetry','','[]','苦海周遭斷去帆，東風吹淚向天南。',64,'全唐诗/poet.song.239000.json','["苦海周遭斷去帆，東風吹淚向天南。", "龍蛇澤裏清明五，燕雀籠中寒食三。", "撲面風沙驚我在，滿襟霜露痛誰堪。", "何當歸骨先人墓，千古不爲丘首慚。"]'),
('db5d1021-6718-4d71-aad9-b53dd3e4148b','覽鏡見鬚髯消落爲之流涕','文天祥','宋','宋诗','song-poetry','','[]','萬里飄零等一毫，滿前風景恨滔滔。',64,'全唐诗/poet.song.239000.json','["萬里飄零等一毫，滿前風景恨滔滔。", "淚如杜宇喉中血，鬚似蘇郎節上旄。", "今日形骸遲一死，向來事業竟徒勞。", "青山是我安魂處，清夢時時賦大刀。"]'),
('9499826b-245e-401d-b866-479dd50c3285','讀赤壁賦前後二首  其一','文天祥','宋','宋诗','song-poetry','','[]','昔年仙子謫黄州，赤壁磯頭汗漫遊。',64,'全唐诗/poet.song.239000.json','["昔年仙子謫黄州，赤壁磯頭汗漫遊。", "今古興亡真過影，乾坤俯仰一虛舟。", "人間憂患何曾少，天上風流更有不。", "我亦洞簫吹一曲，不知身世是蜉蝣。"]'),
('d1deff8d-8ed0-43ac-ab1b-7056f5faf258','讀赤壁賦前後二首  其二','文天祥','宋','宋诗','song-poetry','','[]','一笑滄波浩浩流，隻鷄斗酒更扁舟。',64,'全唐诗/poet.song.239000.json','["一笑滄波浩浩流，隻鷄斗酒更扁舟。", "八龍寫作詩中案，孤鶴來爲夢裏遊。", "楊柳遠煙連北府，蘆花新月對南樓。", "玉仙來往清風夜，還識江山似舊不。"]'),
('d195d915-5219-4e47-84a5-a4b9f8db6d6b','自歎','文天祥','宋','宋诗','song-poetry','','[]','門揜牢愁白日過，不應老子坐婆娑。',64,'全唐诗/poet.song.239000.json','["門揜牢愁白日過，不應老子坐婆娑。", "雖生得似無生好，欲死其如不死何。", "王蠋高風真可挹，魯連大節豈容磨。", "東流不盡銅駝恨，四海悠悠總一波。"]'),
('1e52fd12-6ade-4f80-94b4-9742050b3cd7','端午初度  其一','文天祥','宋','宋诗','song-poetry','','[]','死所初何怨，生朝只自知。',48,'全唐诗/poet.song.239000.json','["死所初何怨，生朝只自知。", "頗懷常杕意，忍誦蓼莪詩。", "浮世百年夢，高人千載期。", "楚囚一杯水，勝似九霞巵。"]'),
('ac99c621-0927-46b5-81be-f59b56f3741d','端午初度  其二','文天祥','宋','宋诗','song-poetry','','[]','向來松下鶴，今日傍誰門。',48,'全唐诗/poet.song.239000.json','["向來松下鶴，今日傍誰門。", "夢見瑶池沸，愁看玉壘昏。", "所思多死所，焉用獨生存。", "可惜菖蒲老，風煙滿故園。"]'),
('2bf53b01-1ef2-475d-a64c-ac201149c65a','端午即事','文天祥','宋','宋诗','song-poetry','','["\u65e0\u5948", "\u58ee\u5fd7", "\u7aef\u5348\u8282"]','五月五日午，贈我一枝艾。',48,'全唐诗/poet.song.239000.json','["五月五日午，贈我一枝艾。", "故人不可見，新知萬里外。", "丹心照夙昔，鬢髮日已改。", "我欲從靈均，三湘隔遼海。"]'),
('bd8d22d9-0241-45ba-9abd-28441145bb8c','自述二首  其一','文天祥','宋','宋诗','song-poetry','','[]','當年嚼血灑銅駝，風氣悠悠柰若何。',64,'全唐诗/poet.song.239000.json','["當年嚼血灑銅駝，風氣悠悠柰若何。", "漢賊已成千古恨，楚囚不覺二年過。", "古今咸道天驕子，老去忽如春夢婆。", "試把睢陽雙廟看，只今事業愧蹉跎。"]'),
('407ef4ee-9418-4f80-998e-b1cd9452ef26','自述二首  其二','文天祥','宋','宋诗','song-poetry','','[]','江南啼血送殘春，漂泊風沙萬里身。',64,'全唐诗/poet.song.239000.json','["江南啼血送殘春，漂泊風沙萬里身。", "漢末固應多死士，周餘乃止一遺民。", "乍看鬚少疑非我，只要心存尚是人。", "坐擁牢愁書眼倦，土床伸脚任吾真。"]'),
('613837d6-1b56-4389-8515-6e96c4f79638','五月十七夜大雨歌','文天祥','宋','宋诗','song-poetry','','[]','去年五月望，流水滿一房。',288,'全唐诗/poet.song.239000.json','["去年五月望，流水滿一房。", "今年後三夕，大雨復沒床。", "我辭江海來，中原路茫茫。", "舟楫不復見，車馬馳康莊。", "矧居圜土中，得水猶得漿。", "忽如巨石浸，倉卒殊徬徨。", "明星尚未啟，大風方發狂。", "叫呼人不譍，宛轉水中央。", "壁下有水穴，群鼠走踉蹡。", "或如魚潑剌，墊溺無所藏。", "周身莫如物，患至不得防。", "業爲世間人，何處逃禍殃。", "朝來闢溝道，宛如决陂塘。", "盡室泥濘塗，化爲糜爛場。", "炎蒸迫其上，臭腐薰其傍。", "惡氣所侵薄，疫癘何可當。", "楚囚欲何之，寢食此一方。", "羈棲無復望，坐待仆且僵。", "乾坤莽空闊，何爲此凉凉。", "達人識義命，此事關綱常。", "萬物方焦枯，皇皇禱穹蒼。", "上帝實好生，夜半下龍章。", "但願天下人，家家足稻粱。", "我命渾小事，我死庸何傷。"]'),
('d1d3214c-250c-4f66-9dcf-22fb400fafc8','先太師忌日','文天祥','宋','宋诗','song-poetry','','[]','萬里先人忌，呼號痛不天。',48,'全唐诗/poet.song.239000.json','["萬里先人忌，呼號痛不天。", "遺孤餘二紀，曠祀忽三年。", "永恨丘園隔，遥憐弟妹圓。", "義方如昨日，地下想欣然。"]'),
('3b4a04a3-fe5d-465e-a94b-d1ac83358a26','築房子歌','文天祥','宋','宋诗','song-poetry','','[]','自予居狴犴，一室以自治。',168,'全唐诗/poet.song.239000.json','["自予居狴犴，一室以自治。", "二年二大雨，地汙實成池。", "圄人爲我惻，畚土以築之。", "築之可二尺，宛然水中坻。", "初運朽壤來，臭穢恨莫追。", "掩鼻不可近，牛皂鷄于塒。", "須臾傳黑墳，千杵鳴參差。", "但見如坻平，糞土不復疑。", "乃知天下事，不在論鎡基。", "苟可掩耳目，臭腐誇神奇。", "世人所不辨，羊質而虎皮。", "大者莫不然，小者又何知。", "深居守我玄，默觀道推移。", "何時蟬蛻去，忽與濁世違。"]'),
('d1907819-18ed-4c82-b100-b910a4039290','有感','文天祥','宋','宋诗','song-poetry','','[]','已矣勿復道，安之如自然。',48,'全唐诗/poet.song.239000.json','["已矣勿復道，安之如自然。", "閑陪黄嬭坐，倦退白衣眠。", "一死知何地，此生休問天。", "怪哉茨野客，宿果墮幽燕。"]'),
('7941d749-f11b-4b1f-88ee-46fbd1f52458','正氣歌','文天祥','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u548f\u53f2\u6000\u53e4", "\u5b8b\u30fb\u8fbd\u30fb\u91d1\u30fb\u5143"]','天地有正氣，雜然賦流形。',288,'全唐诗/poet.song.239000.json','["天地有正氣，雜然賦流形。", "下則爲河嶽，上則爲日星。", "於人曰浩然，沛乎塞蒼冥。", "皇路當清夷，含和吐明庭。", "時窮節乃見，一一垂丹青。", "在齊太史簡，在晉董狐筆。", "在秦張良椎，在漢蘇武節。", "爲嚴將軍頭，爲嵇侍中血。", "爲張睢陽齒，爲顔常山舌。", "或爲遼東帽，清操厲冰雪。", "或爲出師表，鬼神泣壯烈。", "或爲渡江楫，慷慨吞胡羯。", "或爲擊賊笏，逆豎頭破裂。", "是氣所旁薄，凜烈萬古存。", "當其貫日月，生死安足論。", "地維頼以立，天柱頼以尊。", "三綱實係命，道義爲之根。", "嗟予遘陽九，隸也實不力。", "楚囚纓其冠，傳車送窮北。", "鼎鑊甘如飴，求之不可得。", "陰房閴鬼火，春院閟天黑。", "牛驥同一皂，鷄棲鳳凰食。", "一朝濛霧露，分作溝中瘠。", "如此再寒暑，百沴自辟易。"]'),
('38f7b0e4-07e2-4e63-ae5d-de1eca5f8a88','七月二日大雨歌','文天祥','宋','宋诗','song-poetry','','[]','燕山五六月，氣候苦不常。',288,'全唐诗/poet.song.239000.json','["燕山五六月，氣候苦不常。", "積陰綿五旬，畏景淡無光。", "天漏比西極，地濕等南方。", "今何苦常雨，昔何苦常暘。", "七月二日夜，天工爲誰忙。", "浮雲黑如墨，飄風怒如狂。", "滂沱至夜半，天地爲低昂。", "勢如蛟龍出，平陸俄懷襄。", "初疑倒巫峽，又似翻瀟湘。", "千門各已閉，仰視天茫茫。", "但聞屋側聲，人力無支當。", "嗟哉此圜土，占勝非高岡。", "赭衣無容足，南房并北房。", "北房水二尺，聚立唯東箱。", "桎梏猶自可，凜然覆穹牆。", "嘈嘈復雜雜，烝汗流成漿。", "張目以待旦，沈沈漏何長。", "南冠者爲誰，獨居沮洳場。", "此夕水彌滿，浮動八尺床。", "壁老如欲壓，守者殊皇皇。", "我方鼾鼻睡，逍遥遊帝鄉。", "百年一大夢，所歷皆黄粱。", "死生已勘破，身世如遺忘。", "雄鷄叫東白，漸聞語聲揚。"]'),
('09e81716-8b66-4868-8abc-45b735b77e6d','詠懷','文天祥','宋','宋诗','song-poetry','','[]','陰陽相烹然，天地一釜鬵。',180,'全唐诗/poet.song.239000.json','["陰陽相烹然，天地一釜鬵。", "人生居其間，便同肉在砧。", "熱猶以火燎，濕猶以湯潯。", "一歲一煅煉，老形忽駸駸。", "吾生四十六，弱質本不任。", "矧當五六年，患難長侵尋。", "子卿羝羊節，少陵杜鵑心。", "酷罰毒我膚，深憂煩我襟。", "嗟嗟夏涉秋，天道何其淫。", "或時日杲杲，或時雨淋淋。", "方如坐蒸甑，又似立烘煁。", "水火交相禪，益熱與益深。", "宛轉兒戲中，日夜空呻吟。", "何如真鼎鑊，殊我一寸金。", "脫此寒暑殻，誰能復嶇嶔。"]'),
('14dec3b8-ae29-4f70-93ab-f005f73dcd81','偶成','文天祥','宋','宋诗','song-poetry','','[]','昨朝門前地寸裂，今朝床下泥尺深。',64,'全唐诗/poet.song.239000.json','["昨朝門前地寸裂，今朝床下泥尺深。", "人生世間一蒲柳，豈堪日炙復雨淋。", "起來高歌離騷賦，睡去細和梁父吟。", "已矣已矣尚何道，猶有天地知吾心。"]'),
('b6aa4bbd-6a39-4999-b415-747bbd4294bb','移司即事','文天祥','宋','宋诗','song-poetry','','[]','燕山積雨泥塞道，大屋欹傾小成倒。',128,'全唐诗/poet.song.239000.json','["燕山積雨泥塞道，大屋欹傾小成倒。", "赭衣棘下無顔色，倉卒移司避流潦。", "行行桎梏如貫魚，憐我龍鍾遲明早。", "我來二十有一月，若書下下幾一考。", "夢回恍憶入新衙，不知傳舍何時了。", "寄書癡兒了家事，九牛一毛亦云小。", "天門皇皇虎豹立，下土孤臣泣雲表。", "莫令赤子盡爲魚，早願當空日杲杲。"]'),
('a49d08dc-4a35-49ab-839d-418f47160bc2','不睡','文天祥','宋','宋诗','song-poetry','','[]','頻搔白首强憂煎，細雨青燈思欲顛。',64,'全唐诗/poet.song.239000.json','["頻搔白首强憂煎，細雨青燈思欲顛。", "南北東西三萬里，古今上下幾千年。", "只因知事翻成惱，未到放心那得眠。", "眼不識丁馬前卒，隔床鼾鼻正陶然。"]'),
('dcc23d4f-0b11-4516-b1a8-ef0d68ae2a49','宮籍監  其一','文天祥','宋','宋诗','song-poetry','','[]','塵滿南冠歲月深，蹔移一室倚旃林。',32,'全唐诗/poet.song.239000.json','["塵滿南冠歲月深，蹔移一室倚旃林。", "天憐元是青山客，分與窗根兩樹陰。"]'),
('27c52f4f-970a-4307-b7b4-0731dbe11d25','宮籍監  其二','文天祥','宋','宋诗','song-poetry','','[]','壁間頗自有龍蛇，元是誰人小住家。',32,'全唐诗/poet.song.239000.json','["壁間頗自有龍蛇，元是誰人小住家。", "不似爲囚似爲客，倚窗望斷暮天涯。"]'),
('95792b00-167a-4fbb-8133-609fdfc5436c','宮籍監  其三','文天祥','宋','宋诗','song-poetry','','[]','曾過盧溝望塔尖，今朝塔影接虛簷。',32,'全唐诗/poet.song.239000.json','["曾過盧溝望塔尖，今朝塔影接虛簷。", "道人心事真方丈，靜坐日長雲滿簾。"]'),
('dc86f393-af4c-4d9a-8a3f-84697faad245','宮籍監  其四','文天祥','宋','宋诗','song-poetry','','[]','軍衙馬足起黄埃，門掩西風夢正回。',32,'全唐诗/poet.song.239000.json','["軍衙馬足起黄埃，門掩西風夢正回。", "自入燕關人世隔，隔牆忽送市聲來。"]'),
('38edd6a6-6f5a-4df9-a550-3859442439d1','宮籍監  其五','文天祥','宋','宋诗','song-poetry','','[]','新來窗壁頗玲瓏，盡把前時臭腐空。',32,'全唐诗/poet.song.239000.json','["新來窗壁頗玲瓏，盡把前時臭腐空。", "好醜元來都是幻，蘧廬一付夢魂中。"]'),
('c72b183a-1241-4e9a-9555-a6d00658fb04','還司即事  其一','文天祥','宋','宋诗','song-poetry','','[]','幙燕方如寄，屠羊忽復旋。',48,'全唐诗/poet.song.239000.json','["幙燕方如寄，屠羊忽復旋。", "霜枝空獨立，雪窖已三遷。", "漂泊知何所，逍遥付自然。", "庭空誰共語，拄頰望青天。"]'),
('aa7d7315-83bd-4b51-8298-49f30689cc3f','還司即事  其二','文天祥','宋','宋诗','song-poetry','','[]','秋聲滿南國，一葉此飄蓬。',48,'全唐诗/poet.song.239000.json','["秋聲滿南國，一葉此飄蓬。", "牆外千門逈，庭皋四壁空。", "誰家馿吼月，隔巷犬嘷風。", "燈暗人無寐，沉沉夜正中。"]'),
('09b672b1-54a7-42c9-9d66-757a4d50b019','夜起二絕  其一','文天祥','宋','宋诗','song-poetry','','[]','惆悵高歌入睡鄉，夢中魂魄尚飛揚。',32,'全唐诗/poet.song.239000.json','["惆悵高歌入睡鄉，夢中魂魄尚飛揚。", "起來露立頻搔首，夜靜無風自在凉。"]'),
('cd342b23-9035-4561-a0fb-453cde2d6031','夜起二絕  其二','文天祥','宋','宋诗','song-poetry','','[]','三年獨立已成僧，欲與何人說葛藤。',32,'全唐诗/poet.song.239000.json','["三年獨立已成僧，欲與何人說葛藤。", "夜夜隔牆囚叫佛，三生因果伴孤燈。"]'),
('c4f17c9d-ffac-48c4-98a6-ab4336129ec0','還獄','文天祥','宋','宋诗','song-poetry','','[]','人情感故物，百年多離憂。',156,'全唐诗/poet.song.239000.json','["人情感故物，百年多離憂。", "桑下住三宿，應者猶遲留。", "矧茲方丈室，屏居二春秋。", "夜眠與晝坐，隤乎安楚囚。", "自罹大雨水，圜土俱盪舟。", "此身委傳舍，遷徙無定謀。", "去之已旬月，宮室重綢繆。", "今夕果何夕，復此搔白頭。", "恍如流浪人，一旦歸舊遊。", "故家不可復，故國已成丘。", "對此重回首，汪然涕泗流。", "人生如空花，隨風任飄浮。", "哲人貴知命，樂天復何求。"]'),
('d4752fd3-83dc-438b-8796-8d722efc7c4f','偶賦','文天祥','宋','宋诗','song-poetry','','[]','蒼蒼已如此，梁父共誰吟。',48,'全唐诗/poet.song.239000.json','["蒼蒼已如此，梁父共誰吟。", "袖有忠臣傳，床無壯士金。", "收心歸寂滅，隨性過光陰。", "一笑西山晚，門前秋雨深。"]'),
('fef078fb-043d-4b1c-9bd1-a37f3578fa8d','讀杜詩','文天祥','宋','宋诗','song-poetry','','[]','平生蹤跡只奔波，偏是文章被折磨。',64,'全唐诗/poet.song.239000.json','["平生蹤跡只奔波，偏是文章被折磨。", "耳想杜鵑心事苦，眼看胡馬淚痕多。", "千年夔峽有詩在，一夜耒江如酒何。", "黄土一丘隨處是，故鄉歸骨任蹉跎。"]'),
('dac72adb-34f3-46a9-b5dc-dd1186f106c0','感懷二首  其一','文天祥','宋','宋诗','song-poetry','','[]','交遊兵後似蓬飛，流落天涯鵲繞枝。',64,'全唐诗/poet.song.239000.json','["交遊兵後似蓬飛，流落天涯鵲繞枝。", "唐室老臣唯我在，柳州先友託誰碑。", "泥塗猶幸瞻佳士，甘雨如何遇故知。", "一死一生情義重，莫嫌收拾老牛屍。"]'),
('911891b3-c16b-49f1-acb2-566c3fc66954','感懷二首  其二','文天祥','宋','宋诗','song-poetry','','[]','伏龍欲夾太陽飛，獨柱擎天力弗支。',64,'全唐诗/poet.song.239000.json','["伏龍欲夾太陽飛，獨柱擎天力弗支。", "北海風沙漫漢節，浯溪烟雨暗唐碑。", "書空已恨天時去，惜往徒懷國士知。", "抱膝對人復何語，紛紛坐冢卧爲屍。"]'),
('2aabf5d2-263d-4240-bb8f-fdce93fc8028','先兩國初忌','文天祥','宋','宋诗','song-poetry','','[]','北風吹黄花，落木寒蕭颼。',288,'全唐诗/poet.song.239000.json','["北風吹黄花，落木寒蕭颼。", "哀哀我慈母，玉化炎海秋。", "日月水東流，音容隔悠悠。", "小祥哭下邳，大祥哭幽州。", "今此復何夕，荏苒三星周。", "嗟哉不肖孤，宗職曠不修。", "昔母肉未寒，委身墮寇讎。", "仰藥早云遂，庶從地下遊。", "太阿落人手，死生不自由。", "南冠坐絕域，大期落淹流。", "白華下玄髮，碧蘇生緇裘。", "心口自相語，形影旁無儔。", "空庭鬼火閴，天黑對牢愁。", "魚軒在何處，魂魄今安否。", "兒女各北歸，墳墓委南陬。", "寒食雨凄凄，盂飯誰與投。", "荆棘纏蔓草，狐兔緣荒丘。", "長夜良寂寞，與我同幽幽。", "我心亦勞止，我命實不猶。", "昨夕夢堂上，樂昔歡綢繆。", "覺來尚恍惚，血涕連衾禂。", "晨興一瓣香，痛如螫在頭。", "吾家白雲下，萬里同關憂。", "遥憐弟與妹，几筵羅庶羞。"]'),
('0dc5b047-c572-43ce-a1c7-0e8ed53c62db','重陽','文天祥','宋','宋诗','song-poetry','','[]','萬里飄零兩鬢蓬，故鄉秋色老梧桐。',64,'全唐诗/poet.song.239000.json','["萬里飄零兩鬢蓬，故鄉秋色老梧桐。", "雁棲新月江湖滿，燕別斜陽巷陌空。", "落葉何心定流水，黄花無主更西風。", "乾坤遺恨知多少，前日龍山如夢中。"]'),
('d59a0c8d-3ec6-4ad9-958f-6fe747a3277a','又三絕  其一','文天祥','宋','宋诗','song-poetry','','[]','世事濛濛醉不知，南山秋意滿東籬。',32,'全唐诗/poet.song.239000.json','["世事濛濛醉不知，南山秋意滿東籬。", "黄花何故無顔色，應爲元嘉以後詩。"]'),
('a9a1af25-f7a0-40f9-887e-fedc3920122f','又三絕  其二','文天祥','宋','宋诗','song-poetry','','[]','人間萬事轉頭空，皂帽飄蕭一病翁。',32,'全唐诗/poet.song.239000.json','["人間萬事轉頭空，皂帽飄蕭一病翁。", "不學孟嘉狂落魄，故將白髮向西風。"]'),
('19d05eca-59d7-4951-843d-415dbfa13344','又三絕  其三','文天祥','宋','宋诗','song-poetry','','[]','老來憂患易凄凉，說到悲秋更斷腸。',32,'全唐诗/poet.song.239000.json','["老來憂患易凄凉，說到悲秋更斷腸。", "世事不堪逢九九，休言今日是重陽。"]'),
('4d4f9d97-98f8-40c7-8df8-184931d13726','夜','文天祥','宋','宋诗','song-poetry','','[]','秋光連夜色，萬里客凄凄。',48,'全唐诗/poet.song.239000.json','["秋光連夜色，萬里客凄凄。", "落木空山杳，孤雲故國迷。", "衾寒霜正下，燈晚月平西。", "夢過重成夢，千門鷄亂啼。"]'),
('2b159495-52fb-4d4c-8655-dfdd3b2e0814','雨雪','文天祥','宋','宋诗','song-poetry','','[]','秋色金臺路，殷殷半馬蹄。',48,'全唐诗/poet.song.239000.json','["秋色金臺路，殷殷半馬蹄。", "因風隨作雪，有雨便成泥。", "過眼驚新夢，傷心憶舊題。", "江雲愁萬疊，遺恨鷓鴣啼。"]'),
('bf334732-38b6-4b2b-b9df-fdb0c10e8b58','偶成二首  其一','文天祥','宋','宋诗','song-poetry','','[]','燈影沉沉夜氣清，朔風吹夢度江城。',32,'全唐诗/poet.song.239000.json','["燈影沉沉夜氣清，朔風吹夢度江城。", "覺來知打明鐘未，忽聽鄰家叫佛聲。"]'),
('eb5f23e0-8ee2-4d61-80ef-f80a58c14e9a','偶成二首  其二','文天祥','宋','宋诗','song-poetry','','[]','烏兔東西不住天，平生奔走亦茫然。',32,'全唐诗/poet.song.239000.json','["烏兔東西不住天，平生奔走亦茫然。", "向來鞅掌真堪笑，爛熳如今獨自眠。"]'),
('94a4ce1c-b712-4366-8ba8-3599fcaa7b0f','得兒女消息','文天祥','宋','宋诗','song-poetry','','[]','故國斜陽草自春，爭元作相總成塵。',64,'全唐诗/poet.song.239000.json','["故國斜陽草自春，爭元作相總成塵。", "孔明已負金刀志，元亮猶憐典午身。", "骯髒到頭方是漢，娉婷更欲向何人。", "癡兒莫問今生計，還種來生未了因。"]'),
('56fb09fd-a58c-4a68-ae10-d15f44e26277','爲或人賦','文天祥','宋','宋诗','song-poetry','','[]','悠悠成敗百年中，笑看柯山局未終。',64,'全唐诗/poet.song.239000.json','["悠悠成敗百年中，笑看柯山局未終。", "金馬勝遊成舊雨，銅駝遺恨付西風。", "黑頭爾自誇江總，冷齒人能說褚公。", "龍首黄扉真一夢，夢回何面見江東。"]'),
('6ae79dd8-3c92-4a43-9c64-a4002dfb01bd','世事','文天祥','宋','宋诗','song-poetry','','[]','世事孤鴻外，人生落日西。',48,'全唐诗/poet.song.239000.json','["世事孤鴻外，人生落日西。", "棋淫詩興薄，書倦夢魂迷。", "汩汩馳還坐，悠悠笑即啼。", "一真吾自得，開眼總筌蹄。"]'),
('7d2214c5-bd1f-410e-9565-8f588cf81c66','斷雁','文天祥','宋','宋诗','song-poetry','','[]','斷雁西江遠，無家寄萬金。',48,'全唐诗/poet.song.239000.json','["斷雁西江遠，無家寄萬金。", "乾坤風月老，沙漠歲年深。", "白日去如夢，青天知此心。", "素琴弦已絕，不絕是南音。"]'),
('bca390aa-88d4-4c95-8e18-b9b137feecc8','小年','文天祥','宋','宋诗','song-poetry','','[]','燕朔逢窮臘，江南拜小年。',48,'全唐诗/poet.song.239000.json','["燕朔逢窮臘，江南拜小年。", "歲時生處樂，身世死爲緣。", "鴉噪千山雪，鴻飛萬里天。", "出門意寥廓，四顧但茫然。"]'),
('cb8a66e3-5f2d-49e0-b27a-3b766da327a6','除夜','文天祥','宋','宋诗','song-poetry','','["\u8282\u65e5", "\u6625\u8282"]','乾坤空落落，歲月去堂堂。',48,'全唐诗/poet.song.239000.json','["乾坤空落落，歲月去堂堂。", "末路驚風雨，窮邊飽雪霜。", "命隨年欲盡，身與世俱忘。", "無復屠蘇夢，挑燈夜未央。"]'),
('b9ee6224-a6f5-426d-a23f-a1116e086bec','壬午','文天祥','宋','宋诗','song-poetry','','[]','憶昔三月朔，歲在火鼠鄉。',288,'全唐诗/poet.song.239000.json','["憶昔三月朔，歲在火鼠鄉。", "朝登迎鑾鎮，夜宿清邊堂。", "于時坌飆霧，陽精黯無芒。", "胡羯犯彤宮，犬戎升御床。", "慘淡銅駝泣，威垂朱鳥翔。", "我欲疏河嶽，借助金與湯。", "吾道率曠野，繞樹空徬徨。", "慷慨撫鰲背，艱關出羊腸。", "扶日上天門，隨雲拜東皇。", "祖逖誓興晉，鄭畋義扶唐。", "人謀豈云及，天命不于常。", "泗水沉洛鼎，薊丘植汶篁。", "瑶宮可敦后，玉陛單于王。", "革命曠千古，被髮綿八荒。", "海流忽西注，天旋俄右方。", "嗟予俘爲馘，萬里勞梯航。", "秋風上甌脫，夜雪卧桁楊。", "南冠鄭大夫，北窖蘇中郎。", "龍蛇共窟穴，蟻蝨連衣裳。", "周旋溲勃間，宛轉沮洳場。", "漠漠蒼天黑，悠悠白日黄。", "風埃滿沙漠，歲月稔星霜。", "地下雙氣烈，獄中孤憤長。", "唯存葵藿心，不改鐵石腸。"]'),
('53857c56-aa9e-46da-9fd1-494dd0b72161','生日','文天祥','宋','宋诗','song-poetry','','[]','憶昔閑居日，端二逢始生。',288,'全唐诗/poet.song.239000.json','["憶昔閑居日，端二逢始生。", "升堂拜親壽，摳衣接賓榮。", "載酒出郊去，江花相送迎。", "詩歌和盈軸，鏗戛金石聲。", "于時果何時，朝野方休明。", "人生足自樂，帝力無能名。", "譬如江海魚，與水俱忘情。", "詎知君父恩，天地同生成。", "旄頭忽墮地，氛霧迷三精。", "黄屋朔風捲，園林殺氣平。", "四海靡所騁，三年老于行。", "賓僚半蕩覆，妻子同飄零。", "無幾哭慈母，有頃遭潰兵。", "束兵獻穹帳，囚首送空囹。", "痛甚衣冠烈，甘於鼎鑊烹。", "死生久已定，寵辱安足驚。", "不圖坐羅網，四見槐雲青。", "朱顔日復少，玄髮益以星。", "往事真蕉鹿，浮名一草螢。", "牢愁寫玄語，初度感騷經。", "朝登蓬萊門，暮涉芙蓉城。", "忽復臨故國，摇摇我心旌。", "想見家下人，念我涕爲傾。", "交朋說疇昔，惆悵鷄豚盟。"]'),
('7a020d31-15d7-4050-8665-a3029e99ddb0','端午','文天祥','宋','宋诗','song-poetry','','[]','五月五日午，薰風自南至。',168,'全唐诗/poet.song.239000.json','["五月五日午，薰風自南至。", "試爲問大鈞，舉杯三酹地。", "田文當日生，屈原當日死。", "生爲薛城君，死作汨羅鬼。", "高堂狐兔遊，雍門發悲涕。", "人命草頭露，榮華風過耳。", "唯有烈士心，不隨水俱逝。", "至今荆楚人，江上年年祭。", "不知生者榮，但知死者貴。", "勿謂死可憎，勿謂生可喜。", "萬物皆有盡，不滅唯天理。", "百年如一日，一日或千歲。", "秋風汾水辭，春暮蘭亭記。", "莫作留連悲，高歌舞槐翠。"]'),
('a9aa441b-5b18-4b7c-a963-897fc1e83005','自歎三首  其一','文天祥','宋','宋诗','song-poetry','','[]','猛思身世事，四十七年無。',48,'全唐诗/poet.song.239000.json','["猛思身世事，四十七年無。", "鶴髮俄然在，鸞飛久已殂。", "二兒化成土，六女掠爲奴。", "只有南冠在，何妨是丈夫。"]'),
('3798d63b-82d1-4c05-9933-5f8767c11c5f','自歎三首  其二','文天祥','宋','宋诗','song-poetry','','[]','北轍更寒暑，南冠幾晦冥。',48,'全唐诗/poet.song.239000.json','["北轍更寒暑，南冠幾晦冥。", "家山時入夢，妻子亦關情。", "惆悵心如失，崎嶇命復輕。", "遭時命如此，薄分笑三生。"]'),
('dca7aace-e938-4a32-92c9-e648dcb3194d','自歎三首  其三','文天祥','宋','宋诗','song-poetry','','[]','疾病連三次，形容落九分。',48,'全唐诗/poet.song.239000.json','["疾病連三次，形容落九分。", "幾成白宰相，誰識故將軍。", "暗坐羞紅日，閑眠想白雲。", "蒼蒼竟何意，未肯喪斯文。"]'),
('11ade4c7-c8fc-4b85-a716-741fcea91f40','病目二首  其一','文天祥','宋','宋诗','song-poetry','','[]','近來煩惱障，左目忽茫茫。',48,'全唐诗/poet.song.239000.json','["近來煩惱障，左目忽茫茫。", "聶政心雖碎，劉伶醉未忘。", "問天天不應，食日日何傷。", "萬想由來假，收拾太乙光。"]'),
('ba926a6c-2fb0-4d14-844e-bf63c2b0715e','病目二首  其二','文天祥','宋','宋诗','song-poetry','','[]','向來巖下電，無故眩生花。',48,'全唐诗/poet.song.239000.json','["向來巖下電，無故眩生花。", "達磨面向壁，盧仝□塌沙。", "燈前心欲碎，鏡裏鬢空華。", "何日看明月，沈沈斗柄斜。"]'),
('e7156b69-7402-4ecf-a98e-18cb6f20f062','有感','文天祥','宋','宋诗','song-poetry','','[]','心在六虛外，不知身網羅。',48,'全唐诗/poet.song.239000.json','["心在六虛外，不知身網羅。", "病中長日過，夢裏好時多。", "夜夜頻能坐，時時亦自歌。", "平生此光景，回首笑呵呵。"]'),
('9ee46ae0-aa46-4099-af05-6878256bbc4c','早起','文天祥','宋','宋诗','song-poetry','','[]','曉日半窗紅，鄰鷄振翼雄。',48,'全唐诗/poet.song.239000.json','["曉日半窗紅，鄰鷄振翼雄。", "餘子貪慵睡，佳人理髮蓬。", "未忘塵俗慮，那免是非攻。", "前山渾不見，籠翠霧烟中。"]'),
('255185b5-4f6d-4687-b45a-888b2117d7c9','贈許柏溪惟一','文天祥','宋','宋诗','song-poetry','','[]','長風吹飛藿，蜻蛚吟野草。',72,'全唐诗/poet.song.239000.json','["長風吹飛藿，蜻蛚吟野草。", "流光速代謝，興懷令人老。", "遊子中夜起，悠悠酣且歌。", "明月委清照，江湖秋涉多。", "豈無臨淄魚，亦有邯鄲酒。", "懷古招王孫，登高重回首。"]'),
('0995ef42-a948-491d-b83f-b18d7d272d98','生朝','文天祥','宋','宋诗','song-poetry','','[]','客中端二日，風雨送牢愁。',48,'全唐诗/poet.song.239000.json','["客中端二日，風雨送牢愁。", "昨歲猶潘母，今年更楚囚。", "田園荒吉水，妻子老幽州。", "莫作長生祝，吾心在首丘。"]'),
('0b761060-ed26-4d6f-a548-0a7f9ec6ee69','西瓜吟','文天祥','宋','宋诗','song-poetry','','[]','拔出金佩刀，斫破蒼玉瓶。',56,'全唐诗/poet.song.239000.json','["拔出金佩刀，斫破蒼玉瓶。", "千點紅櫻桃，一團黄水晶。", "下咽頓除烟火氣，入齒便作冰雪聲。", "長安清富說邵平，爭如漢朝作公卿。"]'),
('131ab8c8-af5d-49bf-baf1-7d58046539af','石三峰爲示十字云昔日乘龍貴今朝汗馬勞爲足六句','文天祥','宋','宋诗','song-poetry','','[]','雲低昏海日，風急沸洪濤。',48,'全唐诗/poet.song.239000.json','["雲低昏海日，風急沸洪濤。", "昔日乘龍貴，今朝汗馬勞。", "紈綺汙塵土，珠玉委蓬蒿。", "若作凄然賦，吾將僕命騷。"]'),
('31ec4de2-4dff-4e3d-8282-8b420c09c9dc','蚤秋','文天祥','宋','宋诗','song-poetry','','[]','寒魄澹玄河，商飆慓明發。',48,'全唐诗/poet.song.239000.json','["寒魄澹玄河，商飆慓明發。", "羈人坐環堵，壯士衣穿褐。", "晉陵誰復新，秦陵尚云秣。", "夫君百世心，患不在饑渴。"]'),
('bebd68f6-093c-47f8-bd97-9ee783e70839','寄惠州弟','文天祥','宋','宋诗','song-poetry','','[]','五十年兄弟，一朝生別離。',48,'全唐诗/poet.song.239000.json','["五十年兄弟，一朝生別離。", "雁行長已矣，馬足遠何之。", "葬骨知無地，論心更有誰。", "親喪君自盡，猶子是吾兒。"]'),
('a4f61f41-d61e-44fa-b7b9-273bc95f71c0','感傷','文天祥','宋','宋诗','song-poetry','','[]','地維傾渤澥，天柱折崑崙。',48,'全唐诗/poet.song.239000.json','["地維傾渤澥，天柱折崑崙。", "清夜爲揮淚，白雲空斷魂。", "死生蘇子節，貴賤翟公門。", "高廟神靈在，乾坤付不言。"]'),
('5931f7e4-aa34-4710-ab21-601b2aed609f','自歎','文天祥','宋','宋诗','song-poetry','','[]','海闊南風慢，天昏北斗斜。',48,'全唐诗/poet.song.239000.json','["海闊南風慢，天昏北斗斜。", "孤臣傷失國，遊子歎無家。", "官飯身如寄，征衣鬢欲華。", "越王臺上望，家國在天涯。"]'),
('60387f31-cef5-4154-a8db-36578d90d139','虎頭山','文天祥','宋','宋诗','song-poetry','','[]','蚤不逃秦帝，終然陷楚囚。',48,'全唐诗/poet.song.239000.json','["蚤不逃秦帝，終然陷楚囚。", "故園春草夢，舊國夕陽愁。", "妾婦生何益，男兒死未休。", "虎頭山下路，揮淚憶虔州。"]'),
('6f741609-731e-4837-bd4f-636da3486a01','戰場','文天祥','宋','宋诗','song-poetry','','[]','三年海嶠擁貔貅，一日蹉跎白盡頭。',64,'全唐诗/poet.song.239000.json','["三年海嶠擁貔貅，一日蹉跎白盡頭。", "垓下雌雄羞故老，長安咫尺泣孤囚。", "魚龍沸海地爲泣，烟雨滿山天也愁。", "萬死小臣無足憾，蕩陰誰共侍中遊。"]'),
('50e13a8c-ff37-421d-8694-00bb3904b6a9','哭崖山','文天祥','宋','宋诗','song-poetry','','[]','寶藏如山席六宗，樓船千疊水晶宮。',64,'全唐诗/poet.song.239000.json','["寶藏如山席六宗，樓船千疊水晶宮。", "吳兒進退尋常事，漢氏存亡頃刻中。", "諸老丹心付流水，孤臣血淚洒南風。", "早來朝市今何處，如悟人間萬法空。"]'),
('5a788092-0eaa-4575-9450-0047fc49f792','上塚吟','文天祥','宋','宋诗','song-poetry','','[]','余昔從君時，上堂拜姑嫜。',144,'全唐诗/poet.song.239000.json','["余昔從君時，上堂拜姑嫜。", "相携上祖塚，歲時持酒漿。", "姑嫜相繼沒，馬鬣不在鄉。", "共君甌盂飯，清涕流襦裳。", "君貧初赴官，有家不得將。", "妾無應書兒，松檟自成行。", "君別不復歸，歲月何茫茫。", "長安擁朱綬，執雁事侯王。", "豈無一紙書，道路阻且長。", "年年酹寒食，妾心良自傷。", "君家舊巾櫛，至今襲且藏。", "諒君霜露心，白首遥相望。"]'),
('63e8a7b7-87d4-47aa-aab8-867ad7e5846f','葬無主墓碑','文天祥','宋','宋诗','song-poetry','','[]','路逢一石碑，亭亭傲風雨。',144,'全唐诗/poet.song.239000.json','["路逢一石碑，亭亭傲風雨。", "停驂彷彿看，云是無主墓。", "末書戊申歲，屈指九十秋。", "是時龍渡江，甲子恍一周。", "借問葬者誰，承平百世祖。", "亦有周餘民，戰骨委黄土。", "太祖下江南，誓不戮一人。", "神孫再立國，天以報至仁。", "大河流血丹，屠毒誰之罪。", "潼關忽不守，皇皇依汴蔡。", "螳螂知捕蟬，不知黄雀來。", "今古有興廢，重爲生人哀。"]'),
('5f988a0e-eb70-47f9-bfb3-e826f96cddea','邳州哭母小祥','文天祥','宋','宋诗','song-poetry','','[]','我有母聖善，鸞飛星一周。',96,'全唐诗/poet.song.239000.json','["我有母聖善，鸞飛星一周。", "去年哭海上，今年哭邳州。", "遥想仲季間，木主布筵几。", "我躬已不閲，祀事付支子。", "使我早淪落，如此終天何。", "及今畢親喪，於分亦已多。", "母嘗教我忠，我不違母志。", "及泉會相見，鬼神共歡喜。"]'),
('20e04be1-c562-4aec-b3a9-73d631c216b1','哭母大祥','文天祥','宋','宋诗','song-poetry','','[]','前年惠州哭母歛，去年邳州哭母期。',256,'全唐诗/poet.song.239000.json','["前年惠州哭母歛，去年邳州哭母期。", "今年飄泊在何處，燕山獄裏菊花時。", "哀哀黄花如昨日，兩度星周俄箭疾。", "人間送死一大事，生兒富貴不得力。", "祇今誰人守墳墓，零落瘴鄉一堆土。", "大兒狼狽勿復道，下有二兒并二女。", "一兒一女亦在燕，佛廬設供捐金錢。", "一兒一女家下祭，病脫麻衣日晏眠。", "夜來好夢歸故國，忽然海上見顔色。", "一聲鷄叫淚滿床，化爲清血衣裳濕。", "當年嫠緯意謂何，親曾撫我夜枕戈。", "古來全忠不全孝，世事至此甘滂沱。", "夫人開國分齊魏，生榮死哀送天地。", "悠悠國破與家亡，平生無憾惟此事。", "二郎已作門戶謀，江南葬母麥滿舟。", "不知何日歸兄骨，狐死猶應正首丘。"]'),
('58f90cb0-411a-4857-8a0e-d4fd7818221d','先太師忌日','文天祥','宋','宋诗','song-poetry','','[]','太師忌汗漫，二紀似跳丸。',48,'全唐诗/poet.song.239000.json','["太師忌汗漫，二紀似跳丸。", "弟妹俱成立，家鄉忍破殘。", "衣冠晨月暗，墳墓夜風寒。", "萬里逢先忌，無言把淚彈。"]'),
('f9ec4bd2-47b6-422e-a33f-28ef6d90e7fc','己卯十月一日至燕越五日罹狴犴有感而賦  其一','文天祥','宋','宋诗','song-poetry','','[]','直弦不似曲如鈎，自古聖賢多被囚。',64,'全唐诗/poet.song.239000.json','["直弦不似曲如鈎，自古聖賢多被囚。", "命有死時名不死，身無憂處道還憂。", "可憐杜宇空流血，惟願嚴顔便斫頭。", "結束長編猶在此，竈間婢子見人羞。"]'),
('ee4f08dc-c0b9-4f67-a296-3a1d1aab5cd7','己卯十月一日至燕越五日罹狴犴有感而賦  其二','文天祥','宋','宋诗','song-poetry','','[]','落落南冠自結纓，桁楊卧起影縱橫。',64,'全唐诗/poet.song.239000.json','["落落南冠自結纓，桁楊卧起影縱橫。", "坐移白石知何世，夢斷青燈問幾更。", "國破家亡雙淚暗，天荒地老一身輕。", "黄粱得失俱成幻，五十年前元未生。"]'),
('20c0121c-6826-4a6c-b5a4-6dd8e26e9abd','己卯十月一日至燕越五日罹狴犴有感而賦  其三','文天祥','宋','宋诗','song-poetry','','[]','心期耿耿浮雲上，身事悠悠落日西。',64,'全唐诗/poet.song.239000.json','["心期耿耿浮雲上，身事悠悠落日西。", "千古興亡何限錯，百年生死本來齊。", "沙邊莫待哀黄鵠，雪裏何須問牧羝。", "此處曾埋雙寶劍，虹光夜指楚天低。"]'),
('1a91c9a8-0e5c-4c72-ba03-d5fba1b5ae8e','己卯十月一日至燕越五日罹狴犴有感而賦  其四','文天祥','宋','宋诗','song-poetry','','[]','寥陽殿上步黄金，一落顛崖地獄深。',64,'全唐诗/poet.song.239000.json','["寥陽殿上步黄金，一落顛崖地獄深。", "蘇武窖中偏喜卧，劉琨囚裏不妨吟。", "生前已見夜叉面，死去只因菩薩心。", "萬里風沙知己盡，誰人會得廣陵音。"]'),
('a63a8ae1-bcd3-4b0e-87e8-c8d82f5d1bd1','己卯十月一日至燕越五日罹狴犴有感而賦  其五','文天祥','宋','宋诗','song-poetry','','[]','亦知戛戛楚囚難，無柰天生一寸丹。',64,'全唐诗/poet.song.239000.json','["亦知戛戛楚囚難，無柰天生一寸丹。", "鐵馬行鏖南地熱，赭衣坐擁北庭寒。", "朝餐淡薄神還爽，夜睡崎嶇夢自安。", "亡國大夫誰爲傳，祇饒野史與人看。"]'),
('0348ccde-4b5a-4384-b64c-a9e91e4a174b','己卯十月一日至燕越五日罹狴犴有感而賦  其六','文天祥','宋','宋诗','song-poetry','','[]','風雪重門老楚囚，夢回長夜意悠悠。',64,'全唐诗/poet.song.239000.json','["風雪重門老楚囚，夢回長夜意悠悠。", "熊魚自古無雙得，鵠雀如何可共謀。", "萬里山河真墮甑，一家妻子枉填溝。", "兒時愛讀忠臣傳，不謂身當百六秋。"]'),
('7ba3bf12-9568-4649-b843-69a865710338','己卯十月一日至燕越五日罹狴犴有感而賦  其七','文天祥','宋','宋诗','song-poetry','','[]','聽著啼鵑淚滿襟，國亡家破見忠臣。',64,'全唐诗/poet.song.239000.json','["聽著啼鵑淚滿襟，國亡家破見忠臣。", "關河歷落三生夢，風雪飄零萬死身。", "丞相豈能堪獄吏，故侯安得作園人。", "神農虞夏吾誰適，回首西山繼絕塵。"]'),
('9c372dfa-8689-4289-8a74-878c698c9642','己卯十月一日至燕越五日罹狴犴有感而賦  其八','文天祥','宋','宋诗','song-poetry','','[]','風前泣燈影，日下泣霜花。',48,'全唐诗/poet.song.239000.json','["風前泣燈影，日下泣霜花。", "鍾信忽然動，屋陰俄又斜。", "悶中聊度歲，夢裏尚還家。", "地獄何須問，人間見夜叉。"]'),
('58a4c93e-7c73-46de-b85f-e9284813d449','己卯十月一日至燕越五日罹狴犴有感而賦  其九','文天祥','宋','宋诗','song-poetry','','[]','風霜陰忽忽，天地澹悠悠。',48,'全唐诗/poet.song.239000.json','["風霜陰忽忽，天地澹悠悠。", "我自操吳語，誰來問楚囚。", "寂中惟滅想，達處盡忘憂。", "手有韋編在，朝聞夕死休。"]'),
('db789a36-feea-4ad2-8b42-3f481bcefeb2','己卯十月一日至燕越五日罹狴犴有感而賦  其一○','文天祥','宋','宋诗','song-poetry','','[]','環堵塵如屋，纍然一故吾。',48,'全唐诗/poet.song.239000.json','["環堵塵如屋，纍然一故吾。", "解衣烘稚蝨，勻鏁救殘鬚。", "坐處心如忘，吟餘眼已枯。", "不應留滯久，何日裹籧篨。"]'),
('aa8df774-43a1-44ec-b57a-2e5bc60ba68e','己卯十月一日至燕越五日罹狴犴有感而賦  其一一','文天祥','宋','宋诗','song-poetry','','[]','浩劫風塵暗，衣冠痛百罹。',48,'全唐诗/poet.song.239000.json','["浩劫風塵暗，衣冠痛百罹。", "靜傳方外學，晴寫獄中詩。", "烈士惟名殉，真人與物違。", "世間忙會錯，認取去來時。"]'),
('7be4794c-5914-499b-878e-da562a33fc0c','己卯十月一日至燕越五日罹狴犴有感而賦  其一二','文天祥','宋','宋诗','song-poetry','','[]','儼然楚君子，一日造王庭。',48,'全唐诗/poet.song.239000.json','["儼然楚君子，一日造王庭。", "議論探堅白，精神入汗青。", "無書求出獄，有舌到臨刑。", "宋故忠臣墓，真吾五字銘。"]'),
('97f6b2b5-3b94-45f5-b423-a47cce97600e','己卯十月一日至燕越五日罹狴犴有感而賦  其一三','文天祥','宋','宋诗','song-poetry','','[]','兩月縲囚裏，一年憂患餘。',48,'全唐诗/poet.song.239000.json','["兩月縲囚裏，一年憂患餘。", "疏因隨事直，忠故有時愚。", "道在身何拙，心安體自舒。", "近來都勘破，人世只蘧廬。"]'),
('c506da37-a25f-4d30-a1ee-3a52fbe55c14','己卯十月一日至燕越五日罹狴犴有感而賦  其一四','文天祥','宋','宋诗','song-poetry','','[]','衮衣坐縲絏，世事亦堪哀。',48,'全唐诗/poet.song.239000.json','["衮衣坐縲絏，世事亦堪哀。", "枕外親炊黍，爐邊細畫灰。", "無人淚垂血，何地骨生苔。", "風雪江南路，夢中行探梅。"]'),
('5ff83ed7-bbf4-427c-ab7e-fd49d4eb683f','己卯十月一日至燕越五日罹狴犴有感而賦  其一五','文天祥','宋','宋诗','song-poetry','','[]','我自憐人醜，人方笑我愚。',48,'全唐诗/poet.song.239000.json','["我自憐人醜，人方笑我愚。", "身生豫讓癩，背發范增疽。", "已愧功臣傳，猶堪烈士書。", "衣冠事至此，命也欲何如。"]'),
('fffb9f9b-ed13-4c9a-8f05-3d9cca9d2f1c','己卯十月一日至燕越五日罹狴犴有感而賦  其一六','文天祥','宋','宋诗','song-poetry','','[]','久矣忘榮辱，今茲一死生。',48,'全唐诗/poet.song.239000.json','["久矣忘榮辱，今茲一死生。", "理明心自裕，神定氣還清。", "欲了男兒事，幾無妻子情。", "出門天宇闊，一笑暮雲橫。"]'),
('7b064141-bc0a-4569-84f5-771835e86225','己卯十月一日至燕越五日罹狴犴有感而賦  其一七','文天祥','宋','宋诗','song-poetry','','[]','珙璧衣冠十六傳，更無一士死君前。',64,'全唐诗/poet.song.239000.json','["珙璧衣冠十六傳，更無一士死君前。", "自慚重趙非九鼎，猶幸延韓更數年。", "孟博囊頭真自愛，杲卿鈎舌要誰憐。", "人間信有綱常在，萬古西山皎月懸。"]'),
('448ea0aa-0c73-4bab-a33e-ac9e0f9de122','和夷齊西山歌  其一','文天祥','宋','宋诗','song-poetry','','[]','小雅盡廢兮，出車采薇矣。',49,'全唐诗/poet.song.239000.json','["小雅盡廢兮，出車采薇矣。", "戎有中國兮，人類熄矣。", "明王不興兮，吾誰與歸矣。", "抱春秋以沒世兮，甚矣吾衰矣。"]'),
('487f4efc-4744-46f6-a3cf-9c702e9721c2','和夷齊西山歌  其二','文天祥','宋','宋诗','song-poetry','','[]','彼美人兮，西山之薇矣。',44,'全唐诗/poet.song.239000.json','["彼美人兮，西山之薇矣。", "北方之人兮，爲吾是非矣。", "異域長絕兮，不復歸矣。", "鳳不至兮，德之衰矣。"]'),
('a00d45bc-6d9c-4bb9-b897-70f576c2a5fb','十二月二十日作','文天祥','宋','宋诗','song-poetry','','[]','家國哀千古，星霜忽一周。',48,'全唐诗/poet.song.239000.json','["家國哀千古，星霜忽一周。", "黄沙漫故道，白骨委荒丘。", "許遠死何晚，李陵生自羞。", "南來冠不改，吾且任吾囚。"]'),
('04bff1e2-7831-404e-b966-bf5ed2f1e276','二十四日','文天祥','宋','宋诗','song-poetry','','[]','壯心負光岳，病質落幽燕。',48,'全唐诗/poet.song.239000.json','["壯心負光岳，病質落幽燕。", "春節前三日，江鄉正小年。", "歲時如有水，風俗不同天。", "家廟荒苔滑，誰人燒紙錢。"]'),
('e7c7e6aa-64d4-4100-94d2-93a3b5844da4','立春','文天祥','宋','宋诗','song-poetry','','[]','無限斜陽故國愁，朔風吹馬上幽州。',64,'全唐诗/poet.song.239000.json','["無限斜陽故國愁，朔風吹馬上幽州。", "天翻地覆三生劫，歲晚江空萬里囚。", "烈士喪元端不惜，達人知命復何憂。", "祇應四十三年死，兩度無端見土牛。"]'),
('003b2bac-02e5-438e-b58d-607925d1d531','遇靈陽子談道贈以詩','文天祥','宋','宋诗','song-poetry','','[]','昔我愛泉石，長揖離公卿。',144,'全唐诗/poet.song.239000.json','["昔我愛泉石，長揖離公卿。", "結屋青山下，咫尺蓬與瀛。", "至人不可見，世塵忽相纓。", "業風吹浩劫，蝸角爭浮名。", "偶逢大呂翁，如有宿世盟。", "相從語寥廓，俯仰萬念輕。", "天地不知老，日月交其精。", "人一陰陽性，本來自長生。", "指點虛無間，引我歸員明。", "一針透頂門，道骨由天成。", "我如一逆旅，久欲躡屩行。", "聞師此妙訣，蘧廬復何情。"]'),
('546daab0-85ed-4ec7-9579-038bded5dbd8','歲祝犁單閼月赤奮若日焉逢涒灘遇異人指示以大光明正法於是死生脫然若遺矣作五言八句','文天祥','宋','宋诗','song-poetry','','[]','誰知真患難，忽悟大光明。',48,'全唐诗/poet.song.239000.json','["誰知真患難，忽悟大光明。", "日出雲俱靜，風消水自平。", "功名幾滅性，忠孝大勞生。", "天下惟豪傑，神仙立地成。"]'),
('3431176b-1a74-40a3-8f8e-87c2b6a218a7','己卯歲除','文天祥','宋','宋诗','song-poetry','','[]','歲除破衣裳，夜半刺針線。',120,'全唐诗/poet.song.239000.json','["歲除破衣裳，夜半刺針線。", "遊子長夜思，佳人不可見。", "草枯稚馿吼，燈暗饑鼠現。", "深室閉星斗，輕裘卧風霰。", "大化忽流斡，浩劫蕩回轉。", "冠屨失其位，侯王化畸賤。", "弓戈叱奇字，刀鋸摧䪻弁。", "至性詎可遷，微軀不足戀。", "真人坐沖漠，死生一乘傳。", "日月行萬古，神光索九縣。"]'),
('1e0b0379-0758-4c76-b045-eec7aa38cb22','元日','文天祥','宋','宋诗','song-poetry','','[]','鐵馬風塵暗，金龍日月新。',48,'全唐诗/poet.song.239000.json','["鐵馬風塵暗，金龍日月新。", "衣冠懷故國，鼓角泣離人。", "自分流年晚，不妨吾道春。", "方來有千載，兒女枉悲辛。"]'),
('fcf73ef2-87b2-4edc-802d-f55715862a5b','庚辰四十五歲','文天祥','宋','宋诗','song-poetry','','[]','東風昨夜忽相過，天地無情柰老何。',64,'全唐诗/poet.song.239000.json','["東風昨夜忽相過，天地無情柰老何。", "千載方來那有盡，百年未半已爲多。", "君傳南海長生藥，我愛西山餓死歌。", "泡影生來隨自在，悠悠不管世間魔。"]'),
('997698b5-8f56-4504-98e0-2a24a75fc7ee','感興','文天祥','宋','宋诗','song-poetry','','[]','萬里雲山斷客魂，浮雲心事向誰言。',64,'全唐诗/poet.song.239000.json','["萬里雲山斷客魂，浮雲心事向誰言。", "月侵鄉夢夜推枕，風送牢愁晝掩門。", "蘇子窖中閑日月，石郎家裏舊乾坤。", "朝聞夕死吾何恨，坐把春秋子細論。"]'),
('9afdf386-5ae0-4b2b-bf5d-d2bbcc7fe721','正月十三日','文天祥','宋','宋诗','song-poetry','','[]','去年今日遁崖山，望見龍舟咫尺間。',64,'全唐诗/poet.song.239000.json','["去年今日遁崖山，望見龍舟咫尺間。", "海上樓臺俄已變，河陽車駕不須還。", "可憐羝乳煙橫塞，空想鵑啼月掩關。", "人世流光忽如此，東風吹雪鬢毛班。"]'),
('d65b3feb-4056-410d-9bed-ed12ee2cc65e','上元懷舊','文天祥','宋','宋诗','song-poetry','','[]','禁門三五金吾夜，回首青春忽二毛。',64,'全唐诗/poet.song.239000.json','["禁門三五金吾夜，回首青春忽二毛。", "池上昔陪王母宴，斗中今直貴人牢。", "風生江海龍遊遠，月滿關山鶴唳高。", "夢到鈞天燈火閙，依然彩筆照宮袍。"]'),
('43ad5a08-0a56-4cfb-8607-be57ed5ccc98','讀史','文天祥','宋','宋诗','song-poetry','','[]','自古英雄士，還爲薄命人。',48,'全唐诗/poet.song.239000.json','["自古英雄士，還爲薄命人。", "孔明登四十，韓信過三旬。", "壯志摧龍虎，高詞泣鬼神。", "一朝事千古，何用怨青春。"]'),
('8e7d57bd-14c3-4e21-a658-6648e16fa0b5','感傷','文天祥','宋','宋诗','song-poetry','','[]','家國傷冰泮，妻孥歎陸沉。',48,'全唐诗/poet.song.239000.json','["家國傷冰泮，妻孥歎陸沉。", "半生遭萬劫，一落下千尋。", "各任汝曹命，那知吾輩心。", "人誰無骨肉，恨與海俱深。"]'),
('64ab5766-d963-45b7-8dd8-7d3267306d9f','遣興  其一','文天祥','宋','宋诗','song-poetry','','[]','一落顛崖不自由，春風相對說牢愁。',64,'全唐诗/poet.song.239000.json','["一落顛崖不自由，春風相對說牢愁。", "稚馿黑月光中吼，饑鼠青燈影下遊。", "豈料乾坤成墮甑，始知身世是虛舟。", "遥憐海上今塵土，前代風流不肯休。"]'),
('766d6154-ff69-4c0e-ae66-a465c80efb42','遣興  其二','文天祥','宋','宋诗','song-poetry','','[]','東風吹草日高眠，試把平生細問天。',64,'全唐诗/poet.song.239000.json','["東風吹草日高眠，試把平生細問天。", "燕子愁迷江右月，杜鵑聲破洛陽烟。", "何從林下尋元亮，只向塵中作魯連。", "莫笑道人空打坐，英雄收斂便神仙。"]'),
('e549d2c1-6510-4e1b-8c25-1810f597e0e9','四月八日','文天祥','宋','宋诗','song-poetry','','[]','今朝浴佛舊風流，身落山前第一州。',64,'全唐诗/poet.song.239000.json','["今朝浴佛舊風流，身落山前第一州。", "贛上瑶桃俄五稔，海中玉果已三周。", "人生聚散真成夢，世事悲懽一轉頭。", "坐對薰風開口笑，滿懷耿耿復何求。"]'),
('ac13e98b-b7a0-45fa-90af-d411fca8bbc4','夜起','文天祥','宋','宋诗','song-poetry','','[]','夢破東窗月半明，此身雖在只堪驚。',64,'全唐诗/poet.song.239000.json','["夢破東窗月半明，此身雖在只堪驚。", "一春花裏離人淚，萬里燈前故國情。", "龍去想應回海島，雁飛猶未出江城。", "客愁多似西山雨，一任蕭條白髮生。"]'),
('07249dce-6165-4cba-b343-f0cd7abf9486','端午感興  其一','文天祥','宋','宋诗','song-poetry','','[]','千金鑄鏡百神愁，功與當年禹服侔。',32,'全唐诗/poet.song.239000.json','["千金鑄鏡百神愁，功與當年禹服侔。", "荆棘故宮魑魅走，空餘揚子水東流。"]'),
('62feec40-a5d2-4c46-89b3-92117b0991e1','端午感興  其二','文天祥','宋','宋诗','song-poetry','','[]','當年忠血墮讒波，千古荆人祭汨羅。',32,'全唐诗/poet.song.239000.json','["當年忠血墮讒波，千古荆人祭汨羅。", "風雨天涯芳草夢，江山如此故都何。"]'),
('52690c7e-18f5-45a7-9415-ebe215ab5d8a','端午感興  其三','文天祥','宋','宋诗','song-poetry','','[]','流棹西來恨未銷，魚龍寂寞暗風潮。',32,'全唐诗/poet.song.239000.json','["流棹西來恨未銷，魚龍寂寞暗風潮。", "楚人猶自貪兒戲，江上年年奪錦標。"]'),
('ddfd7bd2-42c5-4f9f-bfe2-023847d47137','見艾有感','文天祥','宋','宋诗','song-poetry','','[]','過眼驚初夏，回頭憶晚春。',48,'全唐诗/poet.song.239000.json','["過眼驚初夏，回頭憶晚春。", "已憐花結子，又見艾爲人。", "故國丹心老，中原白髮新。", "靈修那解化，清夢楚江濱。"]'),
('087eee7f-abb5-4f3d-9da8-a4505fd8ba2d','自歎','文天祥','宋','宋诗','song-poetry','','[]','綠槐雲影弄黄昏，月照牢愁半掩門。',64,'全唐诗/poet.song.239000.json','["綠槐雲影弄黄昏，月照牢愁半掩門。", "一片心如千片碎，十分鬚有二分存。", "沙邊黄鵠長回首，江上杜鵑空斷魂。", "豎子溷人漫不省，紅纓白馬意軒軒。"]'),
('c83145e1-1df8-4203-a968-47cba5c30b4e','自遣','文天祥','宋','宋诗','song-poetry','','[]','詩餘眠白日，飲後坐清風。',48,'全唐诗/poet.song.239000.json','["詩餘眠白日，飲後坐清風。", "萬事乘除裏，平生寵辱中。", "心無隨境變，意自與天通。", "莫笑邯鄲夢，惺惺更是空。"]'),
('4ddfba14-5c27-4d2e-895d-b69e04adda60','自述','文天祥','宋','宋诗','song-poetry','','[]','赤舄登黄道，朱旗上紫垣。',48,'全唐诗/poet.song.239000.json','["赤舄登黄道，朱旗上紫垣。", "有心扶日月，無力報乾坤。", "往事飛鴻渺，新愁落照昏。", "千年滄海上，精衛是吾魂。"]'),
('7dfe4cd7-9836-453d-9e2e-36aca291f509','不睡','文天祥','宋','宋诗','song-poetry','','[]','終夕起推枕，五更聞打鍾。',48,'全唐诗/poet.song.239000.json','["終夕起推枕，五更聞打鍾。", "精神入朱鳥，形影落盧龍。", "弭節蓬萊島，揚旗太華峰。", "奔馳竟何事，回首謝喬松。"]'),
('d1f4b5b3-8107-4cb5-ba86-9ed428e4d746','七夕','文天祥','宋','宋诗','song-poetry','','[]','大地風塵惡，長天歲月奔。',48,'全唐诗/poet.song.239000.json','["大地風塵惡，長天歲月奔。", "憂來渾是感，夢破與誰言。", "緱鶴空回首，河牛暗斷魂。", "吾今拙又拙，無復問天孫。"]'),
('5f8755f8-6110-421d-8671-4d5d35f11828','有感','文天祥','宋','宋诗','song-poetry','','[]','石郎草草割山川，一落人手三百年。',64,'全唐诗/poet.song.239000.json','["石郎草草割山川，一落人手三百年。", "八州風雨暗連天，三皇五帝如飛煙。", "人人野祭伊水邊，春秋斷爛不復傳。", "白頭潦倒今魯連，夜深危坐日晏眠。"]'),
('77c753d3-b0ac-4b7a-aec8-5940874a53d8','聞季萬至','文天祥','宋','宋诗','song-poetry','','[]','去年別我旋出嶺，今年汝來亦至燕。',64,'全唐诗/poet.song.239000.json','["去年別我旋出嶺，今年汝來亦至燕。", "弟兄一囚一乘馬，同父同母不同天。", "可憐骨肉相聚散，人間不滿五十年。", "三仁生死各有意，悠悠白日橫蒼煙。"]'),
('d6754e77-557b-4cab-bd41-eaffc452d3a4','有感','文天祥','宋','宋诗','song-poetry','','[]','平生心事付悠悠，風雨燕南老楚囚。',64,'全唐诗/poet.song.239000.json','["平生心事付悠悠，風雨燕南老楚囚。", "故舊相思空萬里，妻孥不見滿三秋。", "絕憐諸葛隆中意，贏得子長天下遊。", "一死皎然無復恨，忠魂多少暗荒丘。"]'),
('e55ae25a-72da-4d7a-ae8b-dda03239bf46','感懷','文天祥','宋','宋诗','song-poetry','','[]','去歲趨燕路，今晨發楚津。',48,'全唐诗/poet.song.239000.json','["去歲趨燕路，今晨發楚津。", "浪名千里客，剩作一年人。", "鏡裏秋容別，燈前暮影親。", "魯連疑未死，聊用托芳塵。"]'),
('f09bf424-dc28-4505-ac9e-4a10eefbc8f3','重陽  其一','文天祥','宋','宋诗','song-poetry','','[]','飄零萬里若爲家，一夜西風吹鬢華。',32,'全唐诗/poet.song.239000.json','["飄零萬里若爲家，一夜西風吹鬢華。", "祇有新詩題甲子，更無故舊對黄花。"]'),
('17c5d846-46a0-4931-a286-d415459cf917','重陽  其二','文天祥','宋','宋诗','song-poetry','','[]','江南秋色滿梧桐，回首青山萬事空。',32,'全唐诗/poet.song.239000.json','["江南秋色滿梧桐，回首青山萬事空。", "怕見鏡中新白髮，長將破帽裹西風。"]'),
('1a875686-9d0d-4468-bdc9-0e35654db1ff','重陽  其三','文天祥','宋','宋诗','song-poetry','','[]','風捲車塵弄曉寒，天涯流落寸心丹。',32,'全唐诗/poet.song.239000.json','["風捲車塵弄曉寒，天涯流落寸心丹。", "去年醉與茱萸別，不把今年作健看。"]'),
('6a525193-93fd-409c-a51d-1945ace13e61','己卯十月一日予入燕城歲月冉冉忽復周星而予猶未得死也因賦八句','文天祥','宋','宋诗','song-poetry','','[]','去冬陽月朔，吾始至幽燕。',48,'全唐诗/poet.song.239000.json','["去冬陽月朔，吾始至幽燕。", "浩劫真千載，浮生又一年。", "天南照天北，山後接山前。", "夢裏乾坤老，孤臣雪咽氈。"]'),
('bae8b43f-c811-4e6b-9a3a-4c7d28cb8cd2','己卯十月五日予入燕獄今三十有六旬感興一首','文天祥','宋','宋诗','song-poetry','','[]','石晉舊燕趙，鍾儀新楚囚。',48,'全唐诗/poet.song.239000.json','["石晉舊燕趙，鍾儀新楚囚。", "山河千古痛，風雨一年周。", "過雁催人老，寒花送客愁。", "捲簾雲滿座，抱膝意悠悠。"]'),
('1dca4070-6785-47b1-9f4c-95d6b73a1964','去年十月九日余至燕城今周星不報爲賦長句','文天祥','宋','宋诗','song-poetry','','[]','君不見常山太守駡羯奴，天津橋上舌盡刳。',134,'全唐诗/poet.song.239000.json','["君不見常山太守駡羯奴，天津橋上舌盡刳。", "又不見睢陽將軍怒切齒，三十六人同日死。", "去冬長至前一日，朔庭呼我弗爲屈。", "丈夫開口即見膽，意謂生死在頃刻。", "赭衣冉冉生蒼苔，書雲時節忽復來。", "鬼影青燈照孤坐，夢啼死血丹心破。", "只今便作渭水囚，食粟已是西山羞。", "悔不當年跳東海，空有魯連心獨在。"]'),
('55c9a7fe-fef0-4525-8162-9f740bb8c47d','冬至','文天祥','宋','宋诗','song-poetry','','[]','書雲今日事，夢破曉鳴鍾。',48,'全唐诗/poet.song.239000.json','["書雲今日事，夢破曉鳴鍾。", "家禍三生劫，年愁兩度冬。", "江山乏小草，霜雪見孤松。", "春色蒙泉裏，煙蕪幾萬重。"]'),
('93d76715-1221-475f-b39f-736f8f51b462','冬晴','文天祥','宋','宋诗','song-poetry','','[]','北國天寒少，南方地氣來。',48,'全唐诗/poet.song.239000.json','["北國天寒少，南方地氣來。", "年光如箭去，世事正輪迴。", "可怪新祈雪，相思久別梅。", "夜闌燈坐暗，獨自撥殘灰。"]'),
('1e5ef801-850f-4199-9a6b-41bbe93fc6ad','自歎','文天祥','宋','宋诗','song-poetry','','[]','可憐大流落，白髮魯連翁。',48,'全唐诗/poet.song.239000.json','["可憐大流落，白髮魯連翁。", "每夜瞻南斗，連年坐北風。", "三生遭際處，一死笑談中。", "贏得千年在，丹心射碧空。"]'),
('b1d6eaec-8c20-4ae8-b173-932523d3d4c1','戊寅臘月二十日空坑敗被執于今二周年矣感懷八句','文天祥','宋','宋诗','song-poetry','','[]','橫磨十萬坐無謀，回首蹉跎海上州。',64,'全唐诗/poet.song.239000.json','["橫磨十萬坐無謀，回首蹉跎海上州。", "太傅只圖和藥了，將軍便謂斫頭休。", "乾坤顛倒真千劫，身世留連復一周。", "一死到今如送佛，空窗淡月夜悠悠。"]'),
('71170655-2a7f-447e-84e4-0692963207ab','所懷','文天祥','宋','宋诗','song-poetry','','[]','萬里青山兩鬢華，老臣無國又無家。',64,'全唐诗/poet.song.239000.json','["萬里青山兩鬢華，老臣無國又無家。", "乾坤局促籠中鳥，風雪飄零糞上花。", "歲晚江空人已逝，天寒日短路何賒。", "書生不作綱常計，聞是東門已種瓜。"]'),
('aa5143db-fa23-48ca-9c0b-7fff8e0bdb20','除夜  其一','文天祥','宋','宋诗','song-poetry','','[]','門揜千山黑，孤燈伴不眠。',48,'全唐诗/poet.song.239000.json','["門揜千山黑，孤燈伴不眠。", "故鄉在何處，今夕是窮年。", "住世真無係，爲囚已自然。", "勞勞空歲月，得死似登仙。"]'),
('d8215b63-bd23-46ef-995a-888512b710bb','除夜  其二','文天祥','宋','宋诗','song-poetry','','[]','歲暮難爲客，天涯况是囚。',48,'全唐诗/poet.song.239000.json','["歲暮難爲客，天涯况是囚。", "乾坤還許大，歲月忽如流。", "夢過元無夢，憂多更不憂。", "屠蘇兒女態，肯作百年謀。"]'),
('03f789e9-6c01-46de-a6e7-12f42893596b','元日  其一','文天祥','宋','宋诗','song-poetry','','[]','金虬銜日出，鐵騎勒春回。',48,'全唐诗/poet.song.239000.json','["金虬銜日出，鐵騎勒春回。", "天上青門隔，人間白髮催。", "霜寒欺舊草，山晚放新梅。", "環堵甘牢落，東風枉却來。"]'),
('e66e65af-232d-4503-bb4b-3e9c8150a957','元日  其二','文天祥','宋','宋诗','song-poetry','','[]','慙愧雲臺客，飄零雪滿氈。',48,'全唐诗/poet.song.239000.json','["慙愧雲臺客，飄零雪滿氈。", "不圖朱鳥影，猶見白蛇年。", "宮殿荒烟隔，門庭宿草連。", "乾坤自春色，回首一潸然。"]'),
('337e7505-c685-4451-9597-2440ab6d9411','初六日即事','文天祥','宋','宋诗','song-poetry','','[]','車馬燕山閙，誰家早管絃。',48,'全唐诗/poet.song.239000.json','["車馬燕山閙，誰家早管絃。", "開門忽見雪，擁被不知年。", "篋破書猶在，爐殘火復燃。", "偷桃昨日事，回首哭堯天。"]'),
('c5723dc4-9801-4138-a7db-55615ea9554b','人日','文天祥','宋','宋诗','song-poetry','','[]','今年爲蛇年，此日是人日。',48,'全唐诗/poet.song.239000.json','["今年爲蛇年，此日是人日。", "江右一龍鍾，山中舊佔畢。", "獨坐守太玄，一笑發狂疾。", "悠悠王正意，衰涕感麟筆。"]'),
('e98f0990-d918-4e01-b0c7-06ccab5dc1cf','自歎','文天祥','宋','宋诗','song-poetry','','[]','功業羞前輩，形骸感故吾。',48,'全唐诗/poet.song.239000.json','["功業羞前輩，形骸感故吾。", "屢判嵇紹血，幾無慶公鬚。", "落落惟心在，蒼蒼有意無。", "江流總遺淚，何止失吞吳。"]'),
('16008148-b484-4859-bc60-f4ab647d2d24','元夕  其一','文天祥','宋','宋诗','song-poetry','','[]','燈火喧三市，衣冠宴九宸。',48,'全唐诗/poet.song.239000.json','["燈火喧三市，衣冠宴九宸。", "金吾不禁夜，公子早行春。", "夢斷青山遠，愁侵白髮新。", "燕山今夕月，清影伴孤臣。"]'),
('9b521961-99cb-4ec4-a2e4-2bfdfd4a76e0','元夕  其二','文天祥','宋','宋诗','song-poetry','','[]','飄零竟如此，元夕幾堪憐。',48,'全唐诗/poet.song.239000.json','["飄零竟如此，元夕幾堪憐。", "南國張燈火，燕山沸管絃。", "相思雲萬里，剩看月三年。", "笑與東風道，浮生信偶然。"]'),
('d687d535-5e30-421d-8735-5cc060d6632c','社稷第一','文天祥','宋','宋诗','song-poetry','','[]','南極連銅柱，煌煌太宗業。',24,'全唐诗/poet.song.239000.json','["南極連銅柱，煌煌太宗業。", "始謀誰其間，風雨秋一葉。"]'),
('4e4d4a96-390f-431e-a30f-9b45ab86bbb2','理宗度宗第二','文天祥','宋','宋诗','song-poetry','','[]','先帝弓劍遠，永懷侍芳茵。',24,'全唐诗/poet.song.239000.json','["先帝弓劍遠，永懷侍芳茵。", "今朝漢社稷，爲話涕沾巾。"]'),
('5fbce9ee-469a-458c-8f16-f0cb8f010ee2','誤國權臣第三','文天祥','宋','宋诗','song-poetry','','[]','蒼生倚大臣，此風破南極。',24,'全唐诗/poet.song.239000.json','["蒼生倚大臣，此風破南極。", "開邊一何多，至死難塞責。"]'),
('ef07c7d2-0968-4bec-b770-52e96517f57b','瀘州大將第四','文天祥','宋','宋诗','song-poetry','','[]','西南失大將，带甲滿天地。',24,'全唐诗/poet.song.239000.json','["西南失大將，带甲滿天地。", "高人憂禍胎，感歎亦歔欷。"]'),
('1dfea3be-d5aa-4202-8060-13055dd3d103','襄陽第五','文天祥','宋','宋诗','song-poetry','','[]','十年殺氣盛，百萬攻一城。',24,'全唐诗/poet.song.239000.json','["十年殺氣盛，百萬攻一城。", "賊臣表逆節，胡騎忽縱橫。"]'),
('6cb4bbec-be2d-4d1e-b872-1c865513b23f','荆湖諸戍第六','文天祥','宋','宋诗','song-poetry','','[]','長嘯下荆門，胡行速如鬼。',24,'全唐诗/poet.song.239000.json','["長嘯下荆門，胡行速如鬼。", "門戶無人持，社稷堪流涕。"]'),
('c35ccce7-0c76-4600-8cf1-f5873288cb92','黄州第七','文天祥','宋','宋诗','song-poetry','','[]','桓桓陳將軍，東屯大江北。',24,'全唐诗/poet.song.239000.json','["桓桓陳將軍，東屯大江北。", "化作虎與豺，楚星南天黑。"]'),
('367be724-9eb4-4da5-9c38-7df27a8dac47','陽羅堡第八','文天祥','宋','宋诗','song-poetry','','[]','日色隠孤戍，大江聲怒號。',24,'全唐诗/poet.song.239000.json','["日色隠孤戍，大江聲怒號。", "朝廷任猛將，宿昔恨滔滔。"]'),
('bf0de4b7-c5cc-47cc-b914-151bd29aeed3','京湖宣閫第九','文天祥','宋','宋诗','song-poetry','','[]','正當艱難時，豈無濟時策。',24,'全唐诗/poet.song.239000.json','["正當艱難時，豈無濟時策。", "連檣荆州船，悠悠回赤壁。"]'),
('0eec2144-6f9b-48e9-9449-59a2f347e0ad','渡江第十','文天祥','宋','宋诗','song-poetry','','[]','濟江元自闊，輕舟下吳會。',24,'全唐诗/poet.song.239000.json','["濟江元自闊，輕舟下吳會。", "南紀改波瀾，吾將罪真宰。"]'),
('b1fef0c6-d224-428f-af51-2ae1b8b4f506','鄂州第十一','文天祥','宋','宋诗','song-poetry','','[]','鄂渚分雲樹，春城带雨長。',24,'全唐诗/poet.song.239000.json','["鄂渚分雲樹，春城带雨長。", "惜哉形勝地，河岳空金湯。"]'),
('c59968d1-1cb2-4d73-b020-a7688d1fdf56','江州第十二','文天祥','宋','宋诗','song-poetry','','[]','戎馬暗天宇，落日九江流。',24,'全唐诗/poet.song.239000.json','["戎馬暗天宇，落日九江流。", "元惡迷是似，化作黄長虬。"]'),
